-- Poems batch 384
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fc6288e9-b8f1-499b-8cdc-436f143f1d97','自贊三首  其三','釋明辯','宋','宋诗','song-poetry','','[]','潦倒住持，不言規矩。',34,'全唐诗/poet.song.94000.json','["潦倒住持，不言規矩。", "聚三百僧，說無義語。", "平生要討便宜，落水也求乾處。"]'),
('62edd139-dada-4cd6-aa53-e176848c8628','達磨贊','釋明辯','宋','宋诗','song-poetry','','[]','昇元閣前懡㦬，洛陽峰畔乖張。',44,'全唐诗/poet.song.94000.json','["昇元閣前懡㦬，洛陽峰畔乖張。", "皮髓傳成放霸，雙履無處埋藏。", "不是一番寒徹骨，爭得梅花撲鼻香。"]'),
('d0637000-afc9-4f56-bfce-c4ab1140c04a','頌古三十二首  其一','釋明辯','宋','宋诗','song-poetry','','[]','掀翻地軸乾坤窄，撥轉天輪宇宙寬。',32,'全唐诗/poet.song.94000.json','["掀翻地軸乾坤窄，撥轉天輪宇宙寬。", "須向強中呈好手，虛空打碎劫初看。"]'),
('b2cb0c22-2220-4ac7-83db-46969be0dd4f','頌古三十二首  其二','釋明辯','宋','宋诗','song-poetry','','[]','垂鈎不似迷津客，張網誠非待兔人。',32,'全唐诗/poet.song.94000.json','["垂鈎不似迷津客，張網誠非待兔人。", "半夜烏雞何處去，天明吞卻玉麒麟。"]'),
('9102caf0-c8d5-494e-9f8c-546776a35ae4','頌古三十二首  其三','釋明辯','宋','宋诗','song-poetry','','[]','古皇前化超群檄，無字印文明劃劃。',32,'全唐诗/poet.song.94000.json','["古皇前化超群檄，無字印文明劃劃。", "今時衲子若當陽，往往半千成五百。"]'),
('c6fbeb66-f8da-4a0d-8797-d6d79f06e91e','頌古三十二首  其四','釋明辯','宋','宋诗','song-poetry','','[]','獵涉榮枯未是奇，到頭誰是出家兒。',32,'全唐诗/poet.song.94000.json','["獵涉榮枯未是奇，到頭誰是出家兒。", "故鄉漠漠在消息，時有孤雲嶺外歸。"]'),
('e62fc7e8-afc2-4e56-9cb6-6bf313158983','頌古三十二首  其五','釋明辯','宋','宋诗','song-poetry','','[]','天高雲靜月彎彎，雨過秋空眼界寬。',32,'全唐诗/poet.song.94000.json','["天高雲靜月彎彎，雨過秋空眼界寬。", "百億文殊真妙體，分明只在一毫端。"]'),
('047ac9ed-aa36-4368-a34b-be4292f9b1a4','頌古三十二首  其六','釋明辯','宋','宋诗','song-poetry','','[]','鶖子已圓無漏種，換卻身形總不知。',32,'全唐诗/poet.song.94000.json','["鶖子已圓無漏種，換卻身形總不知。", "通途一貫非他物，午夜胡僧步雪歸。"]'),
('ec82586a-939e-43a0-b82e-068e0c79a666','頌古三十二首  其七','釋明辯','宋','宋诗','song-poetry','','[]','靈山會上舊家風，脫略從茲勢莫窮。',32,'全唐诗/poet.song.94000.json','["靈山會上舊家風，脫略從茲勢莫窮。", "金斗峰前重漏泄，莫將附子當天雄。"]'),
('ca808753-11a3-48a7-9f4e-3deab0835373','頌古三十二首  其八','釋明辯','宋','宋诗','song-poetry','','[]','冤憎會苦，愛別離苦。',20,'全唐诗/poet.song.94000.json','["冤憎會苦，愛別離苦。", "鈍置瞿曇，一場莽鹵。"]'),
('36a3c124-e595-4d2b-92ee-ed55dbf8325d','頌古三十二首  其九','釋明辯','宋','宋诗','song-poetry','','[]','當堂古路白雲漫，碧眼黄頭尚未諳。',32,'全唐诗/poet.song.94000.json','["當堂古路白雲漫，碧眼黄頭尚未諳。", "無孔笛兒氈拍板，輕輕吹破御街寒。"]'),
('57dd83da-f802-434a-8b48-ccbdf3805bb1','頌古三十二首  其一○','釋明辯','宋','宋诗','song-poetry','','[]','馬祖非心非佛，直下更無窼窟。',28,'全唐诗/poet.song.94000.json','["馬祖非心非佛，直下更無窼窟。", "今年樹上胡桃，勝似去年柑橘。"]'),
('e37c55c0-08ed-4375-8d97-825c9afa03b0','頌古三十二首  其一一','釋明辯','宋','宋诗','song-poetry','','[]','金剛南際老番王，反著襴衫入大唐。',32,'全唐诗/poet.song.94000.json','["金剛南際老番王，反著襴衫入大唐。", "牛首旃檀都賣了，唯垂鼻孔不囊藏。"]'),
('a4114863-f351-4d56-bc3d-c8aebbaa8e31','頌古三十二首  其一二','釋明辯','宋','宋诗','song-poetry','','[]','盤走珠兮珠走盤，當機脫略好生觀。',32,'全唐诗/poet.song.94000.json','["盤走珠兮珠走盤，當機脫略好生觀。", "世人知貴不知價，信手拈來也不難。"]'),
('65de6d1f-b4d2-4205-9553-9c8b30a9bd7c','頌古三十二首  其一三','釋明辯','宋','宋诗','song-poetry','','[]','蘿蔔頭禪聒噪人，霜刀累切了無痕。',32,'全唐诗/poet.song.94000.json','["蘿蔔頭禪聒噪人，霜刀累切了無痕。", "自古不通人咬嚼，只容衲子鶻崙吞。"]'),
('60c149ac-353e-41e4-abe5-a07626d73f19','頌古三十二首  其一四','釋明辯','宋','宋诗','song-poetry','','[]','玉洞玄關道路長，蟠桃豈是等閑芳。',32,'全唐诗/poet.song.94000.json','["玉洞玄關道路長，蟠桃豈是等閑芳。", "遮藏不許人間見，只恐春風漏泄香。"]'),
('0686ad20-3fcf-44f6-bfbc-9dcc29366e5d','頌古三十二首  其一五','釋明辯','宋','宋诗','song-poetry','','[]','兜羅綿樣硬贅頭，河北風流老趙州。',32,'全唐诗/poet.song.94000.json','["兜羅綿樣硬贅頭，河北風流老趙州。", "鹹處著鹽淡添水，軒頭一笑更無休。"]'),
('94e2735b-62df-4c64-9a79-b95ceb1a989a','頌古三十二首  其一六','釋明辯','宋','宋诗','song-poetry','','[]','左轉右轉，金剛寶劍。',36,'全唐诗/poet.song.94000.json','["左轉右轉，金剛寶劍。", "全藏半藏，由基發箭。", "紅心心裏中紅心，驚得須彌頭倒旋。"]'),
('0badeb12-729b-449d-8c1e-6091b9ab3dc7','頌古三十二首  其一七','釋明辯','宋','宋诗','song-poetry','','[]','大寂宗風示後昆，金剛寶劍利當門。',32,'全唐诗/poet.song.94000.json','["大寂宗風示後昆，金剛寶劍利當門。", "瞎驢滅卻正法眼，那箇男兒解出群。"]'),
('82c6a498-e7f0-48e6-9dc4-1127e7d207fe','頌古三十二首  其一八','釋明辯','宋','宋诗','song-poetry','','[]','脫略情塵老睦州，虎頭虎尾一時收。',32,'全唐诗/poet.song.94000.json','["脫略情塵老睦州，虎頭虎尾一時收。", "芳草渡頭韓幹馬，綠楊堤畔戴嵩牛。"]'),
('5605689e-6044-4777-9d4b-a6cfbd2ea7ba','頌古三十二首  其一九','釋明辯','宋','宋诗','song-poetry','','[]','體量非功不墮今，星移斗換豈同輪。',32,'全唐诗/poet.song.94000.json','["體量非功不墮今，星移斗換豈同輪。", "多年曆日雖無用，犯著應須總滅門。"]'),
('6ec7eb2e-707b-4257-b667-97f3bed230b0','頌古三十二首  其二○','釋明辯','宋','宋诗','song-poetry','','[]','高高孤頂雪濛濛，劫外行藏路不通。',32,'全唐诗/poet.song.94000.json','["高高孤頂雪濛濛，劫外行藏路不通。", "半夜嶺梅消息轉，不關春色暗香濃。"]'),
('56cc265a-e527-4806-9e17-94a3a8122733','頌古三十二首  其二一','釋明辯','宋','宋诗','song-poetry','','[]','玉鞭纔舉乾坤靜，皇道私無顯至尊。',32,'全唐诗/poet.song.94000.json','["玉鞭纔舉乾坤靜，皇道私無顯至尊。", "貴極鑾轝纔指斥，將軍正令不容存。"]'),
('277886ec-5e83-46eb-bbbd-9df11d1d154b','頌古三十二首  其二二','釋明辯','宋','宋诗','song-poetry','','[]','轉位投機覓更難，回途復妙豈相關。',32,'全唐诗/poet.song.94000.json','["轉位投機覓更難，回途復妙豈相關。", "新豐洞口翻波浪，一掃須教徹底乾。"]'),
('228c87f2-092b-411b-9029-c5454cc2cb1c','頌古三十二首  其二三','釋明辯','宋','宋诗','song-poetry','','["\u6000\u4eba", "\u4e94\u8a00\u7edd\u53e5", "\u95fa\u6028", "\u5510\u8bd7\u4e09\u767e\u9996"]','打起黄鶯兒，莫教枝上啼。',24,'全唐诗/poet.song.94000.json','["打起黄鶯兒，莫教枝上啼。", "幾回驚妾夢，不得到遼西。"]'),
('3f638eba-8b7a-4a16-ab5f-09e1dc3a3e33','頌古三十二首  其二四','釋明辯','宋','宋诗','song-poetry','','[]','六朝翻譯傳來妙，到頭未悟當時竅。',32,'全唐诗/poet.song.94000.json','["六朝翻譯傳來妙，到頭未悟當時竅。", "須信枝頭老鳳凰，春來翻作黄鶯叫。"]'),
('cbfd8ecd-1826-4a0a-b7f7-e4677fe3df12','頌古三十二首  其二五','釋明辯','宋','宋诗','song-poetry','','[]','萬丈寒潭徹底清，霜天午夜欲生冰。',32,'全唐诗/poet.song.94000.json','["萬丈寒潭徹底清，霜天午夜欲生冰。", "釣魚要擲金鱗餌，撥轉蘆蓬向月明。"]'),
('47d70ba4-5a02-4a51-be08-997ac6fe70cf','頌古三十二首  其二六','釋明辯','宋','宋诗','song-poetry','','[]','養得男兒要賭錢，渾身無有寸絲纏。',32,'全唐诗/poet.song.94000.json','["養得男兒要賭錢，渾身無有寸絲纏。", "是非窟裏和身入，生滅門中滿口宣。"]'),
('aa6ae107-0fe6-414c-9fd7-507e2f1aca98','頌古三十二首  其二七','釋明辯','宋','宋诗','song-poetry','','[]','高安灘頭百雜碎，象骨峰前眼搭癡。',32,'全唐诗/poet.song.94000.json','["高安灘頭百雜碎，象骨峰前眼搭癡。", "敢道鼓山無鼻孔，藂林千古笑嘻嘻。"]'),
('b5f3255a-47e0-42a0-8b25-197494523446','頌古三十二首  其二八','釋明辯','宋','宋诗','song-poetry','','[]','微酸梅子始生仁，鶯老花殘迹已陳。',32,'全唐诗/poet.song.94000.json','["微酸梅子始生仁，鶯老花殘迹已陳。", "一夜南風移斗柄，明朝煙柳不關春。"]'),
('40a3c3cd-92fe-41ad-b73b-f28e943388b9','頌古三十二首  其二九','釋明辯','宋','宋诗','song-poetry','','[]','老將高提白玉鞭，雙駒一策去翩翩。',32,'全唐诗/poet.song.94000.json','["老將高提白玉鞭，雙駒一策去翩翩。", "古今得失論量底，空看西山暮雨前。"]'),
('7d29594f-450a-45c2-a364-7572482df1c3','頌古三十二首  其三○','釋明辯','宋','宋诗','song-poetry','','[]','曲蟺踏著相頭摮，啞子得夢自家笑。',32,'全唐诗/poet.song.94000.json','["曲蟺踏著相頭摮，啞子得夢自家笑。", "笑到天明說向誰，烏鴉解作麒麟叫。"]'),
('9e777c4b-5fae-4ccf-80e3-63f9a70a71cc','頌古三十二首  其三一','釋明辯','宋','宋诗','song-poetry','','[]','試問人間有底忙，好將春事報春光。',32,'全唐诗/poet.song.94000.json','["試問人間有底忙，好將春事報春光。", "直饒日日花前醉，一季都來九十場。"]'),
('fdc2c09f-73e8-47c4-9694-680c931b8f23','頌古三十二首  其三二','釋明辯','宋','宋诗','song-poetry','','[]','栗蓬吞得有何難，更教吐出又心酸。',32,'全唐诗/poet.song.94000.json','["栗蓬吞得有何難，更教吐出又心酸。", "吞吐得來休嚼碎，南辰光射北辰寒。"]'),
('109f34c2-449e-474c-8525-b9e1bd46af83','見石火省徹頌','釋自回','宋','宋诗','song-poetry','','[]','用盡工夫，渾無巴鼻。',20,'全唐诗/poet.song.94000.json','["用盡工夫，渾無巴鼻。", "火光迸散，元在這裏。"]'),
('7e691b82-3167-451c-9e86-e52597f37b23','趙州勘婆頌','釋自回','宋','宋诗','song-poetry','','[]','三軍不動旗閃爍，老婆正是魔王腳。',32,'全唐诗/poet.song.94000.json','["三軍不動旗閃爍，老婆正是魔王腳。", "趙州無柄鐵掃帚，掃蕩煙塵空索索。"]'),
('39f01a2b-ca6f-4638-bede-cef82e130ce6','住東巖','釋居靜','宋','宋诗','song-poetry','','[]','月生一，東巖乍住增愁寂。',76,'全唐诗/poet.song.94000.json','["月生一，東巖乍住增愁寂。", "紅塵世路有多端，米麵倉儲無顆粒。", "崖爲伴，泉爲匹，颯颯清風來入室。", "山王土地暗中忙，雲版鐘魚偷淚滴。", "世人莫道空守巖，亦有東籬打西壁。"]'),
('eafe59c7-193e-47ea-ba65-6a1a1fe6bbc6','頌示學者','釋居靜','宋','宋诗','song-poetry','','[]','十門綱要掌中施，機會來時自有爲。',32,'全唐诗/poet.song.94000.json','["十門綱要掌中施，機會來時自有爲。", "作者不須排位次，大都首尾是根基。"]'),
('dce500f3-41b6-439e-b307-fbe55da29fe3','偈二首  其一','釋勝','宋','宋诗','song-poetry','','[]','即心即佛幾人知，立雪齊腰只得皮。',32,'全唐诗/poet.song.94000.json','["即心即佛幾人知，立雪齊腰只得皮。", "四海浪平龍玩寶，儘他螻蟻撼須彌。"]'),
('3ca4bf2b-7d34-4df9-a089-5f8938f0ee52','偈二首  其二','釋勝','宋','宋诗','song-poetry','','[]','護生須是殺，殺盡始安居。',24,'全唐诗/poet.song.94000.json','["護生須是殺，殺盡始安居。", "會得箇中意，分明在半途。"]'),
('ebecb55d-0fb4-4147-9448-820acf8d3020','頌古七首  其一','釋勝','宋','宋诗','song-poetry','','[]','無量妙義皆周匝，旋乾轉坤爲一合。',32,'全唐诗/poet.song.94000.json','["無量妙義皆周匝，旋乾轉坤爲一合。", "當陽橫按笑中刀，猶欠頂門上一踏。"]'),
('5c8c7a03-27d0-4399-8983-f29abe72c7af','頌古七首  其二','釋勝','宋','宋诗','song-poetry','','[]','漢祖拜將務決勝，非韓誰敢當茲任。',32,'全唐诗/poet.song.94000.json','["漢祖拜將務決勝，非韓誰敢當茲任。", "赤幡高竪化城降，星在盤兮不在秤。"]'),
('77805661-9d9f-4236-84a5-a44a9c5f585f','頌古七首  其三','釋勝','宋','宋诗','song-poetry','','["\u534e\u5c71"]','腳踏清波分華嶽，手擎紅日轉重雲。',32,'全唐诗/poet.song.94000.json','["腳踏清波分華嶽，手擎紅日轉重雲。", "徒勞謾費干戈力，究竟還歸有道君。"]'),
('20ff1d21-1eb8-4bd8-8a82-a39d0c77f956','頌古七首  其四','釋勝','宋','宋诗','song-poetry','','[]','借路經過無面目，因邪打正有拳頭。',32,'全唐诗/poet.song.94000.json','["借路經過無面目，因邪打正有拳頭。", "衲僧門下無干涉，徒用精金換得鍮。"]'),
('09320144-773d-4be8-8d65-b5f306d4aeb2','頌古七首  其五','釋勝','宋','宋诗','song-poetry','','[]','藤蘿荆棘離離草，枯樹無退還不倒。',32,'全唐诗/poet.song.94000.json','["藤蘿荆棘離離草，枯樹無退還不倒。", "敗棄知他疊幾重，不消一陳秋風掃。"]'),
('38bcd0a9-8efe-416c-aa0a-a24d342275af','頌古七首  其六','釋勝','宋','宋诗','song-poetry','','[]','許由臨岸洗耳，巢父不飲牛水。',28,'全唐诗/poet.song.94000.json','["許由臨岸洗耳，巢父不飲牛水。", "侍者親入帝鄉，趙州只在草裏。"]'),
('624eda82-03c5-4ed6-be9f-8e36b8ceda06','頌古七首  其七','釋勝','宋','宋诗','song-poetry','','[]','乙巳大人丘，叢林爲寇讎。',24,'全唐诗/poet.song.94000.json','["乙巳大人丘，叢林爲寇讎。", "利牙如劍戟，生殺有來由。"]'),
('58f7db58-893b-4771-b7b5-5e44cd060379','頌古二十四首  其一','釋勝','宋','宋诗','song-poetry','','[]','摩天鴆鳥九頭毒，護世那吒八臂長。',32,'全唐诗/poet.song.94000.json','["摩天鴆鳥九頭毒，護世那吒八臂長。", "水自竹邊流出冷，風從花裏過來香。"]'),
('c2d1e658-7fde-44c3-9d2b-bfcdcb4440c8','頌古二十四首  其二','釋勝','宋','宋诗','song-poetry','','[]','心佛物兮俱不是，坐斷舌頭除藥忌。',32,'全唐诗/poet.song.94000.json','["心佛物兮俱不是，坐斷舌頭除藥忌。", "橫拈倒用總由他，活捉魔群穿卻鼻。"]'),
('7e691140-39ff-4eba-9f94-42bea8372915','頌古二十四首  其三','釋勝','宋','宋诗','song-poetry','','[]','南泉王老太無端，卻逐鹽官作樂官。',32,'全唐诗/poet.song.94000.json','["南泉王老太無端，卻逐鹽官作樂官。", "西祖令嚴行禁止，免他禪會錯欣歡。"]'),
('94d52c45-a820-471a-921a-51f5516c593e','頌古二十四首  其四','釋勝','宋','宋诗','song-poetry','','[]','師子窟中師子兒，逸群遊翫海珠璣。',32,'全唐诗/poet.song.94000.json','["師子窟中師子兒，逸群遊翫海珠璣。", "溈山呼索渾無竅，有理難伸穿得奇。"]'),
('3408b3ee-36ec-4cf2-80b2-eafb076c156f','頌古二十四首  其五','釋勝','宋','宋诗','song-poetry','','[]','無業何太切，白雲何太孤。',24,'全唐诗/poet.song.94000.json','["無業何太切，白雲何太孤。", "胡鬚將謂赤，更有赤鬚胡。"]'),
('d7e42599-2e20-4229-bd57-8e27f7642d0f','頌古二十四首  其六','釋勝','宋','宋诗','song-poetry','','[]','就身打劫壯吾曹，喚得賢侯智眼高。',32,'全唐诗/poet.song.94000.json','["就身打劫壯吾曹，喚得賢侯智眼高。", "忿色不知何處去，珠回玉轉透雲袍。"]'),
('be31e977-6cf4-4ecd-b96e-51edaee197e3','頌古二十四首  其七','釋勝','宋','宋诗','song-poetry','','[]','陸亘回珠轉玉，南泉換斗移星。',28,'全唐诗/poet.song.94000.json','["陸亘回珠轉玉，南泉換斗移星。", "花陰滿地日午，夢覺流鶯一聲。"]'),
('e151300e-ff6a-4699-a642-4b8cfd9f9ac3','頌古二十四首  其八','釋勝','宋','宋诗','song-poetry','','[]','行者失卻眼，南泉破卻鍋。',24,'全唐诗/poet.song.94000.json','["行者失卻眼，南泉破卻鍋。", "滿堂僧不厭，一箇俗人多。"]'),
('6f806586-4095-46b4-baab-d54d68c1b379','頌古二十四首  其九','釋勝','宋','宋诗','song-poetry','','[]','披蓑側笠千峰上，引水澆蔬五老前。',32,'全唐诗/poet.song.94000.json','["披蓑側笠千峰上，引水澆蔬五老前。", "中有瓜田難納履，睦州倒退在傍邊。"]'),
('8e204893-0c32-4d10-8d06-e418110eb6be','頌古二十四首  其一○','釋勝','宋','宋诗','song-poetry','','[]','問端如箭透垣牆，賴值靈雲手段長。',32,'全唐诗/poet.song.94000.json','["問端如箭透垣牆，賴值靈雲手段長。", "駿馬蹇驢皆控勒，鞭教戰勝出沙場。"]'),
('ae1af97f-36e4-40e8-861e-880dddfd8401','頌古二十四首  其一一','釋勝','宋','宋诗','song-poetry','','[]','太孤太賒日杲杲，璞玉渾金惡種草。',32,'全唐诗/poet.song.94000.json','["太孤太賒日杲杲，璞玉渾金惡種草。", "無負平生雪此冤，不如一陣香風掃。"]'),
('fa1aeffd-7173-45ff-9573-4ea3a0d12cc5','頌古二十四首  其一二','釋勝','宋','宋诗','song-poetry','','[]','握七星刀尋作者，倒司農印對冤讎。',32,'全唐诗/poet.song.94000.json','["握七星刀尋作者，倒司農印對冤讎。", "當陽一句分賓主，九曲黄河水逆流。"]'),
('0eaa031b-dc90-4fcc-906d-82fad5127a3b','頌古二十四首  其一三','釋勝','宋','宋诗','song-poetry','','[]','剜心計剖腹繼傳燈，鬼面神頭打葛藤。',33,'全唐诗/poet.song.94000.json','["剜心計剖腹繼傳燈，鬼面神頭打葛藤。", "傑出諸方無等匹，也知只是赴齋僧。"]'),
('d5d91c1c-a2da-4c65-afc3-86c17019917b','頌古二十四首  其一四','釋勝','宋','宋诗','song-poetry','','[]','驅耕夫牛照即用，奪饑人食用即照。',32,'全唐诗/poet.song.94000.json','["驅耕夫牛照即用，奪饑人食用即照。", "不得同參把手行，安知袖裏有穿竅。"]'),
('b1e84e3b-e694-495e-b0c1-ff2333cfa5e5','頌古二十四首  其一五','釋勝','宋','宋诗','song-poetry','','[]','佛法無情報爾曹，忽生忽殺在吹毛。',32,'全唐诗/poet.song.94000.json','["佛法無情報爾曹，忽生忽殺在吹毛。", "若教韓信得妙訣，自是深明防漢高。"]'),
('6b026c8d-14f0-4a94-8002-07d47e7a74af','頌古二十四首  其一六','釋勝','宋','宋诗','song-poetry','','[]','一箇鐵額銅頭，一人三頭六臂。',28,'全唐诗/poet.song.94000.json','["一箇鐵額銅頭，一人三頭六臂。", "二俱借人鼻孔，卻與洞山出氣。"]'),
('f3d7243b-682b-4ad8-9663-82a73fb9fa44','頌古二十四首  其一七','釋勝','宋','宋诗','song-poetry','','[]','有喝端如探竿草，無師血脈通紅線。',32,'全唐诗/poet.song.94000.json','["有喝端如探竿草，無師血脈通紅線。", "當陽不識李將軍，徒學穿楊一枝箭。"]'),
('5c08fe9a-5ef2-4760-85ae-624150492bcf','頌古二十四首  其一八','釋勝','宋','宋诗','song-poetry','','[]','雞作蒼鷹拏鼈鼻，鴨爲金翅作獰龍。',32,'全唐诗/poet.song.94000.json','["雞作蒼鷹拏鼈鼻，鴨爲金翅作獰龍。", "空王以此垂洪範，錦上鋪花知幾重。"]'),
('25e98651-5441-48da-8cba-726dd6b45866','頌古二十四首  其一九','釋勝','宋','宋诗','song-poetry','','[]','展事無回互，投機通一綫。',24,'全唐诗/poet.song.94000.json','["展事無回互，投機通一綫。", "洞山無眼筋，入地獄如箭。"]'),
('7901e22c-5203-4493-82f5-8cd1ffdd1c54','頌古二十四首  其二○','釋勝','宋','宋诗','song-poetry','','[]','貓全食血功，虎備起屍殺。',24,'全唐诗/poet.song.94000.json','["貓全食血功，虎備起屍殺。", "無奈何舅何，不傳上樹訣。"]'),
('7f7f458a-44d8-4031-9f37-eaa086fe6e2c','頌古二十四首  其二一','釋勝','宋','宋诗','song-poetry','','[]','開口便見膽，工夫傲東魯。',24,'全唐诗/poet.song.94000.json','["開口便見膽，工夫傲東魯。", "昔於豆子山，也解打瓦鼓。"]'),
('43b1c289-5a62-4313-9b37-71e45a80b0b2','頌古二十四首  其二二','釋勝','宋','宋诗','song-poetry','','[]','鐵餡價難窮，誰知屈味濃。',24,'全唐诗/poet.song.94000.json','["鐵餡價難窮，誰知屈味濃。", "法幢光祖域，正董在胸中。"]'),
('aedc2cc3-bb82-4f20-98cb-347bdba9d144','頌古二十四首  其二三','釋勝','宋','宋诗','song-poetry','','[]','先祖滔滔無固必，後人悱悱有雌雄。',32,'全唐诗/poet.song.94000.json','["先祖滔滔無固必，後人悱悱有雌雄。", "巨靈擡手無多子，分破華山千萬重。"]'),
('79949319-3eab-48ac-aeaf-4d16c63b3ff6','偈頌四首  其一','釋師遠','宋','宋诗','song-poetry','','[]','今朝二月半，百華開爛熳。',64,'全唐诗/poet.song.94000.json','["今朝二月半，百華開爛熳。", "雲繞翠峰頭，鶯啼楊柳岸。", "觀音借路行，文殊分主伴。", "獨有解空人，支筇渾不管。", "直饒天外雨華飛，翻覆都來是這漢。"]'),
('c3459a10-be13-4c04-8bc0-8af2abe6632a','偈頌四首  其二','釋師遠','宋','宋诗','song-poetry','','[]','堯風舜日兩依依，一片虛凝截萬機。',32,'全唐诗/poet.song.94000.json','["堯風舜日兩依依，一片虛凝截萬機。", "何必胡僧親付囑，如人飲水自家知。"]'),
('ac6caccb-25d0-4350-a877-5e4370c5839e','偈頌四首  其三','釋師遠','宋','宋诗','song-poetry','','[]','五日一番陞座，拈出現成行貨。',28,'全唐诗/poet.song.94000.json','["五日一番陞座，拈出現成行貨。", "大衆普請商量，恰是老僧罪過。"]'),
('88b446bf-b414-4c27-a0ca-e69a1fe92175','偈頌四首  其四','釋師遠','宋','宋诗','song-poetry','','[]','三腳驢子弄蹄行，直透威音萬丈坑。',48,'全唐诗/poet.song.94000.json','["三腳驢子弄蹄行，直透威音萬丈坑。", "雲在嶺頭閑不徹，水流澗下大忙生。", "湖南長老誰能會，行人更在青山外。"]'),
('b4402951-281d-48ea-8403-a7cc3f6442f5','頌古三首  其一','釋師遠','宋','宋诗','song-poetry','','[]','出得出不得，定從何處起。',53,'全唐诗/poet.song.94000.json','["出得出不得，定從何處起。", "文殊往梵天，罔明輕彈指。", "乘流即行，遇坎即止。", "君不見虛築防胡萬里城，不知禍起蕭牆裏。"]'),
('4897eb78-308f-452c-85cc-4e1401d5eaca','頌古三首  其二','釋師遠','宋','宋诗','song-poetry','','[]','不是風兮不是顛，長街短巷走如煙。',32,'全唐诗/poet.song.94000.json','["不是風兮不是顛，長街短巷走如煙。", "院裏有齋常記得，時時掛在口皮邊。"]'),
('0c546960-8d66-4556-8202-f0108e50fed1','頌古三首  其三','釋師遠','宋','宋诗','song-poetry','','[]','呵呵大笑不尋常，笑得眉間也放光。',32,'全唐诗/poet.song.94000.json','["呵呵大笑不尋常，笑得眉間也放光。", "不是明招重注腳，叢林洎合錯商量。"]'),
('76b15fe9-9602-44b3-863e-354b3b54842c','舉趙州訪二庵主公案頌','釋紹悟','宋','宋诗','song-poetry','','[]','一重山盡一重山，坐斷孤峰子細看。',32,'全唐诗/poet.song.94000.json','["一重山盡一重山，坐斷孤峰子細看。", "霧卷雲收山嶽靜，楚天空闊一輪寒。"]'),
('2cb32888-69b2-43ee-8a3b-4b419a9a773e','石庵成日偈','子言庵主','宋','宋诗','song-poetry','','[]','一擊石庵全，縱然得自然。',48,'全唐诗/poet.song.94000.json','["一擊石庵全，縱然得自然。", "清涼無暑氣，涓潔有甘泉。", "寬廓含沙界，寂寥絕衆緣。", "箇中無限義，風月一床眠。"]'),
('fb6cd872-f237-4269-b208-608d69a03c0d','答贇禪師問宗門三印','南修造','宋','宋诗','song-poetry','','[]','印空印泥印水，平地寒濤競起。',28,'全唐诗/poet.song.94000.json','["印空印泥印水，平地寒濤競起。", "假饒去就十分，也是靈龜曳尾。"]'),
('44ba664d-b5a3-4f13-847b-5b407ad22b62','偈','釋高','宋','宋诗','song-poetry','','[]','象王行，師子住，赤腳崑崙眉卓竪。',32,'全唐诗/poet.song.94000.json','["象王行，師子住，赤腳崑崙眉卓竪。", "寒山拾得笑呵呵，指點門前老松樹。"]'),
('da918cb8-2b17-4f4e-8a73-58892dc93e05','頌古五首  其一','釋慧光','宋','宋诗','song-poetry','','[]','雨洗淡紅桃蕚嫩，風搖淺碧柳絲輕。',32,'全唐诗/poet.song.94000.json','["雨洗淡紅桃蕚嫩，風搖淺碧柳絲輕。", "白雲影裏怪石露，綠水光中古木清。"]'),
('1761c5cf-0e84-4d52-a71a-6ac26d928be8','頌古五首  其二','釋慧光','宋','宋诗','song-poetry','','[]','窣堵古形儀，未舉已先知。',24,'全唐诗/poet.song.94000.json','["窣堵古形儀，未舉已先知。", "巍然存海底，影落樹頭輝。"]'),
('9d868d1f-7472-451a-8538-5fd96d69ab91','頌古五首  其三','釋慧光','宋','宋诗','song-poetry','','[]','偷喫油糍，賣弄口觜。',20,'全唐诗/poet.song.94000.json','["偷喫油糍，賣弄口觜。", "年老成魔，謾神嚇鬼。"]'),
('22b8222c-d53a-46a4-85b5-c5310d19a23c','頌古五首  其四','釋慧光','宋','宋诗','song-poetry','','[]','一吹無孔笛，一撫沒絃琴。',28,'全唐诗/poet.song.94000.json','["一吹無孔笛，一撫沒絃琴。", "一曲兩曲無人會，雨過夜塘秋水深。"]'),
('44106c69-6c41-44ef-9564-0569ac17d338','頌古五首  其五','釋慧光','宋','宋诗','song-poetry','','[]','狗子無佛性，全提摩竭令。',24,'全唐诗/poet.song.94000.json','["狗子無佛性，全提摩竭令。", "纔擬犯鋒鋩，喪卻窮性命。"]'),
('3b228094-7f3f-419f-a52d-bd6d7de79921','尋春次曾宏甫韻','曾幾','宋','宋诗','song-poetry','','[]','春山數峰青，春水一溪綠。',108,'全唐诗/poet.song.94000.json','["春山數峰青，春水一溪綠。", "幽尋山水間，物物可寓目。", "花香若三薫，柳色若新沐。", "吾儕幸閑放，晴晝頗連屬。", "胡爲深閉門，終日仰看屋。", "嘉招儻亟拜，豈敢憚僕僕。", "請君攜壺去，政恐日不足。", "小槽雖蜜甜，何必待醽醁。", "茗事姑置之，雷車困枵腹。"]'),
('c9a61777-c7d1-4639-9cfc-50866f081cb0','次范益謙遷居九江經過上饒見贈韻','曾幾','宋','宋诗','song-poetry','','[]','君爲九江行，意有風雨快。',168,'全唐诗/poet.song.94000.json','["君爲九江行，意有風雨快。", "維舟玉溪畔，未割故人愛。", "停杯一問我，請以所聞對。", "九江萬事好，賞詠看前輩。", "巖巖匡俗廬，頂踵極高大。", "其中藏曲折，願勿遺瑣碎。", "煙波湓浦游，風月庾樓會。", "以兹供筆硯，安得有蕪累。", "矧君著幽禪，直欲入三昧。", "飽參山南北，毋問人顯晦。", "歸來亦何云，聖處果何在。", "要知方策間，即有文字外。", "我今如是說，初不墮荒怪。", "屋漏實臨之，斯言尚無愧。"]'),
('a3f14b10-1da0-49db-9422-9001e0e0e3b9','次陳少卿見贈韻','曾幾','宋','宋诗','song-poetry','','[]','少卿令德公，不肯入州府。',144,'全唐诗/poet.song.94000.json','["少卿令德公，不肯入州府。", "種花養風煙，藝木蔭庭宇。", "了無適俗韻，真可與晤語。", "永懷君詩句，凈洗我塵土。", "如何百里問，此秘欠未覩。", "今晨款荆扉，老氣壓方虎。", "新詩疾雨風，妙字列行伍。", "華宗有后山，句律嚴七五。", "豫章乃其師，工部以爲祖。", "君方討淵源，奚啻窺牖戶。", "我貧無一錢，不敢學農圃。", "空餘數卷書，腸腹自撐拄。"]'),
('d2584525-3575-4901-be32-03cd76f3092a','陳卿又和三首而仲通判亦三作嚴教授再賦皆有見及語予不可以無言故復次韻','曾幾','宋','宋诗','song-poetry','','[]','官屬邃中書，朝班高太府。',144,'全唐诗/poet.song.94000.json','["官屬邃中書，朝班高太府。", "陳卿棹臂去，偃仰一茅宇。", "臨池看魚樂，坐樹聽鳥語。", "脩竹手所栽，薪萌爭上土。", "天開重新運，聖作萬物覩。", "會合如風雲，吹嘘者龍虎。", "陳卿落閑處，問孰與爲伍。", "毛穎傳中人，渠儂適成五。", "詩章出咳唾，流派考宗祖。", "仲嚴更獻酬，胸次非小戶。", "覽觀不暇給，爛若花藥圃。", "可畏韻險艱，浮梁裊相拄。"]'),
('d005d455-a798-4a15-8a04-9333f6b17e4c','沈明遠教授用東坡仇池石韻賦予所蓄英石次其韻','曾幾','宋','宋诗','song-poetry','','[]','維南有絲溪，溪石如水綠。',168,'全唐诗/poet.song.94000.json','["維南有絲溪，溪石如水綠。", "瞻相百里間，抱負一夫足。", "聲名作災怪，攻取及背腹。", "在者略無奇，溪神爲顰蹙。", "蠻煙瘴雨地，故舊實州牧。", "坐令數峰青，飛過大江凟。", "何嘗說向人，恐類和氏玉。", "公然遭奪攘，不使得藏伏。", "廣文到吾廬，索隱妙蓍卜。", "東坡韻險艱，句句巧追逐。", "幽人所好山，已占一林谷。", "又兼小崢嶸，無乃太多欲。", "端如耐久朋，相與會心曲。", "大勝輕薄兒，浮雲變何速。"]'),
('f38f0b62-cce6-47c9-8041-c1ee5c447fb6','次綠字韻','曾幾','宋','宋诗','song-poetry','','[]','舍前南山青，舍後北山綠。',168,'全唐诗/poet.song.94000.json','["舍前南山青，舍後北山綠。", "捫蘿涉其巔，策杖遶其足。", "中間奇絕處，表裏見心腹。", "登臨豈不佳，老境日以蹙。", "誰知怪石供，能坐我郊牧。", "政應索幽遐，何憚越川凟。", "嶔𡼭庾嶺南，美者色蒼玉。", "賞音無東坡，尤物多跧伏。", "今年致書求，屢以可否卜。", "故人爲遣送，健步遠相逐。", "雖非古仇池，要是好崖谷。", "似爲天所矜，此段獨從欲。", "深慚舁致重，路轉知幾曲。", "安得滄海神，鞭笞使之速。"]'),
('7ae9566a-6372-487f-aaa8-100ef74ee81e','還守台州次陸務觀贈行韻','曾幾','宋','宋诗','song-poetry','','[]','蟬噪高柳岸，鷺飛遠沙汀。',204,'全唐诗/poet.song.94000.json','["蟬噪高柳岸，鷺飛遠沙汀。", "蕭然感予懷，清靜游神庭。", "老樹失故綠，殘芳謝微馨。", "胡爲趣召節，日日晨昏星。", "放纜西興渡，落帆浙江亭。", "恭惟陛下聖，萬國瞻儀刑。", "黼座懸日月，孤燈耿熒熒。", "况復如許病，自知不能廷。", "所以乞閑散，庶幾守沈冥。", "方虞秋霜嚴，翻得春露零。", "再聞芸草香，一洗海物腥。", "父老喜我來，無異化鶴丁。", "兒童喜我來，小駟騎青青。", "諒有隔生契，不然定誰令。", "四海習鑿齒，幾年讀書螢。", "新詩中律呂，雖美無人聽。", "鳴聲勿浪出，坐待軒皇伶。"]'),
('d942a611-9ed1-4c95-9eb2-3d50998ac1e7','次折仲古避寇潯州韻','曾幾','宋','宋诗','song-poetry','','[]','我持十口家，不辦一葉船。',240,'全唐诗/poet.song.94000.json','["我持十口家，不辦一葉船。", "賊聲日夜急，欲濟江無邊。", "身雖墮眢井，仰視猶有天。", "天理儻未爽，偷兒浪垂涎。", "洗心占羅池，稽首依靈泉。", "竟以妻子免，百神果昭然。", "得從潯江遊，未斷龍城緣。", "爲問米何如，買禾可論廛。", "向來魚菜市，十戶八九旋。", "令我喜折屐，喜定翻悲憐。", "王師靜江南，趨者人摩肩。", "一日百回首，我非強項宣。", "盛欲徑梅庾，不然傍郴連。", "終鮮孔方兄，留滯等謫遷。", "尚念吾鼻祖，永懷舊山川。", "往還武城居，家風到今傳。", "我方尋昨夢，一舸百笮牽。", "而公下劈箭，如駔駿得鞭。", "江村索居地，未敢高枕眠。", "世事公等在，歸與有逢年。"]'),
('9723d7cb-6d86-4e25-b92a-ccf03a5ac56c','次雪峰空老韻二首  其一','曾幾','宋','宋诗','song-poetry','','[]','雪峰僧中龍，此道誰與共。',48,'全唐诗/poet.song.94000.json','["雪峰僧中龍，此道誰與共。", "蕭然兩伽陀，不舉似大衆。", "獨貽茶山老，以當蒲塞供。", "巖花與澗草，信手拈來用。"]'),
('6939a139-fd96-4bd9-af27-6aac023f1093','次雪峰空老韻二首  其二','曾幾','宋','宋诗','song-poetry','','[]','獨烹茶山茶，未對雪峰雪。',48,'全唐诗/poet.song.94000.json','["獨烹茶山茶，未對雪峰雪。", "須知千里間，只共一眀月。", "陳家參玄人，道眼應一瞥。", "爲語管城君，相從熾然說。"]'),
('25679285-40de-45b8-a707-74ad3ac89af5','贈疏山清老','曾幾','宋','宋诗','song-poetry','','[]','江西草堂清，道價直寰宇。',156,'全唐诗/poet.song.94000.json','["江西草堂清，道價直寰宇。", "中分死心坐，親飲晦堂乳。", "與人作陰凉，雨後散煩暑。", "千林搖落後，鬰鬰松柏古。", "厖頭覆霜雪，碧眼照針縷。", "貫穿禪家流，領略我輩語。", "居山専論道，餘事百不覩。", "人言師疏慢，我但見媚嫵。", "去年瀟湘來，叢席歷幾所。", "踞堂號知識，說法若雲雨。", "陰求乃翁事，未見一人舉。", "請師長住世，此道要盟主。", "杖拂有餘閑，時時入州府。"]'),
('ad6245a8-ac01-4025-ab40-1b7c0bda7d62','贈空上人','曾幾','宋','宋诗','song-poetry','','[]','我搴空門秀，得之古疏山。',192,'全唐诗/poet.song.94000.json','["我搴空門秀，得之古疏山。", "斯人器玉壺，中有寶月寒。", "四壁澹相對，安身一蒲團。", "玲瓏六窗靜，竟日心猿閑。", "時從禪那起，游戲于筆端。", "當其參尋時，恣意雲水間。", "松風潄齒頰，蘿月入肺肝。", "政使不學詩，已見詩一斑。", "況復用心苦，俗氛何由干。", "今晨出數篇，秀色若可餐。", "清妍梅著雪，圓美珠走盤。", "乃知心鏡中，萬象紛往還。", "皆吾所現物，摹寫初不難。", "誰能效我輩，造語出險艱。", "請師賸汲古，凈洗蔬腸酸。", "坐令韓退之，收歛加巾冠。"]'),
('b193f95b-6737-4c67-8391-6ee184d1d3f9','送秘丞羅庭揚將漕湖北','曾幾','宋','宋诗','song-poetry','','[]','湖南八九州，海內清絕地。',144,'全唐诗/poet.song.94000.json','["湖南八九州，海內清絕地。", "與公白雞年，接翼鴻雁使。", "高堂親八十，無復遠逰意。", "奉承萬事了，趨走三節至。", "詔書引上殿，帝曰汝國器。", "置之蓬萊山，身亦典中秘。", "乖離如許久，會念差足慰。", "胡爲未暖席，歸與不可制。", "人生故鄉樂，況攬澄清轡。", "皇華遣使臣，光采寧有是。", "紅塵跨鞍馬，老矣殊少味。", "著鞭輸公先，吾亦從此逝。"]'),
('8c6815f7-17de-417d-a197-1617d5752378','贈趙判官壽卿二首  其一','曾幾','宋','宋诗','song-poetry','','[]','身爲高帝孫，面作寒士氣。',48,'全唐诗/poet.song.94000.json','["身爲高帝孫，面作寒士氣。", "緣情德麟語，寫物大年意。", "青雲無蘇黄，何以致後世。", "窗明几靜間，是事且遊戲。"]'),
('48d40194-4411-4a8f-ba0c-ec097ca338a6','贈趙判官壽卿二首  其二','曾幾','宋','宋诗','song-poetry','','[]','得州敢爲榮，得士乃足詫。',48,'全唐诗/poet.song.94000.json','["得州敢爲榮，得士乃足詫。", "此郎精琴書，不獨妙詩畫。", "雖云于小道，舉不在人下。", "無乃太不廉，誰知非譏罵。"]'),
('4c8c9de9-81ab-463a-8a61-e1bf6c1c7383','王巖起樂齋','曾幾','宋','宋诗','song-poetry','','[]','歡悰挽不來，愁思推不去。',120,'全唐诗/poet.song.94000.json','["歡悰挽不來，愁思推不去。", "達人方寸地，固自有樂處。", "得非山林歟，或用詩酒故。", "一朝不在眼，便覺少佳趣。", "人言顔子樂，瓢飲映蔬茹。", "何曾夢見渠，浪自起欣慕。", "此君與天游，于物初不寓。", "攜持小齋名，扁榜隨所住。", "要知真樂事，未省離跬步。", "我亦欲睎顔，從君尚能屢。"]'),
('52f30098-94b3-4898-9f7a-cdf4e774c27a','題張彦實舍人墓下湧泉亭','曾幾','宋','宋诗','song-poetry','','[]','紫薇花底人，去作泉下夢。',96,'全唐诗/poet.song.94000.json','["紫薇花底人，去作泉下夢。", "佳城閉青春，風木號永痛。", "寒泓孰出之，甘冽可抱甕。", "乃知主地神，效此清凈供。", "汲引入中廚，色味勝乳湩。", "老龍來試詩，事有萬鈞重。", "寄聲松大夫，并語石翁仲。", "俱修護持職，以遺雲來用。"]'),
('ef3469fb-d903-43aa-9cc6-bef94237fd0a','題盛彦光少府丘壑軒','曾幾','宋','宋诗','song-poetry','','[]','何許覓丘壑，不専在山林。',72,'全唐诗/poet.song.94000.json','["何許覓丘壑，不専在山林。", "胸次儻蕭散，市朝有幽尋。", "只今謝幼輿，超然抱遐心。", "俯仰得佳趣，何嘗日登臨。", "我雖非夔曠，粗亦能賞音。", "不用一再鼓，山高水深深。"]'),
('4eb2de00-7564-425f-814e-bf0500b78f94','題黄嗣深家所蓄惠崇秋晚畫','曾幾','宋','宋诗','song-poetry','','[]','叢蘆受風低，積潦得霜淺。',48,'全唐诗/poet.song.94000.json','["叢蘆受風低，積潦得霜淺。", "沙勻洲渚凈，水澹鳧鴨遠。", "禪扉掩晝夜，短紙開秋晚。", "欲問此間詩，半山呼不返。"]'),
('6e4c4fc4-462a-40b2-ad94-ee54862add42','題程伯禹給事漫吾亭','曾幾','宋','宋诗','song-poetry','','[]','漫郎専一溪，萬事俱不理。',144,'全唐诗/poet.song.94000.json','["漫郎専一溪，萬事俱不理。", "胡爲墮我相，名字出奇詭。", "山林軒冕歟，等是寄焉耳。", "程公榜亭意，道眼深照此。", "端居亦偶然，小出聊復爾。", "宣城幻事了，郤夢歸故里。", "結廬澄潭上，盡室清鏡裏。", "木陰凉夏簟，荷氣馥秋水。", "遥岑招不來，爲我列窗几。", "昔吾與今吾，念念如脱屣。", "心期次山外，人要安石起。", "公勿賦遠遊，行應去天咫。"]'),
('816cdd4e-1ec2-4d4a-9acf-bcf2351eac1f','題南嶽銓德觀秋聲軒','曾幾','宋','宋诗','song-poetry','','["\u8861\u5c71"]','月明雁叫遠，露下蟬號寒。',120,'全唐诗/poet.song.94000.json','["月明雁叫遠，露下蟬號寒。", "幽幽草蟲泣，索索梧葉乾。", "愁人知秋早，聽此良獨難。", "竹君南北美，佩服青琅玕。", "天風一披拂，庭宇聲珊珊。", "靈宫蔭老樾，别館如深山。", "心凈鑒止水，眼明揖千竿。", "虛籟自然奏，有琴不須彈。", "世議大可厭，市聲無少閑。", "不如聽君語，竟日簾垂間。"]'),
('fef1c89b-a110-4932-8f0a-058fb78ee5db','題臨川宰徐伯章心遠軒','曾幾','宋','宋诗','song-poetry','','[]','徐侯心萬里，身墮百里中。',108,'全唐诗/poet.song.94000.json','["徐侯心萬里，身墮百里中。", "政以詩禮庭，上有鶴髪翁。", "豈無敲榜喧，不入丘壑胸。", "開軒寄遠韻，几凈窗玲瓏。", "竹影落夏簟，水光搖秋空。", "一對鳧鶩行，萬里牛馬風。", "悠然見南山，不與俗眼同。", "徐侯歸去來，三徑資已豐。", "身將心共遠，勿爲督郵恭。"]'),
('73cf9696-1012-4204-96f3-e359caf7d311','春初過王仲禮教授小園','曾幾','宋','宋诗','song-poetry','','[]','幽居倦孤寂，俗駕難追攀。',144,'全唐诗/poet.song.94000.json','["幽居倦孤寂，俗駕難追攀。", "相攜笻九節，徑造茅三間。", "王卿貧無事，况得獨冷官。", "衡門靜如水，委巷深于山。", "自言學爲圃，雖小殊可觀。", "始至度略彴，徐行轉闌干。", "當階藝紅藥，坐待青春還。", "春還未數日，草樹猶清寒。", "殷勤小梅花，一笑冰雪顔。", "煑茗當酒醴，言詩替吹彈。", "君知靜中勝，得此良獨難。", "相戒勿浪出，黄塵點人冠。"]'),
('9886de24-41e2-469f-81c7-558c91ff5aa6','汪㟯惇仁教授即官舍作齋予以獨冷名之','曾幾','宋','宋诗','song-poetry','','[]','昔君困虀鹽，蓬首窗下讀。',132,'全唐诗/poet.song.94000.json','["昔君困虀鹽，蓬首窗下讀。", "秋螢屢乾死，明月以爲燭。", "麻衣肘欲穿，才換一袍綠。", "豈知冷淡債，十載償未足。", "書齋開冰廳，敗壁數椽屋。", "横經綴鵠鷺，未省進鳧鶩。", "窮通更事耳，裘扇有反覆。", "直今張羅地，便恐車擊轂。", "先生粲可流，示現著冠服。", "從渠勢炙手，了不見凉燠。", "小詩應大笑，笑我未忘俗。"]'),
('63011f46-91ae-4d58-a9f3-9b4cda90aacf','董令升舍人朋溪圖趙祖文筆也','曾幾','宋','宋诗','song-poetry','','[]','谷風不須歌，朋友道缺絕。',144,'全唐诗/poet.song.94000.json','["谷風不須歌，朋友道缺絕。", "請歌伐木詩，歌罷聽吾說。", "漢朝儒宗系，今代侍臣傑。", "甘泉久論思，陽羡小休歇。", "郊園谷幽幽，喬木覆清樾。", "百禽鳴其間，相喚極可悦。", "坐令公感慨，朋好苦難結。", "不如侶荆溪，迥與世情别。", "淡乎若無味，了不見凉熱。", "是以樂從之，諸峰况羅列。", "趙侯有能事，短紙藏曲折。", "更作陶淵眀，飄颻弄明月。"]'),
('eac390a0-677a-4b1b-9112-d4b74b6a7e01','相馬圖呈杜勉齋左司','曾幾','宋','宋诗','song-poetry','','[]','造物出萬類，貴賤伊誰分。',252,'全唐诗/poet.song.94000.json','["造物出萬類，貴賤伊誰分。", "圭璋雜瓦礫，世道同疏親。", "既收大宛種，一掃駑駘群。", "乃觀相馬圖，低首先吟呻。", "千金購死骨，舉國無其真。", "生死何太晚，鹽車負艱辛。", "悠悠虞阪道，赤日煎紅塵。", "行人亦何多，具眼惟孫君。", "一顧不旋踵，價越連城珍。", "誰爲繪此像，庸示將來人。", "相馬失之瘦，相士失之貧。", "于兹有鉅公，數載居沉淪。", "涵養浩然氣，輪蹄任紛紜。", "素識太平相，鶚表飛青雲。", "紫泥日邊下，八座生陽春。", "攄心握文柄，引年啟賢門。", "凝睇辨臧否，立志安斯民。", "他時了經濟，丹青畫麒麟。", "回顧相馬者，細務何足云。", "寥寥載千古，二道非同倫。", "相士今何人，少陵身後身。"]'),
('419df8de-14fd-4b71-bd43-4f55176fb009','紹興帥相湯公會五客蓬萊閣登望海亭屬某賦詩','曾幾','宋','宋诗','song-poetry','','[]','赫赫會稽郡，潭潭府公居。',192,'全唐诗/poet.song.94000.json','["赫赫會稽郡，潭潭府公居。", "一州勝絕處，畢集于庭除。", "秦望極高秀，千峰散江湖。", "蓬萊爲收攬，遠近爭奔趨。", "溟渤無百里，登臨失東隅。", "翬飛卧龍頂，便可窺方壺。", "丞相不獨饗，故人盛招呼。", "兵厨列樽俎，賓次羅簪裾。", "傑閣坐褫带，危亭上肩輿。", "耄倪爭指似，還見雲間無。", "一月明白璧，五星燦連珠。", "鄙夫何足數，愧汗沾霜鬚。", "客有徐季海，題名數行書。", "怒猊抉石外，筋力顔之徒。", "周老盍命駕，屬聞遂懸車。", "何妨行役事，政用兒孫扶。"]'),
('fa4c4a83-2ba6-4ca3-84a1-7f5a7aacd8fe','陸務觀讀道書名其齋曰玉笈','曾幾','宋','宋诗','song-poetry','','[]','自生民以來，未有夫子盛。',192,'全唐诗/poet.song.94000.json','["自生民以來，未有夫子盛。", "六經更百代，略不覩疵病。", "瞿聃書角立，亦各談性命。", "空門甚宏放，果報駭觀聽。", "是以雖至愚，讀者無不敬。", "周時柱下史，設教本清靜。", "至今五千言，談若鼔鐘磬。", "雖爲二郗諂，秖作二何佞。", "遂令黄冠徒，冷落度晨暝。", "賢哉機雲孫，道眼極超勝。", "殺青貝多葉，收貯腹中竟。", "慨然發琅函，窗白棐几凈。", "三家一以貫，不事頰舌競。", "吾皇漢孝文，恭已民自定。", "願君益沈涵，持以奉仁聖。", "遠師曹相國，下視劉子政。"]'),
('27c2554e-aeb4-4ece-b4fc-8b746e70f5d5','喜得洞霄','曾幾','宋','宋诗','song-poetry','','[]','乞身知才疏，從容荷主聖。',96,'全唐诗/poet.song.94000.json','["乞身知才疏，從容荷主聖。", "叫閽如杜宇，不謂天亦聽。", "除書入手來，一洗百念靜。", "復疑是夢中，驚喜久乃定。", "尚餘折腰米，敗我生塵甑。", "要令襟見肘，始與家聲稱。", "今兹火用事，日永南風競。", "林下聽中興，姑容老夫病。"]'),
('0dc0bc0f-593a-4e76-a554-45edc07634e3','喜天游二十一兄至亳社時同叔夏十六兄作','曾幾','宋','宋诗','song-poetry','','[]','登高望南都，雉堞疑可數。',132,'全唐诗/poet.song.94000.json','["登高望南都，雉堞疑可數。", "城中人不見，百里等燕楚。", "我無簡書畏，自笑誰縛汝。", "東風送兄來，下馬逼三鼔。", "迎門閙兒童，羅拜欣欲舞。", "花枝應亦喜，紅幞已微吐。", "聊爲文字飲，一洗别離苦。", "别離何足云，千載成仰俯。", "要知靜中趣，回視今孰愈。", "焚香默自照，下此一轉語。", "鈴閣老師兄，當爲君去取。"]'),
('5229b112-a54d-49fd-99b5-ae1e41b24a6c','言懷貽寓居','曾幾','宋','宋诗','song-poetry','','[]','郊居麥風凉，佛屋梅雨潤。',96,'全唐诗/poet.song.94000.json','["郊居麥風凉，佛屋梅雨潤。", "縈簾一炷香，隱几百念盡。", "時從黄卷語，坐看青燈燼。", "昏昏花亂眼，種種雪侵鬢。", "懷哉佳友朋，久矣闕親近。", "其誰破愁寂，令我生鄙吝。", "及閑當過君，請以茗椀進。", "言詩固不能，把酒亦無分。"]'),
('4d5ea162-52bb-4fdf-82eb-5a5a094887b9','坐睡','曾幾','宋','宋诗','song-poetry','','[]','竹窗納虛明，棐几亦滑凈。',96,'全唐诗/poet.song.94000.json','["竹窗納虛明，棐几亦滑凈。", "幽人坐清秋，倦對古賢聖。", "丹田閲千息，一氣忽空靜。", "豈期黑甜鄉，于此得棲徑。", "倒牀未必佳，邂逅乃復勝。", "覺來欠伸餘，兩眼半開瞑。", "吾身竟何許，神意久方定。", "從此謝衾帷，蒲團日相倩。"]'),
('58b9f3ce-0376-4cff-8cc4-1a5e234917d0','自越上還信步尋梅','曾幾','宋','宋诗','song-poetry','','[]','客子千里至，未曾款入門。',72,'全唐诗/poet.song.94000.json','["客子千里至，未曾款入門。", "妻孥勞苦外，徑走江梅村。", "江梅若有待，欲謝花猶存。", "向人一笑粲，冷蘂生春温。", "遶樹三匝已，投空雪飛翻。", "歸來理夢事，淡月籠黄昏。"]'),
('39832b68-4bdd-4c75-b622-c788aa809b4e','鄭侍郎招賞瑞香','曾幾','宋','宋诗','song-poetry','','[]','浮花雖不多，要是乏美質。',48,'全唐诗/poet.song.94000.json','["浮花雖不多，要是乏美質。", "前庭錦烘籠，君向何許得。", "色香極穠麗，裁翦極細密。", "複幕重簾開，毋令犯風日。"]'),
('6b1038c9-85e7-484b-9e77-d116844e38bc','晁侍郎折贈芍藥三種','曾幾','宋','宋诗','song-poetry','','[]','室空無侍者，終日延白光。',144,'全唐诗/poet.song.94000.json','["室空無侍者，終日延白光。", "今夕果何夕，粲者忽在旁。", "得非散花天，來試鐵石腸。", "非羅復非綺，何物爲衣裳。", "或濃若猩血，或淺若鵝黄。", "或如淡臙脂，薫以百和香。", "竟不可意解，發書問何祥。", "乃知延閣老，買得從維揚。", "自不耐渠惱，幽懷可禁當。", "牢辭又不敢，熟視徒彷徨。", "吾聞諸古人，物美應獻王。", "呼兒燎沈水，持以供虛皇。"]'),
('a238f33d-9aff-4a99-932f-cbaa10d363f1','明秀堂松','曾幾','宋','宋诗','song-poetry','','[]','柳侯所爲邦，十步一遺跡。',120,'全唐诗/poet.song.94000.json','["柳侯所爲邦，十步一遺跡。", "蒼官列前墀，相對儼如客。", "邦人言此松，曾及侍侯側。", "風號四百年，雪立二千尺。", "江城閑草木，詩卷多採摘。", "柑非往日黄，柳是近時碧。", "同生不同死，乃見老氣格。", "尚想哦其間，清聲出金石。", "龍鱗未脱落，熊軾幾換易。", "臨民有餘師，視此古遺直。"]'),
('4cdb3804-9cfa-4bf6-9dbe-9d84b1711463','種芭蕉','曾幾','宋','宋诗','song-poetry','','[]','僧窗誰與晤，有竹兩三竿。',120,'全唐诗/poet.song.94000.json','["僧窗誰與晤，有竹兩三竿。", "栽培費老手，方法傳多端。", "朝朝問無恙，暮暮愁其乾。", "調護閲三載，今年遽彫殘。", "芭蕉雖小草，長大不作難。", "一身菡萏然，萬竅玲瓏間。", "滿中貯春水，烈日何能干。", "以兹陰凉葉，代彼青琅玕。", "但恐質柔脆，不堪歲祁寒。", "人生無牢強，當作如是觀。"]'),
('004fe952-fcb9-4c3e-ac27-68c446445ba2','詠蠟梅','曾幾','宋','宋诗','song-poetry','','[]','花時冶遊郎，紛若一鬨市。',48,'全唐诗/poet.song.94000.json','["花時冶遊郎，紛若一鬨市。", "蠟梅空自芳，俗眼不稱意。", "洗心無一塵，坐覺香細細。", "乃知成風斤，要斲郢人鼻。"]'),
('00f4c705-07db-4b7e-b488-a906e8949dc1','吳甥遺靈壁石以詩還之','曾幾','宋','宋诗','song-poetry','','[]','閑居百封書，總爲一片石。',120,'全唐诗/poet.song.94000.json','["閑居百封書，總爲一片石。", "窗中列遠岫，所欠者靈壁。", "吳甥手持來，知向何許得。", "鏗鏘發金聲，温潤見玉色。", "諸峰掃空翠，一水界山白。", "嵁巖出其間，如月挂虛碧。", "坐令所珍藏，不作一錢直。", "吾雖甚愛之，子亦有此癖。", "歸與霅溪旁，從汝舊知識。", "欲去復遲遲，摩挲遂移刻。"]'),
('2697cdaf-4b5f-462c-9670-3e3ad711545d','何德器贈太湖石','曾幾','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','愛山已成癡，愛石又成癖。',144,'全唐诗/poet.song.94000.json','["愛山已成癡，愛石又成癖。", "徒聞有絲溪，時復夢靈壁。", "太湖只在眼，曾未收寸碧。", "多自五嶺來，仍煩百書索。", "何侯小崢嶸，湖水深處得。", "蒼潤波濤餘，巉巖鬼神力。", "摩挲復湔洗，攘取畏賓客。", "偶然及幽事，遣送初不惜。", "俄頃交定盟，歡焉慰岑寂。", "奪君書几間，坐我洞庭側。", "持還豈人情，藏去有慚色。", "苦乏仇池篇，如何滿高直。"]'),
('594b84f4-6894-4513-9b7c-778334a69730','寄崑山李宰覓石','曾幾','宋','宋诗','song-poetry','','[]','崑山定飛來，美玉山所有。',120,'全唐诗/poet.song.94000.json','["崑山定飛來，美玉山所有。", "山祇用功深，刓畫歲時久。", "崢嶸出峰巒，空洞開戶牖。", "幾書通置郵，一片未入手。", "即今製錦人，在昔伐木友。", "嘗蒙委繡段，尚闕報瓊玖。", "奈何不厚顔，尤物更乞取。", "但懷相知心，豈憚一開口。", "指揮爲幽尋，包裹付下走。", "散帙列岫窗，摩挲慰衰朽。"]'),
('a15f8c17-2d26-4159-8687-f5ece5568133','造侄寄人面毛竹杖四','曾幾','宋','宋诗','song-poetry','','[]','麥秋氣清和，槐夏日陰翳。',144,'全唐诗/poet.song.94000.json','["麥秋氣清和，槐夏日陰翳。", "塊然守蓬蒿，何以破昏滯。", "肩輿卒輩乏，徒步腳力費。", "出門即林丘，散策空夢寐。", "賸爲猶子憐，遽以此君至。", "分明人面目，刻畫老根柢。", "毛君又一奇，枝幹不少異。", "想應開一束，妙簡得三四。", "今晨入吾手，夷險可歷試。", "芒鞋與周旋，白拂相嫵媚。", "人生七十稀，況復已過二。", "多謝汝扶持，無乃太晚計。"]'),
('6d9b0c40-fd2d-4844-a7ea-8f8023af70ad','方時敏作寄茶詩允迪趙承之爭論鋒起有以詩棋取決之意二者僕皆不能姑次韻','曾幾','宋','宋诗','song-poetry','','[]','叢林一轉語，矛盾生諸方。',168,'全唐诗/poet.song.94000.json','["叢林一轉語，矛盾生諸方。", "不知維摩詰，衆論付括囊。", "君家富月團，入眼驚未嘗。", "勸君勿浪出，中有雙龍藏。", "一朝不自秘，詞鋒起堂皇。", "詩棋競攻取，信美非吾鄉。", "吾鄉亦何有，黍麥紛低昂。", "作詩天所戒，但欲身稍昌。", "奕棋正如詩，坐看星垂芒。", "怪君真不廉，顧我俱無長。", "天寒袖手垂，未厭舌本強。", "懸知決戰時，兩陣爭堂堂。", "詩壇與棋兵，傷殺亦大當。", "歸去竟何得，驚雷轉空腸。"]'),
('1bad65d5-c993-4ae9-bdd8-041c0292d225','即事','曾幾','宋','宋诗','song-poetry','','[]','朝隨粥魚作，夕與棲鳥眠。',72,'全唐诗/poet.song.94000.json','["朝隨粥魚作，夕與棲鳥眠。", "中間復何事，野飯炊山田。", "摩腹步脩廡，披襟坐南軒。", "薫爐鬰佳氣，茶鼎浮輕烟。", "閑開竹窗帙，靜憩蒲團禪。", "庶幾永白日，亦用銷殘年。"]'),
('ff78324a-fbd5-4883-8f43-6ba0230dfafb','東軒小室即事五首  其一','曾幾','宋','宋诗','song-poetry','','[]','卷書坐東軒，有竹甚魁偉。',48,'全唐诗/poet.song.94000.json','["卷書坐東軒，有竹甚魁偉。", "清風過其間，戛戛鳴不已。", "寫之以素琴，音節淡如水。", "不惜爲人彈，臨流須洗耳。"]'),
('524cb6d8-5e77-4a0e-a67f-012836802d24','東軒小室即事五首  其二','曾幾','宋','宋诗','song-poetry','','[]','鼠跡印塵几，蝸涎篆書帷。',48,'全唐诗/poet.song.94000.json','["鼠跡印塵几，蝸涎篆書帷。", "兒童勿除去，佳處正在茲。", "人言有何好，此段真成癡。", "俗子徒敗意，幽懷定誰知。"]'),
('c388caf7-829b-4250-8f06-a207fe0a4369','東軒小室即事五首  其三','曾幾','宋','宋诗','song-poetry','','[]','去聖未云遠，故在黄卷中。',48,'全唐诗/poet.song.94000.json','["去聖未云遠，故在黄卷中。", "孰能領其要，直用一理通。", "森羅廢興事，瑩若磨青銅。", "使我見萬古，敬謝典午公。"]'),
('8b006735-4c3f-495e-aa9f-b1694498cedb','東軒小室即事五首  其四','曾幾','宋','宋诗','song-poetry','','[]','烹茗破睡境，炷香玩詩編。',48,'全唐诗/poet.song.94000.json','["烹茗破睡境，炷香玩詩編。", "問詩誰所作，其人久沈泉。", "工部百世祖，涪翁一燈傳。", "閑無用心處，參此如參禪。"]'),
('f844bbf1-c35d-47ad-81e3-90d7a0ccbc7f','東軒小室即事五首  其五','曾幾','宋','宋诗','song-poetry','','[]','有客過丈室，呼兒具爐薫。',48,'全唐诗/poet.song.94000.json','["有客過丈室，呼兒具爐薫。", "清談似微馥，妙處渠應聞。", "沈水已成燼，博山尚停雲。", "斯須客辭去，趺坐對餘芬。"]'),
('1bd6f7ef-8bd9-405d-9000-c950b78172b8','盛夏東軒偶成五首  其一','曾幾','宋','宋诗','song-poetry','','[]','一堂既虛閑，一室可息偃。',48,'全唐诗/poet.song.94000.json','["一堂既虛閑，一室可息偃。", "松篁度風清，窗戶去日遠。", "幽禪過亭午，凉氣生薄晚。", "閫內即妻孥，更深遂忘返。"]'),
('67066a89-d866-4867-9dd3-e5e4a5bc0a4c','盛夏東軒偶成五首  其二','曾幾','宋','宋诗','song-poetry','','[]','攜簟入深竹，脱巾挂低枝。',48,'全唐诗/poet.song.94000.json','["攜簟入深竹，脱巾挂低枝。", "無令兒輩覺，更恐俗客知。", "清風何故來，口詠淵明詩。", "凉冷似太過，還從徑中歸。"]'),
('a54e9f39-0b59-416d-928b-4830176b68de','盛夏東軒偶成五首  其三','曾幾','宋','宋诗','song-poetry','','[]','松風夏逾清，竹日午更凈。',48,'全唐诗/poet.song.94000.json','["松風夏逾清，竹日午更凈。", "蕭然松竹間，得此林壑性。", "異哉今日暑，無復有晨暝。", "疲薾安所逃，茅齋入僧定。"]'),
('2691f156-6fd5-42d1-9e0c-5f45f3cc1ab5','盛夏東軒偶成五首  其四','曾幾','宋','宋诗','song-poetry','','[]','因病不舉酒，況當朱明天。',48,'全唐诗/poet.song.94000.json','["因病不舉酒，況當朱明天。", "客至但茗椀，談詩復談禪。", "甘寒百尺井，舊日陸子泉。", "安得僧舍雪，霏微濕茶烟。"]'),
('9aefb57b-e622-457a-97d2-ac3a7e270761','盛夏東軒偶成五首  其五','曾幾','宋','宋诗','song-poetry','','[]','澗蒲上九節，不受塵土姿。',48,'全唐诗/poet.song.94000.json','["澗蒲上九節，不受塵土姿。", "清泉自澡潔，白石相因依。", "種蕉水中央，佳處略似之。", "誰能後彫賞，惟有歲寒知。"]'),
('5f5ea698-d851-4ce6-95e1-4884d97798f1','友直軒','曾幾','宋','宋诗','song-poetry','','[]','友義喪來久，琢磨復誰能。',144,'全唐诗/poet.song.94000.json','["友義喪來久，琢磨復誰能。", "金鉤被采錄，絕棄朱絲繩。", "直哉少稷甫，一室清于冰。", "危坐對書帙，曲几非所凭。", "日暮無人來，疏籬上寒藤。", "惟有手種竹，挺然得其朋。", "風低與雪重，搶地如弗勝。", "政使可斷折，天姿諒難凌。", "物或亂真贗，君其别淄澠。", "攘羊而證父，是子烏足稱。", "所以貴温潤，不令見觚稜。", "要我細商略，此言有師承。"]'),
('38d0b366-ab8b-420d-882f-c8e6a13f7a10','松風亭四首  其一','曾幾','宋','宋诗','song-poetry','','[]','長卿壁四立，杜老茅三重。',48,'全唐诗/poet.song.94000.json','["長卿壁四立，杜老茅三重。", "茶山窮次骨，憩寂以長松。", "直幹以棟宇，清陰自帡幪。", "山泉落高處，審聽是松風。"]'),
('0e2b3dbf-3918-4625-8c89-59b3fe7cf7c3','松風亭四首  其二','曾幾','宋','宋诗','song-poetry','','[]','客至引幽步，步及松風亭。',48,'全唐诗/poet.song.94000.json','["客至引幽步，步及松風亭。", "問亭何當作，笑視何足聽。", "俗論鬨蛙黽，市聲殷雷霆。", "時來一洗耳，兩眼爲君青。"]'),
('56bbc934-b212-4944-b7c7-db19cd955888','松風亭四首  其三','曾幾','宋','宋诗','song-poetry','','[]','有客過茅宇，煮茶坐松風。',48,'全唐诗/poet.song.94000.json','["有客過茅宇，煮茶坐松風。", "問亭果安在，笑指十八公。", "君看梁與棟，豈不深且雄。", "何必用斤斧，然後成帡幪。"]'),
('d8ae9bb9-0cc5-4ba8-9ade-c99ede30a622','松風亭四首  其四','曾幾','宋','宋诗','song-poetry','','[]','回環數株松，老幹極落落。',48,'全唐诗/poet.song.94000.json','["回環數株松，老幹極落落。", "清風一披拂，竽籟自然作。", "喧囂世俗事，秖使人意惡。", "誰能洗耳來，相與憩寂寞。"]'),
('229acc74-9bb7-4ab8-8715-5664b6e6ec9d','清樾軒','曾幾','宋','宋诗','song-poetry','','[]','開軒在獨園，繞屋得清樾。',96,'全唐诗/poet.song.94000.json','["開軒在獨園，繞屋得清樾。", "不知何年樹，殆爲今日設。", "窗扉落林影，時復亂風月。", "喧聲了不聞，幽哢極可悦。", "玉溪僧所廬，無似許明潔。", "頗疑三昧手，斷取從二浙。", "禪房花木深，此語信佳絕。", "何以落其成，爐薰薦茗雪。"]'),
('21426151-7639-4b13-bc68-3a2fa573ce34','山房','曾幾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','竹樹轉深徑，茶山給孤園。',144,'全唐诗/poet.song.94000.json','["竹樹轉深徑，茶山給孤園。", "禪流打包去，舊日單寮存。", "堂堂十八公，不知幾寒温。", "其誰晤對汝，冷落依頽垣。", "有客占作室，此公正當軒。", "風聲落天半，似與幽人言。", "已矣復焉往，佳哉略無喧。", "在昔公擇父，實惟謫仙孫。", "讀書廬山中，仰視五老尊。", "頭白不歸來，高議排金門。", "吾敢效前輩，分應守丘樊。", "何憂蕙帳缺，悵望鶴與猿。"]'),
('9f4142d1-f2d5-4556-afb1-1a94089d1038','香寂圃','曾幾','宋','宋诗','song-poetry','','[]','陂陀茶山西，草樹無空空。',120,'全唐诗/poet.song.94000.json','["陂陀茶山西，草樹無空空。", "呼兒鋤其荒，花木亂栽種。", "葩華以時折，薌澤得風送。", "真成摩詰病，幻出天女供。", "游人等蜂蜨，晴日競喧哄。", "靈堅不自持，玉隴紛一鬨。", "誰知根塵間，境界極空洞。", "誠能返其流，當見寂不動。", "花飛已無蹤，香過忽如夢。", "于焉自聞聞，爾乃得大用。"]'),
('fee79c26-0e1a-4baa-887a-b46208c87260','横碧軒','曾幾','宋','宋诗','song-poetry','','[]','道山心已灰，但有愛山癖。',96,'全唐诗/poet.song.94000.json','["道山心已灰，但有愛山癖。", "移家過溪住，政爲數峰碧。", "空濛梅子雨，了不見顔色。", "朝來忽獻狀，欣若對佳客。", "晴窗卷書坐，葱翠長在側。", "似爲神所憐，持用慰岑寂。", "會登此山頭，卻望水南北。", "煙樹有無間，吾廬應可識。"]'),
('65237756-8528-4353-b0b5-c675266b3ca0','詠南池','曾幾','宋','宋诗','song-poetry','','[]','衡門久棲遲，永日孰與儔。',72,'全唐诗/poet.song.94000.json','["衡門久棲遲，永日孰與儔。", "既絕車馬喧，遂適林塘幽。", "荷香因雨來，水鳥鳴相酬。", "虛懷睨物表，可以觀天遊。", "古來英雄人，何異貉一丘。", "茫然不知歸，沒世隨波流。"]'),
('9e3f0397-c936-48ab-af5e-b892b5856bd5','遊靈川縣水洞','曾幾','宋','宋诗','song-poetry','','[]','清溪東南馳，礙此碧玉峰。',132,'全唐诗/poet.song.94000.json','["清溪東南馳，礙此碧玉峰。", "蛟龍夜相宅，奮迅生雷風。", "剨開兩貝闕，鑿翠成珠宮。", "坐令空洞處，一水油然通。", "泉流百道來，投注萬斛鍾。", "不知深幾許，湛若鎔青銅。", "定應天下稀，豈但湘南雄。", "嘉與二三子，葉舟渺相從。", "周旋乳蓋底，蕩漾菱花中。", "爲我告行客，無爲苦匆匆。", "小酌清泠淵，洗汝塵坌胸。"]'),
('909d553d-ea68-4441-9fd9-f0bf2f0f747c','漵浦縣鄧夢授主簿惜日軒','曾幾','宋','宋诗','song-poetry','','[]','羲和鞭白駒，秋日淒已短。',120,'全唐诗/poet.song.94000.json','["羲和鞭白駒，秋日淒已短。", "向來曬書地，欲作炙背暖。", "鄧侯開西軒，棗下歌纂纂。", "前山隱半規，悵望支手版。", "我慵類天賦，身世兩不管。", "著鞭慚祖生，運甓謝陶侃。", "銅壺一百刻，夜夢分去半。", "午窗又爲祟，長閉讀書眼。", "勉旃崇明德，已事不可緩。", "作詩非爲君，實自警疏嬾。"]'),
('a3fb7455-2b76-4e90-8934-824af194cf47','漵浦柟木洞蓋神龍所居今年夏大旱縣官乞取其水以禱立應民猶以爲未足因作是詩以遺諸公致再請之意焉','曾幾','宋','宋诗','song-poetry','','[]','傾心南山雲，如渴望梅嶺。',192,'全唐诗/poet.song.94000.json','["傾心南山雲，如渴望梅嶺。", "朝來有佳思，拄笏不見頂。", "豐隆駿奔走，列缺元馳騁。", "雨不到人間，風伯乃爲梗。", "生來食官倉，四海無二頃。", "歌詩視天漢，一念極耿耿。", "階前甃清泉，洮頮冰雪冷。", "乾喉欲生煙，空下百尺綆。", "幽軒竹三四，柯葉殊秀整。", "邇來頭搶地，但懼不得永。", "以斯占稻粱，生意魚在鼎。", "潛虯民司命，膏澤浸茲境。", "邑官樹嘉政，責報甚形影。", "缾罌走十里，豈憚一再請。", "君其潔齋俟，百穀正延頸。", "客子無遠謀，空腸望遺秉。"]'),
('4173b9af-48ad-49a2-b647-776b2800e46a','詠旱三首  其一','曾幾','宋','宋诗','song-poetry','','[]','驕陽方施行，秋節已樹立。',48,'全唐诗/poet.song.94000.json','["驕陽方施行，秋節已樹立。", "田苗在膏肓，何道可副急。", "雲雷不成雨，成雨初不濕。", "咄咄逼中秋，爲霖恐無及。"]'),
('9845905a-3fe3-4b02-aa2a-f0cfeabdaf03','詠旱三首  其二','曾幾','宋','宋诗','song-poetry','','[]','邦人奉教條，久不知肉味。',48,'全唐诗/poet.song.94000.json','["邦人奉教條，久不知肉味。", "潭龍不能神，土偶安足恃。", "應真住蘭若，雲雨可立致。", "胡不迎之來，明明有前事。"]'),
('e1f6d168-b60c-462a-935d-43307a862ab5','詠旱三首  其三','曾幾','宋','宋诗','song-poetry','','[]','春雨接梅雨，便有水潦憂。',48,'全唐诗/poet.song.94000.json','["春雨接梅雨，便有水潦憂。", "乞晴今幾日，又以憫雨求。", "田苗雖向槁，尚冀什一收。", "政恐穫稻月，沛淫不能休。"]'),
('0ed15052-a0db-47a5-9661-4c1b070db6b8','六月十四日大雨連朝','曾幾','宋','宋诗','song-poetry','','[]','黄金北斗高，何似六月雨。',120,'全唐诗/poet.song.94000.json','["黄金北斗高，何似六月雨。", "舉頭看雲霄，此祕初未覩。", "今晨沛然下，其勢莫能禦。", "既蠲人鬰陶，又長我禾黍。", "誰言爲郡樂，病不對樽俎。", "似爲神所憐，用是娛悦汝。", "緇黄諠諷誦，巫覡亂呼舞。", "惠然從風來，茲事一不舉。", "臨民多秕政，何道致如許。", "稽首謝皇天，傾心奉明主。"]'),
('a3499f0a-156d-49eb-a2b2-343d7d33c664','七月一日復大雨用前韻','曾幾','宋','宋诗','song-poetry','','[]','山頭一寸雲，山下一尺雨。',120,'全唐诗/poet.song.94000.json','["山頭一寸雲，山下一尺雨。", "青天在層陰，未用遽披覩。", "懸知壠畝間，不著蓑笠禦。", "呼兒趣秧稻，喚婦催釀黍。", "使君同戚休，有味勝鼎俎。", "似聞小人言，無復怨詈汝。", "行看黄雲翻，不獨翠浪舞。", "飭廚辦千觴，飲客醉一舉。", "不知城東湖，今復深幾許。", "鷗鷺莫相疑，龜魚且爲主。"]'),
('ebd0fc7a-6f66-4f91-a894-a65439d91b1c','夏雨應祈呈桂帥二首  其一','曾幾','宋','宋诗','song-poetry','','[]','山椒雲氣佳，林表雨聲急。',48,'全唐诗/poet.song.94000.json','["山椒雲氣佳，林表雨聲急。", "元戎郊坰去，歸騎旌旆濕。", "老夫不能陪，凉傍竹窗入。", "兒報夕陽明，環城碧簪立。"]'),
('db69214f-8d48-47c3-847d-b5c39c1af685','夏雨應祈呈桂帥二首  其二','曾幾','宋','宋诗','song-poetry','','[]','窗前有梧桐，報我以好雨。',48,'全唐诗/poet.song.94000.json','["窗前有梧桐，報我以好雨。", "不眠聽疏滴，佳事想農圃。", "苗根不須問，蔬甲已如許。", "小簟六尺牀，蕭然睡亭午。"]'),
('ce52ddcd-dc1d-4159-a42f-2af9a3e19214','寒雨浹旬終不成雪','曾幾','宋','宋诗','song-poetry','','[]','幽棲又三冬，好雪無一片。',120,'全唐诗/poet.song.94000.json','["幽棲又三冬，好雪無一片。", "今晨靄同雲，薄暮集微霰。", "先聲乃如許，落勢大可見。", "呼兒出門看，通夕知幾徧。", "聽窗復聽竹，攲枕不知倦。", "終然成底事，寒雨閉深院。", "何嘗憂瘠田，初不辦歡醼。", "囊螢已乾死，無以映書卷。", "請天收層陰，斗柄行欲轉。", "愛日上晴軒，如披故人面。"]'),
('f9be2aa3-a9ab-472f-a1b3-a16132e7cf93','喜晴','曾幾','宋','宋诗','song-poetry','','[]','求晴而得晴，老子不勝喜。',168,'全唐诗/poet.song.94000.json','["求晴而得晴，老子不勝喜。", "夜聞屋瓦聲，如疾痛在已。", "通宵遂無寐，落勢殊未已。", "禾頭臥沙泥，便恐欲生耳。", "謂天爲不仁，春夏雨如彼。", "即今孰主張，秋潦更如此。", "垂成又敗之，天意定不爾。", "果如吾所料，林杪風忽起。", "玄雲走四山，白日行萬里。", "腰鐮知幾家，持杵者誰子。", "歡聲田野閑，樂事圖畫裏。", "使君經旬憂，杯酒爲一洗。", "官倉不須問，百室既盈止。", "作詩告同僚，可以賀我矣。"]'),
('e0775219-f46a-452a-b2d8-5e661e5b91ea','初至天台','曾幾','宋','宋诗','song-poetry','','[]','疇昔所欣慕，天台冠坤靈。',180,'全唐诗/poet.song.94000.json','["疇昔所欣慕，天台冠坤靈。", "興公妙摹寫，粲若披圖經。", "自憐嬰世網，仰愧鴻冥冥。", "夙契諒非淺，半生吏金庭。", "成此一段奇，得按東吳刑。", "又分臨海竹，想像山圍屏。", "稍稍向鈴閣，行行叩禪扃。", "一丘與一壑，所見皆所聆。", "石梁臥劍戟，布水驅雷霆。", "五百大開士，神光秘林坰。", "于我定不薄，是事初無形。", "寒嵒二隱者，在眼誰能青。", "庶幾閭丘守，胸次明渭涇。", "向來石磵耳，鬭訟終朝聽。", "凈洗塵俗狀，數上參雲亭。"]'),
('968e4f35-23ee-45a1-924f-da353d9b58aa','聞東湖荷花盛開未嘗一游寄鄭禹功','曾幾','宋','宋诗','song-poetry','','[]','言登巾子山，天外入眼界。',180,'全唐诗/poet.song.94000.json','["言登巾子山，天外入眼界。", "呀然城之東，一鑑如許大。", "得非所領州，其下臨渤澥。", "乃知湖浸闊，便覺井邑隘。", "朝朝横烏紗，暮暮束韋带。", "何曾官事了，秖使人意敗。", "徑須水清泠，一洗胸芥蔕。", "昨來放船好，如更宅爽塏。", "四圍純浸山，碧玉亂石黛。", "兼隨鄭廣文，人境兩疏快。", "維揚幾同僚，獨喜此翁在。", "只今萬紅妝，一一倚青蓋。", "柳陰閑畫舫，荷葉遶公廨。", "鬢絲禪榻上，句法出蔬菜。", "因之雙鯉魚，慎勿欠詩債。"]'),
('76a1408b-ae58-483b-a34d-3c862cc29105','春晴','曾幾','宋','宋诗','song-poetry','','[]','青春挽留渠不住，白髮抛去吾安能。',64,'全唐诗/poet.song.94000.json','["青春挽留渠不住，白髮抛去吾安能。", "東風送汝一杯酒，從此閉戶真同僧。", "酴醿芍藥待判斷，腰鼓横笛當施行。", "奈何但效鵓鳩輩，竟日討論陰與晴。"]'),
('ebbdb67d-d288-4dfe-934d-200a0b438aee','王元渤自湖楚歸贈之','曾幾','宋','宋诗','song-poetry','','[]','南池荷葉疊青錢，玉山門外君著鞭。',160,'全唐诗/poet.song.94000.json','["南池荷葉疊青錢，玉山門外君著鞭。", "南池荷葉成青繖，問君東遊何當返。", "聞道湖州又楚州，舊隱故鄉宜款款。", "清晨剝啄叩我門，我不出門非是嬾。", "不知何物苦相干，能令人熱令人寒。", "偶然脱命冰炭裏，至今體不勝衣冠。", "溪流落盡才如带，想見南池空聚塊。", "更無小鴨睡枯荷，況有紅妝依翠蓋。", "眼看物變惜年光，明月黄花盍舉觴。", "知有中秋恐無分，須君滿意作重陽。"]'),
('d8eebc05-9e83-4151-b3eb-bd83f7c55338','贈閻德夫參議','曾幾','宋','宋诗','song-poetry','','[]','閻公才氣人無敵，列星官曹聲藉藉。',224,'全唐诗/poet.song.94000.json','["閻公才氣人無敵，列星官曹聲藉藉。", "青雲垂上卻回頭，笑說鄉邦富泉石。", "問君功業男兒事，禹重寸陰輕尺璧。", "及身強健不勉旃，汲汲東臯恐非策。", "答云種木須十年，種得成陰已頭白。", "是以江濱五畝園，拄杖芒鞋日經畫。", "即今臺榭數十處，花竹誰能計千百。", "是中便足了一生，頗覺軒裳總無益。", "我聞此語爲驚歎，耆境之間真迫窄。", "元無三徑可就荒，乃知貧過陶彭澤。", "想君舒嘯東臯上，不但淵明心莫逆。", "神交又得王無功，一飯何嘗留俗客。", "未妨獻納雲臺表，著繡晝行尋履跡。", "會當稱是好林塘，門對諸峰一區宅。"]'),
('1940b41d-4432-490f-ac09-d23a307c97fe','次鄭侍郎臥聞秋風韻','曾幾','宋','宋诗','song-poetry','','[]','茶山石燥泉亦枯，草樹疊疊成樵蘇。',64,'全唐诗/poet.song.94000.json','["茶山石燥泉亦枯，草樹疊疊成樵蘇。", "天公風雷起揮袂，咳唾急雨紛跳珠。", "我詩曾未管窺豹，況有文采如於菟。", "勤公見索掃地無，公自瑤碧瑲華琚。"]'),
('71bd2ed9-c377-45d9-9d3f-6f366e721b78','再次蘇字韻','曾幾','宋','宋诗','song-poetry','','[]','秋風不來眼穿枯，颯然而至吾其蘇。',64,'全唐诗/poet.song.94000.json','["秋風不來眼穿枯，颯然而至吾其蘇。", "中宵起我燈火讀，音節自喜如連珠。", "不知何物披拂此，定是嘯谷之於菟。", "窗前況復雨驟作，山溜遶屋鳴瑤琚。"]'),
('d1a00b6b-f981-4666-b0f5-e5fba8fbeb96','三次蘇字韻','曾幾','宋','宋诗','song-poetry','','[]','陶詩雖瘠元非枯，確論近出眉山蘇。',64,'全唐诗/poet.song.94000.json','["陶詩雖瘠元非枯，確論近出眉山蘇。", "君詩不贈世作者，以暗投我如投珠。", "鄙人摹寫不成就，妄指畫狗爲於菟。", "安得才似柳刺史，好辭玉珮鳴瓊琚。"]'),
('93815297-5688-473a-be46-4a2a3bc36480','次程伯禹尚書見寄韻','曾幾','宋','宋诗','song-poetry','','[]','往年書到西風凉，病夫隨牒天一方。',192,'全唐诗/poet.song.94000.json','["往年書到西風凉，病夫隨牒天一方。", "今年書到玉溪上，曖空白露爲清霜。", "人生俯仰成陳迹，只有一丘如宿昔。", "故鄉傑閣公飽山，野寺幽軒我横碧。", "石交曉月長庚星，勢交飛絮水上萍。", "往時玉溪二三老，死生貴賤論交情。", "歸來訪舊其誰羨，程公筆力猶強健。", "鄭公霜鬢未成絲，掛冠不受兒曹勸。", "公于道德猶耕獵，所得不隨天下裂。", "胸中具眼世莫知，筆端有口公能說。", "豹文未省一斑窺，戲逐群兒日課詩。", "詩病無人與商略，湔腸浣胃付神醫。"]'),
('351f9d64-3932-49a5-8c4c-bc5f2ae4eb8a','次僧道規蜜蜂去而復集韻','曾幾','宋','宋诗','song-poetry','','[]','公如老殊所嗜蜜，種花山中引蜂入。',64,'全唐诗/poet.song.94000.json','["公如老殊所嗜蜜，種花山中引蜂入。", "千門萬戶芙蕖房，爲公謀食如風狂。", "朝來蜂臣不趨衙，一心祝蜂早歸家。", "歸來喜舞擊銅鉢，與人從今莫胡越。"]'),
('96dd8de9-cd42-464f-adb6-78a6a8ad3412','吳傅朋出遊絲書求詩','曾幾','宋','宋诗','song-poetry','','[]','使君官事閑時書，略取萬象隨指呼。',128,'全唐诗/poet.song.94000.json','["使君官事閑時書，略取萬象隨指呼。", "空中遊絲定何物，非蠶所吐仍非蛛。", "光風霽日青春暮，惹草縈花細于縷。", "君今幻出一毫端，此秘從來人未覩。", "鈴齋觀者客如雲，有無斷續吁難分。", "不知誰束此毛穎，能使字畫纖無倫。", "嘗聞掃堊生雪白，顛草親承擔夫力。", "世間妙處不可傳，心手應時須自得。"]'),
('7d2d3ddf-2791-4800-b0fd-def56b275c8d','和劉聖俞顧龍山約客韻','曾幾','宋','宋诗','song-poetry','','[]','詩筒四出走中涓，詩句萬選如青錢。',112,'全唐诗/poet.song.94000.json','["詩筒四出走中涓，詩句萬選如青錢。", "曰余借舟期七賢，共嗅梅花咀芳鮮。", "津頭幾度喚長年，晝眠乃若經笥邊。", "舉頭急雪風中旋，瞪視不見山之巓。", "八窗玲瓏繡佛前，同來且結西方緣。", "小軒宛若壺中天，玉琴不斷雨聲傳。", "諾君再宿余敢愆，從君索句發春妍。"]'),
('60e75ea3-13c4-4b6d-9324-daf8928b5b61','肇慶守鄭子禮以李北海石室碑見寄輒次山谷老人韻爲謝','曾幾','宋','宋诗','song-poetry','','[]','吾評古法書，固自有高下。',60,'全唐诗/poet.song.94000.json','["吾評古法書，固自有高下。", "端州遺我石室碑，一字千金恐非價。", "莫邪之劍難爭鋒，李公落筆神氣同。", "詩鳴一代屬山谷，草根亦復吟秋蟲。"]'),
('01368488-0ea2-445f-a569-229c068e9a68','黄嗣深尚書自臨川省其兄嗣文戶部于宜春用元明魯直唱題李生墨竹梅','曾幾','宋','宋诗','song-poetry','','[]','紛紛畫手調紅綠，好以桃花配叢竹。',96,'全唐诗/poet.song.94000.json','["紛紛畫手調紅綠，好以桃花配叢竹。", "豈無短紙作江梅，雪裏溪邊太幽獨。", "李侯胸中有佳處，研滴松煤聊寓目。", "與梅擇對無可人，分付此君真不俗。", "淡煙小雨空濛地，何得月明疏影足。", "始知璀璨出斜枝，詩畫古來真一族。"]'),
('f5f90daa-6f99-4d23-986a-4eb592f427cf','探梅','曾幾','宋','宋诗','song-poetry','','[]','幅巾芒鞋笻竹策，踏遍山南與山北。',64,'全唐诗/poet.song.94000.json','["幅巾芒鞋笻竹策，踏遍山南與山北。", "雪含欲下不下意，梅带將開未開色。", "遶樹三匝且復去，前村一枝應可摘。", "丁寧說似水邊人，從今日報花消息。"]'),
('3025a375-af5f-4386-bb61-5e7b4bd8cf44','許公華遺潘衡墨云其女所造也','曾幾','宋','宋诗','song-poetry','','[]','潘公之墨東坡訣，只今有女能傳業。',128,'全唐诗/poet.song.94000.json','["潘公之墨東坡訣，只今有女能傳業。", "許郎來自大江西，手探玄圭出箱篋。", "摩挲熟視家風在，款識明明筆奇絕。", "見渠顔面得渠心，湛如瞳子堅如鐵。", "晴窗大几石泓凈，未忍磨研令小缺。", "冷金玉版姑試之，一點清光初漏泄。", "廷珪去人端未遠，餘子何勞定優劣。", "健婦果勝大丈夫，從此廬陵是黟歙。"]'),
('f33208f8-fe9d-4ffe-b449-8a5ad9fbbc40','謝胡帥餉酥','曾幾','宋','宋诗','song-poetry','','[]','虎頭骨相生來無，談天吻燥齋腸枯。',64,'全唐诗/poet.song.94000.json','["虎頭骨相生來無，談天吻燥齋腸枯。", "欲從底處覓膏潤，凝香燕寢烹牛酥。", "鵝兒黄拂冰肌膚，關中穰下遠不如。", "已令炊餅作十字，今晨盛饌非伊蒲。"]'),
('cad8bac1-8d7d-4a78-bd98-aa806ca6bef8','謝柳全叔縣丞寄高麗松花','曾幾','宋','宋诗','song-poetry','','[]','幽人所住空山裏，老松皆作虯龍起。',64,'全唐诗/poet.song.94000.json','["幽人所住空山裏，老松皆作虯龍起。", "但知樹底聽松風，不見風前落松子。", "三韓華萼手自開，其間瑣碎如嬰孩。", "請因賈客詔君長，二十餘年無使來。"]'),
('761d8299-aaf1-49aa-98dc-0fcf0e41f92a','㔶甕酒','曾幾','宋','宋诗','song-poetry','','[]','吳儂餅麴成村酒，所取何嘗議升斗。',160,'全唐诗/poet.song.94000.json','["吳儂餅麴成村酒，所取何嘗議升斗。", "一杯未盡朱顔酡，過若茅柴那得久。", "官酤私釀同一律，竟識吾家新醖否。", "近持方法報山妻，入眼從來未曾有。", "舊時菽麥真其父，秫稻麥和以爲母。", "甕頭又戴老瓦盆，墐塞四旁如戶牖。", "數朝已辦糟牀注，不論清濁皆可口。", "欣然一笑謂山妻，慎勿輕傳殆天授。", "答云妙處須心得，縱有此方無此手。", "請君痛飲當解酲，賢哉大勝劉伶婦。"]'),
('daedbe90-5bef-47be-af4e-8ec9debef72b','蓮榭','曾幾','宋','宋诗','song-poetry','','[]','郎官一星幾時落，乃在水遶山圍間。',96,'全唐诗/poet.song.94000.json','["郎官一星幾時落，乃在水遶山圍間。", "幽亭野彴不知數，青鞋庾菜何由閑。", "眼前突兀見蓮榭，秋水泠然沼其下。", "凌波仙子襪生塵，露冷風凄微月夜。", "願公清凈如遠公，吾欲投合保社中。", "冰雪肌膚攲翠蓋，看花心似太虛空。"]'),
('50ec70e0-807b-4d8c-ac34-2734de2cbb9d','遊張公洞','曾幾','宋','宋诗','song-poetry','','[]','張公洞府未著腳，向人浪說游荆溪。',64,'全唐诗/poet.song.94000.json','["張公洞府未著腳，向人浪說游荆溪。", "欲看直上翠羽蓋，不惜扶下青雲梯。", "勁風翻動土囊口，暗水流出桃花蹊。", "卻將深處問兒輩，一夕飛夢窮攀躋。"]'),
('a73c6259-5786-4fb5-9b15-6d8dfb4c0e38','禽聲','曾幾','宋','宋诗','song-poetry','','[]','不如歸去東皋上，美酒提壺迎婦餉。',64,'全唐诗/poet.song.94000.json','["不如歸去東皋上，美酒提壺迎婦餉。", "何妨脱袴著新衣，百箔蠶絲繭如盎。", "春泥滑滑未沒腰，田間布穀初立苗。", "牧兒喜舞麥熟也，報答爾曹婆餅焦。"]'),
('681cf54a-1ad0-40a8-83ce-9f7b6a7e8603','荷池','曾幾','宋','宋诗','song-poetry','','[]','名園中有十頃池，一錢不用君得之。',64,'全唐诗/poet.song.94000.json','["名園中有十頃池，一錢不用君得之。", "菱荷枯折小鴨睡，絕勝紅妝青蓋時。", "蛙鳴莫作鼓吹想，亦莫問屬官與私。", "讀書之暇招客飲，能有此樂非公誰。"]'),
('c2b4031c-dba2-4938-9c0c-814a61748899','次折仲古游潯州桂園韻','曾幾','宋','宋诗','song-poetry','','[]','雞犬圖書同一舸，老夫蕩槳兒扶柂。',160,'全唐诗/poet.song.94000.json','["雞犬圖書同一舸，老夫蕩槳兒扶柂。", "潯江一繫欲生根，夢下湖南向江左。", "極知越俗留連客，性不相投如水火。", "是誰招喚寫羈愁，拄頰西山雲數朵。", "雲山下有園五畝，不植側生旁挺果。", "十年藝桂待芳辛，歲晚風霜深印可。", "有懷澤畔入騷辭，配以蘭椒真類我。", "斧斤竟不赦孤根，問主林神安所坐。", "乃知有用禍先集，社櫟之徒最繁夥。", "徑須澆下磈磊胸，乞取青錢供白墮。"]'),
('8926652c-a407-4c4e-b173-6ffd28dcc609','爲張四明作','曾幾','宋','宋诗','song-poetry','','[]','一生所聞張仲蔚，閉門蓬蒿深幾尺。',64,'全唐诗/poet.song.94000.json','["一生所聞張仲蔚，閉門蓬蒿深幾尺。", "邇来伐竹聲丁丁，手披榛叢待三益。", "徑中踏破蒼苔色，定是幽人芒屨跡。", "莫將車邊兩輪赤，奪此千竿一池碧。"]'),
('1d8c3fa0-8730-4aff-811b-3c7c0956c82e','馮縣丞墨花','曾幾','宋','宋诗','song-poetry','','[]','君持松煤與研滴，慘澹不言生百物。',64,'全唐诗/poet.song.94000.json','["君持松煤與研滴，慘澹不言生百物。", "胸中自無俗子韻，落筆乃有此氣骨。", "江梅正爾不施丹，爲我拂拭爲清寒。", "一枝早晚到窗几，定作月影横斜看。"]'),
('457c896c-286d-429e-b949-1b2b8ee54e3a','錢生遺笻竹斑杖戲作','曾幾','宋','宋诗','song-poetry','','[]','笻山美竹天下聞，有客錢氏之礽雲。',64,'全唐诗/poet.song.94000.json','["笻山美竹天下聞，有客錢氏之礽雲。", "自言吾祖嫌杖晚，贈子九節斑爛文。", "尋幽已得濟勝具，傍險更策扶危勳。", "同行安用木上座，一日不可無此君。"]'),
('6766eb12-edda-43cc-9a64-df43a7724364','夏初示兒曹','曾幾','宋','宋诗','song-poetry','','[]','鳥聲四合陰扶疏，江湖散人拜賜初。',64,'全唐诗/poet.song.94000.json','["鳥聲四合陰扶疏，江湖散人拜賜初。", "此君之子才墮地，一一文采如於菟。", "相看又作故時面，乃是秋風篋中扇。", "寸陰尺璧定何如，付與爾曹分貴賤。"]'),
('58bb0850-4446-4211-865f-b0f792d7ef0f','玩鷗亭','曾幾','宋','宋诗','song-poetry','','[]','乃翁獨步辭雲間，五花判罷遊金鑾。',144,'全唐诗/poet.song.94000.json','["乃翁獨步辭雲間，五花判罷遊金鑾。", "甘泉頗勞侍從事，夜直必夢江湖寛。", "晚遭忌刻泛湘水，衆爲不樂公欣歡。", "白鷗無數沒浩蕩，相親相近俄相安。", "何曾一旦舞不下，始信前事盟未寒。", "文章炳蔚冠當代，衣被諸子猶班班。", "攜持扁牓向陽羨，往日風味追令還。", "乃翁閑散莫浪許，乃翁青紫當拾取。", "回施佳名與老夫，長共群鷗臥煙雨。"]'),
('f0059da7-39a4-446a-b08a-98f655eef4c5','獨青亭','曾幾','宋','宋诗','song-poetry','','[]','霜落水痕風落木，翠蓋倚天惟汝獨。',64,'全唐诗/poet.song.94000.json','["霜落水痕風落木，翠蓋倚天惟汝獨。", "是誰手種百年餘，蔭此空庭一株足。", "歲寒不但色青青，上有垂絲下茯苓。", "松根老僧應取此，制人頽齡起人死。"]'),
('6b027276-a250-48ef-9600-1c28d599c695','題壽樟亭','曾幾','宋','宋诗','song-poetry','','[]','大屋連甍小容足，棟宇以來非一木。',65,'全唐诗/poet.song.94000.json','["大屋連甍小容足，棟宇以來非一木。", "豫章不是十圍樗，受命于天何得獨。", "君莫厭老大蓬蒿間，應龍虹梁果非福。", "虛堂晝靜聞丁丁，溜雨枯皮在空谷。"]'),
('7097b6ed-e89a-45d2-bced-cba27e6040d9','蚊蠅擾甚戲作','曾幾','宋','宋诗','song-poetry','','[]','黑衣小兒雨打窗，斑衣小兒雷殷牀。',112,'全唐诗/poet.song.94000.json','["黑衣小兒雨打窗，斑衣小兒雷殷牀。", "良宵永晝作底用，只與二子更飛揚。", "開尊匕箸須一洗，破卷燈火尤相妨。", "從來所持白羽扇，自許百萬猶能當。", "安知手腕爲汝脱，以小喻大真成狂。", "揮之使去定無策，葛帳十幅眠空堂。", "朝喧暮鬨姑聽汝，坐待九月飛嚴霜。"]'),
('7c4f6f29-14e7-42b6-99c5-743c4a142d66','同鄭禹功登巾子山','曾幾','宋','宋诗','song-poetry','','[]','天台雁蕩天下奇，豈不欲往官縛之。',128,'全唐诗/poet.song.94000.json','["天台雁蕩天下奇，豈不欲往官縛之。", "巾山只在郡南郭，曾未著眼真成癡。", "今晨排遣簿書了，往赴鄭老同幽期。", "羊腸轉盡得蘭若，飛鳥不到雲雨垂。", "青銅鏡外翠屏遶，中有萬屋魚鱗差。", "古來二事不兼得，此地一覽俱無遺。", "蓬萊方丈果何許，雲駕飇馭知爲誰。", "赤城風月幸好戲，驅取鸞鳯相追隨。"]'),
('f6fa6340-0b76-49e8-95d0-fa6838de24d7','立春','曾幾','宋','宋诗','song-poetry','','[]','十載東都客，春盤種種春。',48,'全唐诗/poet.song.94000.json','["十載東都客，春盤種種春。", "翠看蔬甲小，黄愛韭苗新。", "流落成吾老，蕭疏對此辰。", "睦隣如有使，傳語大梁人。"]'),
('a0480322-9b48-4359-9c46-abf12ba0bec7','春日二首  其一','曾幾','宋','宋诗','song-poetry','','[]','今日知何日，東風破臘來。',48,'全唐诗/poet.song.94000.json','["今日知何日，東風破臘來。", "寒隨邊騎去，春與漢軍回。", "彩勝參差翦，蔬盤飣餖開。", "不妨時節好，年事豈禁催。"]'),
('706447a0-d539-4701-bdf3-80aee3d09ba6','春日二首  其二','曾幾','宋','宋诗','song-poetry','','[]','期頤三萬日，政爾亦無多。',48,'全唐诗/poet.song.94000.json','["期頤三萬日，政爾亦無多。", "佳節已如許，衰年將若何。", "雨風增落寞，戚友斷經過。", "問訊庖廚內，猶堪一洗磨。"]'),
('ed2b7d55-6a25-48f0-bdc0-d226d3007fdf','春日即事次韻','曾幾','宋','宋诗','song-poetry','','[]','穠李花如許，殊勝灼灼紅。',48,'全唐诗/poet.song.94000.json','["穠李花如許，殊勝灼灼紅。", "只言開似雪，不道去隨風。", "勝日從吾黨，衰年念此翁。", "詩情猶可強，杯勺不能同。"]'),
('54144b4d-4378-48b5-b522-bb296f822c5d','雨二首  其一','曾幾','宋','宋诗','song-poetry','','[]','秋冬久不雨，氣濁喜雲生。',48,'全唐诗/poet.song.94000.json','["秋冬久不雨，氣濁喜雲生。", "麥隴崇朝潤，茅檐徹夜聲。", "初來斷幽徑，漸密雜疏更。", "賴有牆陰薺，離離已可烹。"]'),
('b96fbb91-4ae9-4050-b8d8-fd0997c87783','雨二首  其二','曾幾','宋','宋诗','song-poetry','','[]','薄晚初霑洒，清晨更慘悽。',48,'全唐诗/poet.song.94000.json','["薄晚初霑洒，清晨更慘悽。", "魚寒拋餌去，鴉濕就簷棲。", "幽澗濺濺溜，長堤淺淺泥。", "一杯持自賀，吾事在鋤犁。"]'),
('aefaaf3c-e377-411f-bf4a-ac86acc6acff','夕雨','曾幾','宋','宋诗','song-poetry','','[]','屣履行莎徑，移牀臥草亭。',48,'全唐诗/poet.song.94000.json','["屣履行莎徑，移牀臥草亭。", "風聲雜溪瀨，雨氣挾龍腥。", "燁燁空中電，昏昏雲罅星。", "徂年又如許，吾鬢得長青。"]'),
('63d6148e-2f1b-4cb8-bef3-7c7d242bad66','雨夜','曾幾','宋','宋诗','song-poetry','','[]','一雨遂通夕，安眠失百憂。',48,'全唐诗/poet.song.94000.json','["一雨遂通夕，安眠失百憂。", "窗扉淡欲曉，枕簟冷生秋。", "畫燭爭棋道，金尊數酒籌。", "依然錦城夢，忘卻在南州。"]'),
('003eb383-8b2a-4414-baba-29a9ae771825','仲夏細雨','曾幾','宋','宋诗','song-poetry','','[]','霢霂無人見，芭蕉報客聞。',48,'全唐诗/poet.song.94000.json','["霢霂無人見，芭蕉報客聞。", "潤能添硯滴，細欲亂爐薫。", "竹樹驚秋半，衾裯愜夜分。", "何當一傾倒，趁取未歸雲。"]'),
('9cf1cbeb-4c58-4c9b-8a9b-c9d33b139429','憫雨','曾幾','宋','宋诗','song-poetry','','[]','梅子黄初徧，秧鍼綠未抽。',48,'全唐诗/poet.song.94000.json','["梅子黄初徧，秧鍼綠未抽。", "若無三日雨，那復一年秋。", "薄晚看天意，今宵破客愁。", "不眠聽竹樹，還有好音不。"]'),
('06f0f1f6-fe5c-4027-81ff-ca558df0d534','郡中迎懷玉山應真請雨得之未沾足','曾幾','宋','宋诗','song-poetry','','[]','憫雨連三月，爲霖抵萬金。',48,'全唐诗/poet.song.94000.json','["憫雨連三月，爲霖抵萬金。", "小垂開士手，足慰老農心。", "果欲千倉積，猶須一尺深。", "病夫渾不寢，危坐聽佳音。"]'),
('19532f67-4e69-4c21-bc18-904f00aa6e1e','蘇秀道中大雨','曾幾','宋','宋诗','song-poetry','','[]','梅雨又時雨，蘇州仍秀州。',48,'全唐诗/poet.song.94000.json','["梅雨又時雨，蘇州仍秀州。", "客行無六月，農事有三秋。", "雲氣深鴻雁，烟波沒白鷗。", "衰年慚愧汝，物役幾時休。"]'),
('d42beb1d-fb0e-4751-bce3-cb135dec800e','晚雨','曾幾','宋','宋诗','song-poetry','','[]','蕭瑟度横塘，霏微映繚牆。',48,'全唐诗/poet.song.94000.json','["蕭瑟度横塘，霏微映繚牆。", "壓低塵不動，洒急土生香。", "聲入楸梧碎，清分枕簟凉。", "回頭忽陳迹，簷角掛斜陽。"]'),
('c410ed93-b9a2-4b82-9126-da0b498c76d0','久雨','曾幾','宋','宋诗','song-poetry','','[]','荒院已無趣，愁霖終不開。',48,'全唐诗/poet.song.94000.json','["荒院已無趣，愁霖終不開。", "簷聲喧客語，屋漏逐人來。", "橋報今朝斷，牆聞昨夜摧。", "尚餘湯餅具，積潦未爲灾。"]'),
('e6e97cd4-ca9d-410b-8b9a-5a12c01e4d90','久雨有懷曾宏甫','曾幾','宋','宋诗','song-poetry','','[]','欲訪溪山老，無如此雨何。',48,'全唐诗/poet.song.94000.json','["欲訪溪山老，無如此雨何。", "一春判棄置，十日斷經過。", "燈火相看放，鶯花即漸多。", "晴暄如有意，數數上南坡。"]'),
('e57024cc-c4a4-47a6-a744-d19fcf0bbb57','苦雨','曾幾','宋','宋诗','song-poetry','','[]','儘道迎梅雨，能無一日晴。',48,'全唐诗/poet.song.94000.json','["儘道迎梅雨，能無一日晴。", "窗昏愁細字，簷暗亂疏更。", "未怪蛙爭席，真憂水冒城。", "何由收積潦，簫鼔賽西成。"]'),
('04bb7f84-d7fa-4ce0-b07a-7e53f0fa314f','大暑','曾幾','宋','宋诗','song-poetry','','[]','赤日幾時過，清風無處尋。',48,'全唐诗/poet.song.94000.json','["赤日幾時過，清風無處尋。", "經書聊枕籍，瓜李漫浮沈。", "蘭若靜復靜，茅茨深又深。", "炎蒸乃如許，那更惜分陰。"]'),
('d090ab55-9b20-4dac-b7a5-f378c15b03a1','謝人送壑源絕品云九重所賜也','曾幾','宋','宋诗','song-poetry','','[]','三伏汗如雨，終朝沾我裳。',48,'全唐诗/poet.song.94000.json','["三伏汗如雨，終朝沾我裳。", "誰分金掌露，來作玉溪凉。", "别甑輭炊飯，小爐深炷香。", "麴生何等物，不與汝同鄉。"]'),
('f72c6a9f-5630-4db7-9498-4cffe0be51e1','大熱欲過廣壽寺謁韓子蒼追凉先之以詩','曾幾','宋','宋诗','song-poetry','','[]','執熱今如此，追凉定若何。',48,'全唐诗/poet.song.94000.json','["執熱今如此，追凉定若何。", "長廊受風遠，廣殿得陰多。", "盛欲扶笻去，還能下榻麽。", "近公如玉雪，未厭數經過。"]'),
('c993f454-85e1-47d0-88a8-074ae6fe2b5a','病中聞鶯啼','曾幾','宋','宋诗','song-poetry','','[]','獨園森古木，其下客幽棲。',48,'全唐诗/poet.song.94000.json','["獨園森古木，其下客幽棲。", "盡日綠陰合，有時黄鳥啼。", "一聲添晝寂，百囀使人迷。", "賴汝生佳聽，身今氣慘悽。"]'),
('155516d7-533d-4678-95cd-06c8a1b37ef2','病起贈曾宏甫','曾幾','宋','宋诗','song-poetry','','[]','同病仍同起，無聊獨至今。',48,'全唐诗/poet.song.94000.json','["同病仍同起，無聊獨至今。", "酒杯君入手，藥裹我關心。", "極暑方無奈，新凉又不禁。", "呼兒鋤徑草，萬一故人臨。"]'),
('884c789f-d311-4ffc-9dda-365f339ec623','蛺蝶','曾幾','宋','宋诗','song-poetry','','[]','不逐春風去，仍當夏日長。',48,'全唐诗/poet.song.94000.json','["不逐春風去，仍當夏日長。", "一雙還一隻，能白或能黄。", "戀戀不能已，翩翩空自狂。", "訃功歸實用，終自愧蜂房。"]'),
('20ec3cdb-070a-47d9-a647-e6673b04ba37','螢火','曾幾','宋','宋诗','song-poetry','','[]','渾忘生朽質，直擬慕光輝。',48,'全唐诗/poet.song.94000.json','["渾忘生朽質，直擬慕光輝。", "解燭書帷靜，能添列宿稀。", "當風方自表，带雨忽成微。", "變滅多無理，榮枯會一歸。"]'),
('83edfba7-7b1b-4171-b7fe-34accf9251b1','讀書','曾幾','宋','宋诗','song-poetry','','[]','散帙有佳趣，俗人那得知。',48,'全唐诗/poet.song.94000.json','["散帙有佳趣，俗人那得知。", "醉鄉非爲酒，坐隱不關棋。", "几凈幽懷愜，窗明老眼宜。", "一生無用處，又把教群兒。"]'),
('be9dad64-1b0e-4f21-9a0f-4cc26c907842','乞筆','曾幾','宋','宋诗','song-poetry','','[]','市上無佳筆，營求亦已勞。',48,'全唐诗/poet.song.94000.json','["市上無佳筆，營求亦已勞。", "護持空雪竹，束縛欠霜毫。", "此物藏三穴，須公拔一毛。", "不堪髯主簿，取用價能高。"]'),
('e5676b62-80a9-4ac6-b3eb-4cdc57850c8c','題雙巖堂','曾幾','宋','宋诗','song-poetry','','[]','老子徜徉地，岩幽想像間。',48,'全唐诗/poet.song.94000.json','["老子徜徉地，岩幽想像間。", "綠陰城角路，青嶂屋頭山。", "簿領惟生睡，壺觴不解顔。", "使人留眼處，龕壁字回環。"]'),
('4d4460c1-45f8-463b-b3b2-fd54c7dec905','泉石堂','曾幾','宋','宋诗','song-poetry','','[]','南坡佳絕處，夏木晝成陰。',48,'全唐诗/poet.song.94000.json','["南坡佳絕處，夏木晝成陰。", "青壁可對面，寒泉能醒心。", "駕言同勝踐，晤語契幽襟。", "野興何曾盡，林間棲暮禽。"]'),
('24009462-d2e6-4d5f-a7df-ea4d2006ddc6','坐進堂','曾幾','宋','宋诗','song-poetry','','[]','茅宇凈掃地，竹爐深炷香。',48,'全唐诗/poet.song.94000.json','["茅宇凈掃地，竹爐深炷香。", "一枝藤倚壁，六尺簟敷牀。", "門掩人聲寂，簾垂晝景長。", "跏趺便終夕，端不負茲堂。"]'),
('6d7a3fd3-a42d-4eed-abba-d0e2a6f7a97a','參雲亭晚坐','曾幾','宋','宋诗','song-poetry','','[]','大暑不可避，微凉安所尋。',48,'全唐诗/poet.song.94000.json','["大暑不可避，微凉安所尋。", "雲霄非濁世，竹樹有清陰。", "海近風先集，山高日易沈。", "無因見明月，螢火亂更深。"]'),
('5809bcd5-372c-41d5-ab28-d27db04582cf','龍溪新亭','曾幾','宋','宋诗','song-poetry','','[]','不識梯山路，今聞駕壑橋。',48,'全唐诗/poet.song.94000.json','["不識梯山路，今聞駕壑橋。", "蛟龍深窟宅，松竹半雲霄。", "與子成二老，由來非一朝。", "崖藤如暫寄，還往肯辭遙。"]'),
('c103ede0-0173-406f-9ea0-c1b0a245958e','雪中次韻','曾幾','宋','宋诗','song-poetry','','[]','積雪何所待，凍雲終未開。',48,'全唐诗/poet.song.94000.json','["積雪何所待，凍雲終未開。", "有時聞瀉竹，無路去尋梅。", "只欲關門臥，誰能蕩槳來。", "辟寒須底物，正乏麴生才。"]'),
('ddb84df7-aae4-4f59-9f2e-1eb5f381ce02','負暄','曾幾','宋','宋诗','song-poetry','','[]','炙背茅簷日，雖貧辦不難。',48,'全唐诗/poet.song.94000.json','["炙背茅簷日，雖貧辦不難。", "趙衰真可愛，范叔一何寒。", "蝨暖無遺索，書明得細看。", "羲和有底急，薄暮更衣單。"]'),
('d40a6830-b49f-49d3-aca3-cccccbf45d88','次韻三首  其一','曾幾','宋','宋诗','song-poetry','','[]','白日無偏照，玄冥不作難。',48,'全唐诗/poet.song.94000.json','["白日無偏照，玄冥不作難。", "有爐如許大，無地可言寒。", "書腹夤緣曬，禪心邂逅看。", "呼兒來共此，形影未孤單。"]'),
('59251811-426d-4c6a-b5c2-d892f499d42b','次韻三首  其二','曾幾','宋','宋诗','song-poetry','','[]','御冬無過酒，得酒政應難。',48,'全唐诗/poet.song.94000.json','["御冬無過酒，得酒政應難。", "可愛惟晴日，相依度歳寒。", "雖非挾纊坐，且作擁爐看。", "饑亦何堪忍，斜陽掛食單。"]'),
('fa516c90-75c9-4e98-bfd7-c16d668af171','次韻三首  其三','曾幾','宋','宋诗','song-poetry','','[]','鑿土篝松火，爲爐有底難。',48,'全唐诗/poet.song.94000.json','["鑿土篝松火，爲爐有底難。", "未知行地日，可辟中人寒。", "氣味醇醪似，光陰尺璧看。", "回頭長夏景，直欲褫中單。"]'),
('06fbb32c-3714-4adb-9316-7717e57b4d3a','晁園','曾幾','宋','宋诗','song-poetry','','[]','晁氏芳菲圃，因依淥水潯。',48,'全唐诗/poet.song.94000.json','["晁氏芳菲圃，因依淥水潯。", "峰巒春著色，桃李晝成陰。", "可惜花狼籍，仍遭雨滯淫。", "饒陽供客眼，只有此園林。"]'),
('eb3de5ec-39b3-4ee1-ba03-095a7efb0b3f','次朱新仲待制見慶次對之命韻','曾幾','宋','宋诗','song-poetry','','[]','典郡才能薄，趨朝氣力微。',48,'全唐诗/poet.song.94000.json','["典郡才能薄，趨朝氣力微。", "更堪持橐去，只合掛冠歸。", "六閤麗千尺，四松森百圍。", "公今有班綴，衰老借餘輝。"]'),
('94f3e466-7033-4ec7-8c70-063b66b1b8bd','次劉千歳喜折仲古見過二首韻  其一','曾幾','宋','宋诗','song-poetry','','[]','新知劉子政，生理髮蕭疏。',48,'全唐诗/poet.song.94000.json','["新知劉子政，生理髮蕭疏。", "勝日歸談笑，佳山奉起居。", "摩挲千古物，料理一牀書。", "秀色堪餐否，聊須摘我蔬。"]'),
('08e527a1-7537-4ee8-b39f-e5bdb86a265b','次劉千歳喜折仲古見過二首韻  其二','曾幾','宋','宋诗','song-poetry','','[]','門對分流水，窗横别岸山。',48,'全唐诗/poet.song.94000.json','["門對分流水，窗横别岸山。", "茅茨居不翦，蓬蓽晝常關。", "傾蓋曾三徑，搖旌每數間。", "猶欣龍閣老，攜得好詩還。"]'),
('d07921b9-c910-473a-aff2-d8ac5a27270b','次曾宏甫見過二首韻  其一','曾幾','宋','宋诗','song-poetry','','[]','客有過蘭若，交情似竹林。',48,'全唐诗/poet.song.94000.json','["客有過蘭若，交情似竹林。", "野花無可落，村酒不宜斟。", "又得清新句，如聞謦欬音。", "南坡盟好在，爲問幾時尋。"]'),
('cccc39b6-04e4-4517-856e-b176c7686335','次曾宏甫見過二首韻  其二','曾幾','宋','宋诗','song-poetry','','[]','鶯啼花落後，芳草綠陰初。',48,'全唐诗/poet.song.94000.json','["鶯啼花落後，芳草綠陰初。", "良會日不足，清談風有餘。", "饑餐聊當肉，嬾出坐無車。", "勿以貧兼病，相過跡也疏。"]'),
('a7e3e470-172a-4d58-aee3-b89b5463f9ca','次鎮江守曾宏甫見寄韻','曾幾','宋','宋诗','song-poetry','','[]','一别高明去，頻爲瘴癘侵。',48,'全唐诗/poet.song.94000.json','["一别高明去，頻爲瘴癘侵。", "連滄公境界，横碧我山林。", "夜雨思同夢，秋風辱寄音。", "他年如衣錦，畢世莫分襟。"]'),
('25f7187d-c72d-4f2d-a410-b1879865ee4e','次曾宏甫見寄韻  其一','曾幾','宋','宋诗','song-poetry','','[]','今晨尺書至，令我寸心寛。',48,'全唐诗/poet.song.94000.json','["今晨尺書至，令我寸心寛。", "老去光陰速，人生會合難。", "竹輿雲洞暖，釣艇玉溪寒。", "小憩饒陽否，吾衰合掛冠。"]'),
('a0366546-48d4-4072-9ae4-ca0139b6167d','次曾宏甫見寄韻  其二','曾幾','宋','宋诗','song-poetry','','[]','剖符舒子國，蠟屐皖公臺。',48,'全唐诗/poet.song.94000.json','["剖符舒子國，蠟屐皖公臺。", "恨不從山簡，欣然見老萊。", "功名身已老，交舊首空回。", "早晚依劉去，朝廷不乏材。"]'),
('ad2b2e44-7b7c-42d7-a622-ae4f4f17e9bc','又二首  其一','曾幾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一紙寢丘書，僧窗屢卷舒。',48,'全唐诗/poet.song.94000.json','["一紙寢丘書，僧窗屢卷舒。", "無因浮左蠡，況復度匡廬。", "政以相望遠，非關自作疏。", "夢成飛鳥去，千里不躊躇。"]'),
('223c7290-71a2-4e42-969e-1d9d2e02d7ec','又二首  其二','曾幾','宋','宋诗','song-poetry','','[]','政喜溪南宅，還乘剡縣船。',48,'全唐诗/poet.song.94000.json','["政喜溪南宅，還乘剡縣船。", "歸來知底日，老去惜餘年。", "觴詠雖休矣，音書未寂然。", "省郎君舊物，消息已真傳。"]'),
('c6d077b5-9cf0-44c1-93c0-547d818768f9','次曾宏甫赴光守留别二首韻  其一','曾幾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聽說光州好，淮山是四隣。',48,'全唐诗/poet.song.94000.json','["聽說光州好，淮山是四隣。", "凝香無一事，奠枕有餘民。", "世以文章著，朝須寵數頻。", "西湖便歸去，應不待班春。"]'),
('41dd6aa5-c700-45bb-a84b-96da06a458fe','次曾宏甫赴光守留别二首韻  其二','曾幾','宋','宋诗','song-poetry','','[]','淮白美無度，山丹開欲然。',48,'全唐诗/poet.song.94000.json','["淮白美無度，山丹開欲然。", "談誇空海內，悵望只溪邊。", "老境嗟無幾，宗盟幸有連。", "到時能走送，别後見相憐。"]'),
('774af649-ab61-4d68-9ac2-45caf1107a9d','五月六日爲叢珍之集于南池呈座中諸公','曾幾','宋','宋诗','song-poetry','','[]','今日攜壺地，南池信杖行。',48,'全唐诗/poet.song.94000.json','["今日攜壺地，南池信杖行。", "紅蕖爭入眼，白鷺最關情。", "待得跳珠雨，來聽打葉聲。", "菰蒲最深處，只欠小舟横。"]'),
('a86af174-6931-4f45-b752-d607eae7a814','公廨蓮池','曾幾','宋','宋诗','song-poetry','','[]','浪說吾邦小，清池思有餘。',48,'全唐诗/poet.song.94000.json','["浪說吾邦小，清池思有餘。", "水風凉枕簟，荷氣馥衣裾。", "客位經過少，官曹簿領疏。", "良辰不行樂，秋水落芙蕖。"]'),
('bd47122b-4646-4048-a72a-511177ce9684','題方氏清芬閣用范文正公韻','曾幾','宋','宋诗','song-poetry','','[]','勝絕登臨地，桐江占十分。',48,'全唐诗/poet.song.94000.json','["勝絕登臨地，桐江占十分。", "省郎才不世，御史氣如雲。", "遂使芝蘭秀，俱能錦繡文。", "諸孫又如許，百代有清芬。"]'),
('9a644b60-4d50-463d-b4a2-9dc7f9885643','效諸生作雪中探梅','曾幾','宋','宋诗','song-poetry','','[]','野梅消息近，踏冷訪林端。',48,'全唐诗/poet.song.94000.json','["野梅消息近，踏冷訪林端。", "東閣尊空滿，南枝雪半殘。", "疏條未禁笑，真態欲欺寒。", "後夜花應好，仍勤束火看。"]'),
('e57bd488-71b2-48b5-a763-1b524dbf2599','嶺梅','曾幾','宋','宋诗','song-poetry','','[]','蠻烟無處洗，梅蕊不勝清。',48,'全唐诗/poet.song.94000.json','["蠻烟無處洗，梅蕊不勝清。", "顧我已頭白，見渠猶眼明。", "折來知韻勝，落去得愁生。", "坐久江南夢，園林雪正晴。"]'),
('c5971d71-a09b-4e54-b465-613e55966307','巖桂二首  其一','曾幾','宋','宋诗','song-poetry','','[]','擢本千巖秀，開花八月凉。',48,'全唐诗/poet.song.94000.json','["擢本千巖秀，開花八月凉。", "雖非傾國色，要是惱人香。", "籬下菊清好，林間蘭靜芳。", "可憐遭遇晚，妙語欠蘇黄。"]'),
('ab29a0b5-49ce-4d61-879d-19a59d8337ce','巖桂二首  其二','曾幾','宋','宋诗','song-poetry','','[]','栗玉黏枝細，青雲翦葉齊。',48,'全唐诗/poet.song.94000.json','["栗玉黏枝細，青雲翦葉齊。", "團團巖下桂，表表木中犀。", "江樹風蕭瑟，園花氣慘悽。", "濃薫不如此，何以慰幽棲。"]'),
('f2e3b783-1cf8-46b2-8682-c06bde829238','種竹','曾幾','宋','宋诗','song-poetry','','[]','近郊蕃竹樹，手種滿庭隅。',48,'全唐诗/poet.song.94000.json','["近郊蕃竹樹，手種滿庭隅。", "餘子不足數，此君何可無。", "風來當一笑，雪壓要相扶。", "莫作封侯相，生來鄙木奴。"]'),
('99675894-8b3e-4746-8e08-cf2ab5b5cb47','二兒次韻予亦復次韻二首  其一','曾幾','宋','宋诗','song-poetry','','[]','此君今日醉，不復記方隅。',48,'全唐诗/poet.song.94000.json','["此君今日醉，不復記方隅。", "窈窕因吾有，恢台到爾無。", "青猶須雨沐，直不要人扶。", "旁舍連高柳，何堪與作奴。"]'),
('d8b8825f-e516-42f7-ba60-8865ffc2a4ec','二兒次韻予亦復次韻二首  其二','曾幾','宋','宋诗','song-poetry','','[]','幽居有忙事，爲竹遶牆隅。',48,'全唐诗/poet.song.94000.json','["幽居有忙事，爲竹遶牆隅。", "雨後青葱否，風前安穩無。", "井深時汲引，架倒復持扶。", "只欠江梅樹，君應壻玉奴。"]'),
('2f3a7e2a-cbf7-4061-ad75-6765d3a73248','新種竹有筍','曾幾','宋','宋诗','song-poetry','','[]','此君非俗物，今歳有佳兒。',48,'全唐诗/poet.song.94000.json','["此君非俗物，今歳有佳兒。", "徑密無人見，僧來報客知。", "西家應滿地，上番欲横枝。", "添得清聲未，君聽風雨時。"]'),
('0d1eed76-8f56-4b04-aa7c-3836fd1ca974','竹軒出筍','曾幾','宋','宋诗','song-poetry','','[]','問訊東軒竹，新萌頗不齊。',48,'全唐诗/poet.song.94000.json','["問訊東軒竹，新萌頗不齊。", "文章藏霧豹，頭角觸藩羝。", "逸氣先騰上，長鞭半落西。", "後來堪底用，采掇付山妻。"]'),
('86d46346-f975-4e02-9ce5-2de988386a96','似賢齋竹','曾幾','宋','宋诗','song-poetry','','[]','大暑不可度，小軒聊復開。',48,'全唐诗/poet.song.94000.json','["大暑不可度，小軒聊復開。", "只消看竹坐，不必要風來。", "豈待迷時種，何妨臘月栽。", "葉端須雨打，有句索渠催。"]'),
('8cbe4155-873f-40f4-91fa-004ae42da54b','所種竹鞭盛行','曾幾','宋','宋诗','song-poetry','','[]','獨遶篔簹徑，令人喜欲顛。',48,'全唐诗/poet.song.94000.json','["獨遶篔簹徑，令人喜欲顛。", "已持蘇老節，更著祖生鞭。", "傍舍應除地，新梢擬上天。", "真成時夜卵，煨茁想明年。"]'),
('15adf342-f760-4027-ac08-a539eb191423','逮子作亭于官舍明清堂後種竹殆千竿余名其亭以留客取老杜竹深留客處之句因題二小詩云  其一','曾幾','宋','宋诗','song-poetry','','[]','行到竹窮處，有亭佳可遊。',48,'全唐诗/poet.song.94000.json','["行到竹窮處，有亭佳可遊。", "境因吾子勝，客爲此君留。", "娟凈經時雨，蕭梢六月秋。", "豈無他草樹，涇渭不同流。"]'),
('12d078a2-c568-4c56-a90f-afdadf17c30c','逮子作亭于官舍明清堂後種竹殆千竿余名其亭以留客取老杜竹深留客處之句因題二小詩云  其二','曾幾','宋','宋诗','song-poetry','','[]','種竹無他事，林間與客遊。',48,'全唐诗/poet.song.94000.json','["種竹無他事，林間與客遊。", "自應攜手入，安用閉門留。", "靜可過僧夏，清宜對奕秋。", "衰翁九節杖，來往亦風流。"]'),
('59b037a8-c917-4ff9-8f27-2b1885a119e5','代書抵筠守譚崧老求茶筍','曾幾','宋','宋诗','song-poetry','','[]','問訊江南美，人推道院州。',48,'全唐诗/poet.song.94000.json','["問訊江南美，人推道院州。", "雨前收雀舌，雪底薦貓頭。", "有客同僧過，頻年遣僕求。", "故交今五馬，解送老龐不。"]'),
('cff1d4b7-5e34-455c-acd0-b448d27f997e','南歸題揚州竹西亭','曾幾','宋','宋诗','song-poetry','','[]','往歳出蕪城，飄然一客星。',48,'全唐诗/poet.song.94000.json','["往歳出蕪城，飄然一客星。", "又從江北路，重到竹西亭。", "楚岸寛圍碧，吳山遠借青。", "聖時還舊觀，歌吹月中聽。"]'),
('0bfd1b81-2a2c-4f37-9782-1bc5e946d64b','登揚州郡圃小金山遙碧亭','曾幾','宋','宋诗','song-poetry','','[]','絕島浸中零，飛來棗葉輕。',48,'全唐诗/poet.song.94000.json','["絕島浸中零，飛來棗葉輕。", "碧天圍斗野，紅日下蕪城。", "山作脩眉翠，人添老眼明。", "園林多勝地，獨愛小崢嶸。"]'),
('31e5c325-91ab-47a7-9d78-d28f4eb4f21a','高郵無梅花求之于揚帥鄧直閣','曾幾','宋','宋诗','song-poetry','','[]','送臘臘垂盡，迎春春欲回。',48,'全唐诗/poet.song.94000.json','["送臘臘垂盡，迎春春欲回。", "如何萬家縣，不見一枝梅。", "有客幽尋去，無人遠寄來。", "揚州何遜在，政用小詩催。"]'),
('6f2e2a50-8721-4b93-9e69-bb27ee8c9dbc','鄧帥寄梅并山堂酒','曾幾','宋','宋诗','song-poetry','','[]','甓社湖邊路，詩筒得報回。',48,'全唐诗/poet.song.94000.json','["甓社湖邊路，詩筒得報回。", "舊時雲液酒，新歳雨肥梅。", "不是園官送，真成驛使來。", "鬢毛都白盡，更著此花催。"]'),
('8ae97112-7af5-4794-9d34-290d05c6377e','謁徑山佛日杲禪師于虎丘','曾幾','宋','宋诗','song-poetry','','[]','此老雲相似，何天不往還。',48,'全唐诗/poet.song.94000.json','["此老雲相似，何天不往還。", "打包龍井寺，持鉢虎丘山。", "一别經年事，相逢半日間。", "向來參底語，不墮有無間。"]'),
('c747c967-a415-4391-83a5-174a5212c1d6','遊虎丘寺','曾幾','宋','宋诗','song-poetry','','[]','重遊吳子國，又入虎丘山。',48,'全唐诗/poet.song.94000.json','["重遊吳子國，又入虎丘山。", "長日挽人住，好風將我還。", "兒童陪勝踐，長老記衰顔。", "無復尹和靖，西菴空掩關。"]'),
('8b8e210b-34ac-4f53-b5d3-abe5696366ba','留别榮茂實侍郎','曾幾','宋','宋诗','song-poetry','','[]','老爲吳會客，耆舊不相忘。',48,'全唐诗/poet.song.94000.json','["老爲吳會客，耆舊不相忘。", "政以牛馬走，曾陪鵷鷺行。", "千年書穴在，六月鏡湖凉。", "從此登臨地，回頭憶侍郎。"]'),
('c369053f-696d-4878-bc7c-2e790f2bd505','寓廣教僧寺','曾幾','宋','宋诗','song-poetry','','[]','似病元非病，求閑方得閑。',48,'全唐诗/poet.song.94000.json','["似病元非病，求閑方得閑。", "殘僧六七輩，敗屋兩三間。", "野外無供給，城中斷往還。", "同參木上座，與汝住茶山。"]'),
('a69145cf-705f-4f9e-839c-46284b9595e5','嶽麓寺','曾幾','宋','宋诗','song-poetry','','[]','嶽麓知名寺，幽尋到眼邊。',48,'全唐诗/poet.song.94000.json','["嶽麓知名寺，幽尋到眼邊。", "林深不見日，山靜只聞泉。", "便欲呼舟去，聊爲借榻眠。", "明朝遊歷處，都在小窗前。"]'),
('9d4b53d7-7b6f-4117-bd23-86c020d5e029','嶺外出巡','曾幾','宋','宋诗','song-poetry','','[]','嶺外身逾老，江南首重回。',48,'全唐诗/poet.song.94000.json','["嶺外身逾老，江南首重回。", "有猿啼夢破，無雁寄書來。", "山雨晴猶濕，蠻烟晝不開。", "如何緣許事，奪我手中杯。"]'),
('c2307758-a2e6-4b57-a66e-b06ec9be64d2','南雄郡守致怪石四株','曾幾','宋','宋诗','song-poetry','','[]','只道無南雁，書今數往還。',48,'全唐诗/poet.song.94000.json','["只道無南雁，書今數往還。", "一窗江表地，數朵廣東山。", "奇甚君風骨，蒼然我面顔。", "歸時要船重，更爲斸岩間。"]'),
('0c2ee533-577c-45f1-940f-f92758db0538','何德器寄道州怪石','曾幾','宋','宋诗','song-poetry','','[]','一去春陵郡，天星幾度回。',48,'全唐诗/poet.song.94000.json','["一去春陵郡，天星幾度回。", "身今鏡湖住，山自道州來。", "指點雙巖出，摩挲一笑開。", "是誰營致此，石友似陳雷。"]'),
('448ac345-d6a6-40e6-8ac6-bf548c47688e','太湖石','曾幾','宋','宋诗','song-poetry','','["\u592a\u6e56"]','誰憐孤峭質，移在太湖心。',48,'全唐诗/poet.song.94000.json','["誰憐孤峭質，移在太湖心。", "出得風波外，任他池館深。", "不同花逞豔，多愧竹垂陰。", "一片至堅操，那憂歳月侵。"]'),
('89f93a38-e0ea-4992-94b4-e50b2d43645c','怪石','曾幾','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','濟勝初無具，搜奇只此間。',48,'全唐诗/poet.song.94000.json','["濟勝初無具，搜奇只此間。", "飛來太湖石，坐我洞庭山。", "面面成窗戶，峰峰出髻鬟。", "寓居端欠此，頗欲載之還。"]'),
('54efd8ed-310a-4ac5-b241-868f685b702d','聞寇至初去柳州','曾幾','宋','宋诗','song-poetry','','[]','剝啄誰敲戶，倉皇客抱衾。',48,'全唐诗/poet.song.94000.json','["剝啄誰敲戶，倉皇客抱衾。", "只看人似蟻，共道賊如林。", "兩岸論千里，扁舟抵萬金。", "病夫桑下戀，萬一有佳音。"]'),
('9a394ffa-73c2-44bd-b850-07cd61a0a6dc','聞寇退欲還柳州寄柳守常子正','曾幾','宋','宋诗','song-poetry','','[]','舊隱龍城在，書傳喜可知。',48,'全唐诗/poet.song.94000.json','["舊隱龍城在，書傳喜可知。", "還來避地客，已去弄兵兒。", "瘴色休看鏡，行期不問龜。", "中秋一杯酒，定與故人持。"]'),
('850fcba0-dfd3-4b63-9550-632bff233d5e','大藤峽','曾幾','宋','宋诗','song-poetry','','[]','一洗干戈眼，舟穿亂石間。',48,'全唐诗/poet.song.94000.json','["一洗干戈眼，舟穿亂石間。", "不因深避地，何得飽看山。", "江潰重圍急，天横一線慳。", "人言三峽險，此路足追攀。"]'),
('25f2627d-ebe9-4e86-86b0-62a2eb158483','歸途','曾幾','宋','宋诗','song-poetry','','[]','歸途似烏鵲，得樹且依棲。',48,'全唐诗/poet.song.94000.json','["歸途似烏鵲，得樹且依棲。", "一寸客亭燭，數聲村舍雞。", "路長風正北，野曠日沈西。", "夢作祠官去，江干入馬蹄。"]'),
('b71dad0a-2145-480c-9065-b1d52dedd9c8','自廣西歸上饒閱所藏書','曾幾','宋','宋诗','song-poetry','','[]','久矣山人去，懷哉屋壁藏。',48,'全唐诗/poet.song.94000.json','["久矣山人去，懷哉屋壁藏。", "侵陵閱梅雨，調護乏芸香。", "次第繙經集，呼兒理在亡。", "乞歸全爲此，何愛橐中裝。"]'),
('09f02585-dce2-4b43-b48e-db7bf6e608cd','初還信州呈寓居諸公','曾幾','宋','宋诗','song-poetry','','[]','萬事不稱意，一生長損心。',48,'全唐诗/poet.song.94000.json','["萬事不稱意，一生長損心。", "稍知閑有味，又覺老相侵。", "田舍那能問，溪山未暇尋。", "清歌一杯酒，聊與故人斟。"]'),
('a5d75738-6c51-4919-a572-d5551fba631f','呂郎治先以職事至常山縣不敢越境以書致兩郡酒日鑄茶','曾幾','宋','宋诗','song-poetry','','[]','子到常山縣，饒陽有敝廬。',48,'全唐诗/poet.song.94000.json','["子到常山縣，饒陽有敝廬。", "相望百里地，空得數行書。", "睡思茶料理，愁懷酒破除。", "新秋即在眼，過我定何如。"]'),
('6537444d-7409-48b4-aa60-f84623fece18','迪侄屢餉新茶二首  其一','曾幾','宋','宋诗','song-poetry','','[]','吾家今小阮，有使附書頻。',48,'全唐诗/poet.song.94000.json','["吾家今小阮，有使附書頻。", "喚起南柯夢，持來北苑春。", "顧余多下駟，況復似陳人。", "不是能分少，其誰遣食新。"]'),
('1f4b89b6-5bf9-4a1d-b793-392cd64cc079','迪侄屢餉新茶二首  其二','曾幾','宋','宋诗','song-poetry','','[]','敕廚羞煮餅，掃地供爐芬。',48,'全唐诗/poet.song.94000.json','["敕廚羞煮餅，掃地供爐芬。", "湯鼎聊從事，茶甌遂策勳。", "興來吾不淺，送似汝良勤。", "欲作柯山點，當令阿造分。"]'),
('4161bff0-8063-4734-8303-fe4978736b7b','造侄寄建茶','曾幾','宋','宋诗','song-poetry','','[]','汝已去閩嶺，茶酒猶粲然。',48,'全唐诗/poet.song.94000.json','["汝已去閩嶺，茶酒猶粲然。", "買應從聚處，寄不下常年。", "洗滌盧仝椀，提攜陸羽泉。", "無人分得好，更憶仲容賢。"]'),
('c63da69d-5887-482f-bc9a-02041980966d','述侄餉日鑄茶','曾幾','宋','宋诗','song-poetry','','[]','寶胯自不乏，山芽安可無。',48,'全唐诗/poet.song.94000.json','["寶胯自不乏，山芽安可無。", "子能來日鑄，吾得具風爐。", "夏木囀黄鳥，僧窗行白駒。", "談多轉生睡，此味正時須。"]'),
('e8eb94f7-bf26-45db-b4d0-6fba5707244c','曾同季餉建溪顧渚新茶','曾幾','宋','宋诗','song-poetry','','[]','雨潤梅黄後，風薫麥秀初。',48,'全唐诗/poet.song.94000.json','["雨潤梅黄後，風薫麥秀初。", "不持新茗椀，空枉故人書。", "顧渚瓊糜似，閩溪玉食餘。", "吾宗重盟好，併以遺閑居。"]'),
('e8c5e271-b3c4-49dd-a801-5e78c9084d52','尹少稷寄顧渚茶','曾幾','宋','宋诗','song-poetry','','[]','駸駸要路津，舊日水南人。',48,'全唐诗/poet.song.94000.json','["駸駸要路津，舊日水南人。", "尙記茶山老，能分顧渚春。", "江淮勞廟算，河路暗胡塵。", "憂國惟生睡，降魔固有神。"]'),
('33ebfee6-f2da-4b57-ba47-82295b289e02','嘗建茗二首  其一','曾幾','宋','宋诗','song-poetry','','[]','破除湯餅睡，倚賴建溪春。',48,'全唐诗/poet.song.94000.json','["破除湯餅睡，倚賴建溪春。", "往日惟求舊，今朝遽食新。", "不辭濃似粥，少待細于塵。", "寶胯無多子，留須我輩人。"]'),
('72ebc7ee-b565-4906-a6b2-ee50f8887257','嘗建茗二首  其二','曾幾','宋','宋诗','song-poetry','','[]','茅宇已初夏，茶甌方早春。',48,'全唐诗/poet.song.94000.json','["茅宇已初夏，茶甌方早春。", "真成湯沃雪，無復渴生塵。", "有客嘲三韭，其誰送八珍。", "不如藏去好，孤負一年新。"]'),
('64007811-4d74-4796-a1a5-a78fda475ef9','煎茶','曾幾','宋','宋诗','song-poetry','','[]','貧中有佳設，石鼎事煎烹。',48,'全唐诗/poet.song.94000.json','["貧中有佳設，石鼎事煎烹。", "顧渚草芽白，惠山泉水清。", "酌多風可御，薫歇霧猶横。", "飲罷妻孥笑，枯腸百轉鳴。"]'),
('bd43a550-9b0a-4cce-92dc-9d1e0c5453f3','鄭侍郎招賞瑞香感舊有作','曾幾','宋','宋诗','song-poetry','','[]','鄭驛留賓處，看花又一年。',48,'全唐诗/poet.song.94000.json','["鄭驛留賓處，看花又一年。", "香囊依葉密，錦繖向人圓。", "子敬新游岱，吾宗復在邊。", "小詩相促迫，感舊一凄然。"]'),
('f7421aee-542a-4f3a-996d-ab40eadaa307','榴花','曾幾','宋','宋诗','song-poetry','','[]','樹陰看已合，榴朵見初明。',48,'全唐诗/poet.song.94000.json','["樹陰看已合，榴朵見初明。", "當夏豈無意，避春真有情。", "花雖後文杏，實可待瓌橙。", "病叟緣何喜，留苔看落英。"]'),
('c7953368-53df-405d-a120-938ade258460','九日小圃菊花有開者病瘍不能泛一杯把玩而已','曾幾','宋','宋诗','song-poetry','','[]','黄菊開何許，疏籬小隱家。',48,'全唐诗/poet.song.94000.json','["黄菊開何許，疏籬小隱家。", "似知重九日，故放兩三花。", "病著杯無淥，衰年髮半華。", "佳辰辜負汝，滿把但成嗟。"]'),
('68538134-cf85-4368-9145-0baa17c680f6','宫祠滿秩','曾幾','宋','宋诗','song-poetry','','[]','雲水天台郡，祠庭我所監。',48,'全唐诗/poet.song.94000.json','["雲水天台郡，祠庭我所監。", "幾年真傲吏，今日是前銜。", "祿米誰周急，園蔬不療饞。", "上書端未免，定不達空函。"]'),
('9a5ba788-c19b-4784-a399-33c39062b7f6','送曾宏甫守天台','曾幾','宋','宋诗','song-poetry','','[]','此地多朋好，惟君似弟兄。',48,'全唐诗/poet.song.94000.json','["此地多朋好，惟君似弟兄。", "不堪輕作别，那得易爲情。", "秋日行灕水，春風上赤城。", "莫言無過雁，略不寄佳聲。"]'),
('9b2f006f-3df7-47f3-9033-420150c92b8d','送戚弼甫解官鹽場二首  其一','曾幾','宋','宋诗','song-poetry','','[]','聽說君中外，堂堂世上名。',48,'全唐诗/poet.song.94000.json','["聽說君中外，堂堂世上名。", "文華張右史，正素老先生。", "已上三年課，相期萬里程。", "贈行無好句，聊用一杯傾。"]'),
('4e7dd07d-f8cb-4618-977a-30a060e6ce82','送戚弼甫解官鹽場二首  其二','曾幾','宋','宋诗','song-poetry','','[]','訪舊今無幾，惟君昔有連。',48,'全唐诗/poet.song.94000.json','["訪舊今無幾，惟君昔有連。", "笑談傾一坐，筆札富諸賢。", "作惡又數日，從游經二年。", "勉旃繩祖武，窮達自關天。"]'),
('4a7ad701-e5b8-40c7-9605-a95d37c5ac5b','送李商叟','曾幾','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','好去皇華使，佳哉所領州。',48,'全唐诗/poet.song.94000.json','["好去皇華使，佳哉所領州。", "職除天祿閣，家近岳陽樓。", "一別誰青眼，相逢各白頭。", "西來多驛騎，能寄短書不。"]'),
('d2419091-60b4-4eb1-bd20-882bfaa37553','送紹興張耆年教授之永嘉學官','曾幾','宋','宋诗','song-poetry','','[]','海內孤寒士，江頭獨冷官。',48,'全唐诗/poet.song.94000.json','["海內孤寒士，江頭獨冷官。", "胡爲涉脩阻，不肯近長安。", "蠲紙無留筆，生枝不带酸。", "名山天下少，行矣雪消殘。"]'),
('be07f4fb-199b-41be-88a1-638027bbfd07','送洪州西山香城長老通公惠通','曾幾','宋','宋诗','song-poetry','','[]','聞說香城寺，孤峰靉靆間。',48,'全唐诗/poet.song.94000.json','["聞說香城寺，孤峰靉靆間。", "公今懷祖印，老去入鄉關。", "穩泛春波水，深藏暮雨山。", "筆頭多語句，寄我不當慳。"]'),
('381955d9-f207-45b8-aa15-10cebef24204','逮子赴湖南漕司舉寄之','曾幾','宋','宋诗','song-poetry','','[]','舉子忙如此，槐花細細開。',48,'全唐诗/poet.song.94000.json','["舉子忙如此，槐花細細開。", "吾兒承詔去，有客附書來。", "鶴髮風前帽，雞頭月下杯。", "衰年餘幾許，勝日不同陪。"]'),
('ef338811-9849-4f5a-be37-9e63a05abdfb','逮子以今歳正月十六日之毗陵而以十二月十五日還舍銓試第二且得新雛以詩示之','曾幾','宋','宋诗','song-poetry','','[]','不見吾兒久，今朝慰眼前。',48,'全唐诗/poet.song.94000.json','["不見吾兒久，今朝慰眼前。", "分襟燈火夜，回櫂雪霜天。", "中鵠令人喜，將雛得我憐。", "一杯歡笑後，急急理塵編。"]'),
('e9ede85f-f9c0-4265-a090-ea370e697531','挽李泰發參政三首  其一','曾幾','宋','宋诗','song-poetry','','[]','公昔遭前政，忠精不少衰。',48,'全唐诗/poet.song.94000.json','["公昔遭前政，忠精不少衰。", "立談廷爭地，上疏里居時。", "意氣南山在，名聲北斗垂。", "心知不亡者，送往得無悲。"]'),
('589bed63-6ce5-4657-a3c1-638a4320cfb2','挽李泰發參政三首  其二','曾幾','宋','宋诗','song-poetry','','[]','漢室推元禮，唐家得衛公。',48,'全唐诗/poet.song.94000.json','["漢室推元禮，唐家得衛公。", "龍門傾後輩，鯨海伏孤忠。", "守護多神物，旋歸一老翁。", "如何九江路，萬事併成空。"]'),
('8ee5dc1a-5818-4296-85ea-3c580dc924bb','挽李泰發參政三首  其三','曾幾','宋','宋诗','song-poetry','','[]','道義曾無間，因依遂有連。',48,'全唐诗/poet.song.94000.json','["道義曾無間，因依遂有連。", "旋聞新雨露，亟返舊林泉。", "父老門庭下，兒孫几杖前。", "不令成此段，泣涕問蒼天。"]'),
('1e132844-e1f3-4e1c-be20-0d94941da708','挽石參議','曾幾','宋','宋诗','song-poetry','','[]','人物千巖秀，家風萬石餘。',48,'全唐诗/poet.song.94000.json','["人物千巖秀，家風萬石餘。", "劉侯深愛畫，杜氏富藏書。", "卿寺曾親擢，藩方有詔除。", "遽隨丹旐去，老淚濺衣裾。"]'),
('fb76f5cc-dc3e-452e-ad27-39a1ef85b920','挽焦適道寺丞二首  其一','曾幾','宋','宋诗','song-poetry','','[]','氣質推渾厚，言談見切磋。',48,'全唐诗/poet.song.94000.json','["氣質推渾厚，言談見切磋。", "過從方里巷，挽送忽山阿。", "吉士今如此，高穹定若何。", "交游雖不乏，耆舊已無多。"]'),
('60c66877-63c4-4c65-b50e-ec3df5705f9a','挽焦適道寺丞二首  其二','曾幾','宋','宋诗','song-poetry','','[]','豈意初秋事，俄聞遠日期。',48,'全唐诗/poet.song.94000.json','["豈意初秋事，俄聞遠日期。", "在公無可憾，有客不勝悲。", "宅兆溪山好，郊原草木衰。", "給孤園上路，無復往還時。"]'),
('20d12aa6-a1c4-477f-ad0b-4bc3e9774e5c','挽陳丞相','曾幾','宋','宋诗','song-poetry','','[]','身已棲巖壑，公初冠廟堂。',48,'全唐诗/poet.song.94000.json','["身已棲巖壑，公初冠廟堂。", "奉祠方德庇，次對復恩光。", "政爾爲舟楫，如何壞棟梁。", "紼謳爭點筆，衰謝獨難忘。"]'),
('3781a494-8e9b-457c-9bed-3b6b5e8caaed','挽梁元功諫議','曾幾','宋','宋诗','song-poetry','','[]','豈弟更三郡，題評冠一鄉。',48,'全唐诗/poet.song.94000.json','["豈弟更三郡，題評冠一鄉。", "繩愆御史疏，補闕諫臣章。", "直歎牙絃絕，明嗟魏鑑亡。", "皇情應震悼，追賁盛龍光。"]'),
('741e7cfd-0ee2-48ab-8e0e-d07defaa5bed','挽程伯禹尚書三首  其一','曾幾','宋','宋诗','song-poetry','','[]','誠明猶博學，直諒更多聞。',48,'全唐诗/poet.song.94000.json','["誠明猶博學，直諒更多聞。", "休父中興傑，宣王上聖君。", "精忠自金石，感會合風雲。", "不謂生芻奠，今來下馬墳。"]'),
('dc498080-553c-4c2d-9c4d-a5496c6c5e7f','挽程伯禹尚書三首  其二','曾幾','宋','宋诗','song-poetry','','[]','璧水三千士，文闈第一人。',48,'全唐诗/poet.song.94000.json','["璧水三千士，文闈第一人。", "煌煌持紫槖，亹亹逼鴻鈞。", "得郡還辭劇，居家更乞身。", "期頤如可料，愁絕上元春。"]'),
('e0ca6f0b-8812-43bb-84e8-bfbb686518c3','挽程伯禹尚書三首  其三','曾幾','宋','宋诗','song-poetry','','[]','昔在宣和日，雍容接俊游。',48,'全唐诗/poet.song.94000.json','["昔在宣和日，雍容接俊游。", "横經臨璧沼，提槧上瀛洲。", "去德俄千里，依仁復兩州。", "豈知垂老别，華屋落山丘。"]'),
('673d8973-a23d-4339-94d3-9bbfb6f8cabd','挽王元渤舍人二首  其一','曾幾','宋','宋诗','song-poetry','','[]','早得文章譽，仍高政事科。',48,'全唐诗/poet.song.94000.json','["早得文章譽，仍高政事科。", "珠璣隨咳唾，襦袴起謳歌。", "老去貧逾甚，歸來病更多。", "善人今已矣，施報果如何。"]'),
('e3fa2b3d-9f73-41e6-b632-4d1d0f307d54','挽王元渤舍人二首  其二','曾幾','宋','宋诗','song-poetry','','[]','觴詠陪真率，言談見坦夷。',48,'全唐诗/poet.song.94000.json','["觴詠陪真率，言談見坦夷。", "凄凉今日事，牢落暮年悲。", "有淚看詩卷，無情對酒巵。", "哀哉王子敬，吾黨一何衰。"]'),
('d6f6a90d-51ae-498f-9dbb-68491d3bc3b7','挽鄭禹功','曾幾','宋','宋诗','song-poetry','','[]','山海淮壖利，吾徒職駿奔。',48,'全唐诗/poet.song.94000.json','["山海淮壖利，吾徒職駿奔。", "長官惟我在，同事只公存。", "句法深深見，心宗細細論。", "清風今已矣，微月耿黄昏。"]'),
('cd6a2f1a-d7d1-4a51-923e-1168d93248c1','挽向伯恭侍郎三首  其一','曾幾','宋','宋诗','song-poetry','','[]','忠義雲霄逼，聲名日月懸。',48,'全唐诗/poet.song.94000.json','["忠義雲霄逼，聲名日月懸。", "劇談風滿坐，傑作氣無前。", "詩酒今彭澤，山林昔輞川。", "不隨秋露盡，家集燦成編。"]'),
('0d3ec70a-f099-4740-9e40-dfbf0fdba4de','挽向伯恭侍郎三首  其二','曾幾','宋','宋诗','song-poetry','','[]','用舍行藏事，如公世所難。',48,'全唐诗/poet.song.94000.json','["用舍行藏事，如公世所難。", "誰能奉香火，直作掛衣冠。", "國論言猶在，宸毫墨未乾。", "一生無限好，留與後人看。"]'),
('f1d58d42-a2b7-4f0d-adb0-e8f2fd5b02d4','挽向伯恭侍郎三首  其三','曾幾','宋','宋诗','song-poetry','','[]','昔在兒童歳，曾陪竹馬游。',48,'全唐诗/poet.song.94000.json','["昔在兒童歳，曾陪竹馬游。", "薌林叨共席，泛宅幸同舟。", "忽忽三年别，堂堂萬事休。", "孤風亭下夢，猶記曩時不。"]'),
('b7d23978-4434-44d0-b10f-bf7bcd5f70b9','挽晁恭道侍郎二首  其一','曾幾','宋','宋诗','song-poetry','','[]','家令西京傑，文元聖世賢。',48,'全唐诗/poet.song.94000.json','["家令西京傑，文元聖世賢。", "大參名更重，學士集爭傳。", "此道長回首，惟公早比肩。", "嗚呼百年半，齎志遂沈泉。"]'),
('76555562-0832-4978-8bb2-0350dfce7d8f','挽晁恭道侍郎二首  其二','曾幾','宋','宋诗','song-poetry','','[]','往日趨金馬，中年剖玉麟。',48,'全唐诗/poet.song.94000.json','["往日趨金馬，中年剖玉麟。", "論思貳卿事，歌詠別都民。", "久矣窮諸妄，歸歟契一真。", "東園尊俎地，俯仰跡成陳。"]'),
('62c425b9-ddcd-479a-9d43-0aa1f27e3b78','挽呂惇智直閣二首  其一','曾幾','宋','宋诗','song-poetry','','[]','呂卿豪傑士，家世兩申公。',48,'全唐诗/poet.song.94000.json','["呂卿豪傑士，家世兩申公。", "小試爲郎日，深知有祖風。", "名高中興後，病著半生中。", "遂作青山去，嗚呼萬事空。"]'),
('446c9f37-75af-4a0b-a87e-c81d6822c7cc','挽呂惇智直閣二首  其二','曾幾','宋','宋诗','song-poetry','','[]','歷數交游內，公家雅有連。',48,'全唐诗/poet.song.94000.json','["歷數交游內，公家雅有連。", "舍人先即世，駕部復沈泉。", "遠訃聞今夏，高談記昔年。", "離窮一片影，大似老夫然。"]'),
('3f821dce-bea2-4623-9edb-f7da2fd01c4e','戲同諸孫課春日遲遲','曾幾','宋','宋诗','song-poetry','','[]','晝漏今多少，人閑只自知。',72,'全唐诗/poet.song.94000.json','["晝漏今多少，人閑只自知。", "簾垂春色靜，窗度日華遲。", "柳影徐徐轉，花陰緩緩移。", "助成耕野事，添得讀書時。", "醉著三竿睡，憂來一局棋。", "吾徒須愛惜，看即是冬曦。"]'),
('6896a076-b00c-43ef-835b-a42cc9f346ab','王履道左丞見訪','曾幾','宋','宋诗','song-poetry','','[]','近市三椽屋，斜陽一席門。',72,'全唐诗/poet.song.94000.json','["近市三椽屋，斜陽一席門。", "故人空厚祿，過我獨高軒。", "轉刻求巾屨，忘形奉笑言。", "性容安石緩，道許穆生存。", "暝色遙岑合，歸途漲水渾。", "傳呼聽已遠，依舊雀聲喧。"]'),
('a519fcf4-a1a8-491c-b530-e0418f33d2e1','雪中登王正中書閣','曾幾','宋','宋诗','song-poetry','','[]','對雪同誰語，登樓似欲仙。',96,'全唐诗/poet.song.94000.json','["對雪同誰語，登樓似欲仙。", "人家修月戶，丈室散花天。", "山擁鉤簾外，江横隱几前。", "寒深落雁渚，清集釣魚船。", "扶病從摩詰，銷憂得仲宣。", "展書明細字，烹茗濕疏烟。", "月好還同夢，詩成已下弦。", "明年儻相憶，一爲到關邊。"]'),
('2af5405e-9344-446c-bc40-b07db426a06f','秋雨排悶十韻','曾幾','宋','宋诗','song-poetry','','[]','今夏久無雨，從秋卻少晴。',120,'全唐诗/poet.song.94000.json','["今夏久無雨，從秋卻少晴。", "空濛迷遠望，蕭瑟送寒聲。", "衣潤香偏著，書蒸蠧欲生。", "壞簷聞瓦墮，漲水見堤平。", "溝溢池魚出，天低塞雁征。", "螢飛明暗廡，蛙閙雜疏更。", "藥醭時須焙，舟閑任自横。", "未憂荒楚菊，直恐敗吳秔。", "夜永燈相守，愁深酒細傾。", "浮雲會消散，鼓笛賽西成。"]'),
('72a95b2b-3cce-4dfa-976d-aec5a895be00','食蜂兒有感','曾幾','宋','宋诗','song-poetry','','[]','蜂兒雖小物，各自有君臣。',96,'全唐诗/poet.song.94000.json','["蜂兒雖小物，各自有君臣。", "奪食已非義，焚巢兹不仁。", "殺身緣底罪，作俑定何人。", "不憚高論直，寧辭遠送珍。", "解包顔有喜，入坐齒生津。", "海錯休前列，山肴且不陳。", "其誰心惻怛，爲汝鼻酸辛。", "願下孩蟲令，恩傾雨露春。"]'),
('8f2d847b-e5f8-42f8-bc04-3d5e6bcc29dd','辭召命呈子忱侍郎','曾幾','宋','宋诗','song-poetry','','[]','嬾慢無端世所遺，獨憐衰病少光輝。',64,'全唐诗/poet.song.94000.json','["嬾慢無端世所遺，獨憐衰病少光輝。", "惠然投我有華衮，何以報公無紵衣。", "末學虛聲慚取譽，舊章多識恐成非。", "侍郎清鑒懸明鏡，莫道塵埃一點飛。"]'),
('7a27b517-eafb-4906-8a7b-9cbf855768a5','王周士顯謨自閩中歸溈山舊隱道經臨川惠然先辱且出示呂居仁送行詩有見及語因次其韻贈周士','曾幾','宋','宋诗','song-poetry','','[]','此生寡偶固其宜，何况身從老得衰。',64,'全唐诗/poet.song.94000.json','["此生寡偶固其宜，何况身從老得衰。", "門外設羅誰一顧，道旁傾蓋子相知。", "斷金已定交逰事，伐木仍傳故舊詩。", "聞說溈山堪避世，卜鄰他日更無疑。"]'),
('3f613c43-4f03-4943-a586-4a89758710af','雪中陸務觀數來問訊用其韻奉贈','曾幾','宋','宋诗','song-poetry','','[]','江湖迥不見飛禽，陸子殷勤有使臨。',64,'全唐诗/poet.song.94000.json','["江湖迥不見飛禽，陸子殷勤有使臨。", "問我家居誰暖眼，爲言憂國只寒心。", "官軍渡口戰復戰，賊壘淮壖深又深。", "坐看天威掃除了，一壺相賀小叢林。"]'),
('b7c2cb84-af54-44e4-92a1-b7c26b45727a','陸務觀效孔方四舅氏體倒用二舅氏題雲門草堂韻某亦依韻','曾幾','宋','宋诗','song-poetry','','[]','陸子家風有自來，胸中所患郤多才。',64,'全唐诗/poet.song.94000.json','["陸子家風有自來，胸中所患郤多才。", "學如大令倉盛筆，文似若耶溪轉雷。", "襟抱極知非世俗，簿書那解作氛埃。", "集賢舊體君拈出，詩卷從今盥水開。"]'),
('789001a9-02cf-4535-9003-6284ba53151e','以湯餅招韓伯周王巖起二提舉鄭深道曾宏甫二使君宏甫有詩次其韻','曾幾','宋','宋诗','song-poetry','','[]','鏡湖淮瀆舊刺史，廬阜赤城新使君。',64,'全唐诗/poet.song.94000.json','["鏡湖淮瀆舊刺史，廬阜赤城新使君。", "敢持湯餅一取飽，更用尊酒重論文。", "玉川遣奴致雙鯉，吏部呼兒書八分。", "不如哦君七字句，舉首看度南山雲。"]'),
('88c7054a-6fe9-4a60-8ccc-0e38a5729a9d','曾宏甫見招看海裳而郡城新有更初闔扉之令予聞鼔亟歸一詩呈宏甫','曾幾','宋','宋诗','song-poetry','','[]','西蜀名花得許穠，晚來呼客醉花中。',64,'全唐诗/poet.song.94000.json','["西蜀名花得許穠，晚來呼客醉花中。", "可憐朵朵枝枝弱，自占深深淺淺紅。", "收拾雖微少陵老，寵光還有翰林公。", "無聊獨出城闉去，燒燭看時恨不同。"]'),
('f8d9ab85-e178-45a4-8256-75efd8be8255','次曾宏甫社日賞海棠吳守宅且試新茗韻','曾幾','宋','宋诗','song-poetry','','[]','一樹深深地主家，外邊誰復見穠華。',64,'全唐诗/poet.song.94000.json','["一樹深深地主家，外邊誰復見穠華。", "卻因社日治聾酒，得醉春時近眼花。", "著粉施朱俱惬當，吹風洗雨但驚嗟。", "酴釄芍藥垂垂發，更試頭綱一餅茶。"]'),
('44a53f88-b3b7-4607-9afb-07208a6ea8ea','蘇秀道中自七月二十五日夜大雨三日秋苖以蘇喜而有作','曾幾','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u519c\u6c11", "\u5fe7\u56fd\u5fe7\u6c11", "\u79cb\u5929", "\u559c\u60a6", "\u53e4\u8bd7\u4e09\u767e\u9996"]','一夕驕陽轉作霖，夢回凉冷潤衣襟。',64,'全唐诗/poet.song.94000.json','["一夕驕陽轉作霖，夢回凉冷潤衣襟。", "不愁屋漏牀牀濕，且喜溪流岸岸深。", "千里稻花應秀色，五更桐葉最佳音。", "無田似我猶欣舞，何况田間望歲心。"]'),
('3ade51ae-e2a9-4a37-a9d2-39bf0177f29f','喻子才提舉招昌源觀梅倦不克往蘇仁仲有詩次韻','曾幾','宋','宋诗','song-poetry','','[]','問公何許看花回，賸說郊坰十里梅。',64,'全唐诗/poet.song.94000.json','["問公何許看花回，賸說郊坰十里梅。", "樹雜古今他處少，枝分南北一齊開。", "昌源已辦行厨去，離渚猶須使節來。", "況復蘭亭公所葺，清流九曲要傳杯。"]'),
('2a71b5ab-7beb-45d3-b372-c18dd4c17d8e','聞降湖北提鹽','曾幾','宋','宋诗','song-poetry','','[]','一爲散吏寄郊坰，三見南山木葉零。',64,'全唐诗/poet.song.94000.json','["一爲散吏寄郊坰，三見南山木葉零。", "病著不能朝帝所，老來只合奉祠庭。", "繡衣玉節官仍作，流水桃花路再經。", "洞口故人應問我，淹留何處髪星星。"]'),
('5c437077-76bd-49a4-853c-01492a9aed58','南山除夜','曾幾','宋','宋诗','song-poetry','','[]','薫風吹船落江潭，日月除盡猶湖南。',64,'全唐诗/poet.song.94000.json','["薫風吹船落江潭，日月除盡猶湖南。", "百年忽已度強半，十事不能成二三。", "青編中語要細讀，蒲團上禪須飽參。", "兒時顔状聽渠改，瀟湘水色深挼藍。"]'),
('30e68064-2059-49ba-87ce-680cd9f03c41','喜聞天兵已臨衢寇','曾幾','宋','宋诗','song-poetry','','[]','野宿溪行各晏然，吳頭楚尾接風烟。',64,'全唐诗/poet.song.94000.json','["野宿溪行各晏然，吳頭楚尾接風烟。", "豈知苻澤深爲祟，不道柯山最近天。", "境上音郵多浪語，殿前兵馬是真傳。", "未能日報書三捷，竹簟紗厨到曉眠。"]'),
('be112d37-0f73-47d3-9bcc-98cee17f04da','至日述事時江海大捷','曾幾','宋','宋诗','song-poetry','','[]','觀臺四望楚氛開，雲物輪囷瑞九垓。',64,'全唐诗/poet.song.94000.json','["觀臺四望楚氛開，雲物輪囷瑞九垓。", "大雪山陰消得盡，微陽井底放令回。", "江心皁幟千艘沒，海角黄旗一騎來。", "想像天顔知有喜，正衙入賀薦金罍。"]'),
('a949782e-bdc7-43a5-98cd-19151ca4ecf2','寄泉南守趙表之','曾幾','宋','宋诗','song-poetry','','[]','天遣高人下别峰，諒無官事汩胸中。',64,'全唐诗/poet.song.94000.json','["天遣高人下别峰，諒無官事汩胸中。", "香來海外沈煙碧，果熟林間荔子紅。", "曹植詩篇疏入社，裴休參問遠同風。", "蕭然丈室維摩詰，何日文殊對此翁。"]'),
('a513cf96-e2bf-4eb3-9f91-6355974eaa24','寄浙漕韓公圭璡','曾幾','宋','宋诗','song-poetry','','[]','故人官達更相求，不但寒温札翰投。',64,'全唐诗/poet.song.94000.json','["故人官達更相求，不但寒温札翰投。", "深貯爐薫來嶺海，遠包書帙到林丘。", "未知輓粟飛芻外，尚及哦詩把酒不。", "千里往還殊不隔，夢魂常繞日邊州。"]'),
('9662dd05-f9d7-4d45-815f-1c43f1ee6d38','寄浙東參議鄭禹功','曾幾','宋','宋诗','song-poetry','','[]','憶昨分攜自日邊，星辰忽忽幾回天。',64,'全唐诗/poet.song.94000.json','["憶昨分攜自日邊，星辰忽忽幾回天。", "故人老作諸侯客，今我初無二頃田。", "安得詩書同保社，敢煩札翰訪林泉。", "萬山不隔襟期處，賴有渠儂一味禪。"]'),
('7f7103c8-0c46-4bcc-b5d2-540421a05ce3','寄十扇與陳述之','曾幾','宋','宋诗','song-poetry','','[]','饒陽輕箑人共知，封書寄與今其時。',64,'全唐诗/poet.song.94000.json','["饒陽輕箑人共知，封書寄與今其時。", "清風兩腋想披拂，眀月千里能追隨。", "一朝貴重得謝傅，中道捐棄憐班姬。", "吾徒且當置是事，魯縞如雪題新詩。"]'),
('32cd61a6-60a8-471f-995d-c5aadfd89ce1','寄信守徐穉山侍郎','曾幾','宋','宋诗','song-poetry','','[]','歸去來兮莫問津，有船即買繫江濱。',64,'全唐诗/poet.song.94000.json','["歸去來兮莫問津，有船即買繫江濱。", "自應一學陶元亮，不用更呼祁孔賓。", "已卜春前春後日，重尋水北水南人。", "使君爲我新茅棟，數有書來意甚真。"]'),
('3e8c5780-a868-428b-8b2c-c7ae0d34c37f','寄何晉之直閣','曾幾','宋','宋诗','song-poetry','','[]','别來不寄一行書，貝葉琅函想自娛。',64,'全唐诗/poet.song.94000.json','["别來不寄一行書，貝葉琅函想自娛。", "喜得直廬新內閣，夢成同舍舊東都。", "絕知筆底鶱騰在，未省體中安隱無。", "見說閩山小兒子，夤緣即罷數趨隅。"]'),
('c580de1c-55c3-4658-ac36-ba5341dcd484','寄提舶王季羔','曾幾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','外臺隱吏極風流，記得衰翁舊日不。',64,'全唐诗/poet.song.94000.json','["外臺隱吏極風流，記得衰翁舊日不。", "三島十洲曾接武，千巖萬壑更從遊。", "官曹閑似雲間鶴，賈舶紛如海上鷗。", "幸有西湖應著我，時操艇子過明州。"]'),
('2ba67161-ffcc-4c81-a299-f18cb5dedb8d','撫州呈韓子蒼待制','曾幾','宋','宋诗','song-poetry','','[]','一時翰墨頗横流，誰以斯文坐鎮浮。',64,'全唐诗/poet.song.94000.json','["一時翰墨頗横流，誰以斯文坐鎮浮。", "後學不虛稱吏部，此生曾是識荆州。", "相逢未改舊青眼，自笑無成今白頭。", "聞道少林新得髓，離言語次許參不。"]'),
('3742a9dd-70fd-41b5-92e3-2c96cfcac7a2','子蒼攜和章見過用韻爲謝','曾幾','宋','宋诗','song-poetry','','[]','胡嶺三年自竄流，歸來差慰此生浮。',64,'全唐诗/poet.song.94000.json','["胡嶺三年自竄流，歸來差慰此生浮。", "政緣天下無雙士，非爲江東第一州。", "懸榻坐中難入眼，設羅門外少回頭。", "袖詩不意高軒過，問里人曾到此不。"]'),
('f051c2f5-56ea-44a4-bfad-2a52791050c3','次子蒼追憶館中納凉韻','曾幾','宋','宋诗','song-poetry','','[]','飯罷蓬瀛屧響廊，薫風啜茗倚繩牀。',64,'全唐诗/poet.song.94000.json','["飯罷蓬瀛屧響廊，薫風啜茗倚繩牀。", "草荒老氏藏書屋，山繞王家避世牆。", "湯餅承公薦槐綠，爐芬遣我夢芸香。", "欲論舊事愁無奈，願挽天河作酒漿。"]'),
('f59e61f1-737a-41a3-944f-db7f7801de5b','聞李泰發參政得旨自便將歸以詩迓之','曾幾','宋','宋诗','song-poetry','','[]','苦遭前政墮危機，二十餘年詠式微。',64,'全唐诗/poet.song.94000.json','["苦遭前政墮危機，二十餘年詠式微。", "天上謫仙皆欲殺，海濱大老竟來歸。", "故園松菊猶存否，舊日人民果是非。", "最小郎君今弱冠，别時聞道不勝衣。"]'),
('89f00e3d-9e9e-4afd-be5b-6eb47df0edcc','李子長縣丞示詩卷','曾幾','宋','宋诗','song-poetry','','[]','乃祖天邊太白星，裔孫名字見家聲。',64,'全唐诗/poet.song.94000.json','["乃祖天邊太白星，裔孫名字見家聲。", "官曹卑似崔斯立，句律清如庾義城。", "贈我不知相報答，投人政恐未分明。", "丞哉于子元無負，松竹成陰水亂鳴。"]'),
('51eb2106-784c-4b7d-b1c1-f2de006485a0','汪彦章內翰除守臨川以詩賀之','曾幾','宋','宋诗','song-poetry','','[]','臨川內史詔除誰，里巷傳聞報客知。',64,'全唐诗/poet.song.94000.json','["臨川內史詔除誰，里巷傳聞報客知。", "金馬門深曾草制，水精宫冷近題詩。", "行看畫省旌旗入，定把書麟筆札隨。", "若訪毗耶舊居士，無人問疾鬢成絲。"]'),
('3ee0346d-953e-4e4e-a44c-f65441a58e63','賀曾裘甫得解','曾幾','宋','宋诗','song-poetry','','[]','南風盛事昔無聞，乃祖詞場筆有神。',64,'全唐诗/poet.song.94000.json','["南風盛事昔無聞，乃祖詞場筆有神。", "一牓豪英收幾士，同年伯仲看三人。", "今君科第欲驚世，他日文章當致身。", "意惬歸來能訪我，亦令宗派倚生春。"]'),
('ad5701e5-1e14-43aa-b2b8-f432faa9d6ce','吳元中少宰復官守長沙以詩賀之','曾幾','宋','宋诗','song-poetry','','[]','眼看亂後幾凋年，神護靈光獨巋然。',64,'全唐诗/poet.song.94000.json','["眼看亂後幾凋年，神護靈光獨巋然。", "鏡裏未添新白髪，囊中初得舊青氊。", "寄書地正當回雁，晤語身方走跕鳶。", "社稷于公端可卜，一篇江漢詠周宣。"]'),
('c5a8534a-d959-4821-b175-58d7367bc968','題徐子禮自覺齋時子禮爲江陰抱麾之行','曾幾','宋','宋诗','song-poetry','','[]','徐子長吟復短吟，奇書窗下日幽尋。',64,'全唐诗/poet.song.94000.json','["徐子長吟復短吟，奇書窗下日幽尋。", "誰知密密深深地，參得明明了了心。", "千里澄江空更濶，中秋素月古猶今。", "使君胸次端如許，願以餘光照所臨。"]'),
('14a28fe8-c51b-434b-846a-c4bc8b62f915','題巾山廣軒次韓无咎韻','曾幾','宋','宋诗','song-poetry','','[]','鈴齋偪仄未銷憂，暇日聊爲帢幘遊。',64,'全唐诗/poet.song.94000.json','["鈴齋偪仄未銷憂，暇日聊爲帢幘遊。", "喬木中間藏古寺，籃輿直上得名流。", "豈無雲水連孤嶼，亦有山林望一州。", "後日玉霄峰頂去，憶經行處爲回頭。"]'),
('ccd16116-a2a8-482f-91e1-5f2cdec6054a','張子公招飯靈感院','曾幾','宋','宋诗','song-poetry','','[]','竹輿響肩艫啞嘔，芙蕖城曉六月秋。',64,'全唐诗/poet.song.94000.json','["竹輿響肩艫啞嘔，芙蕖城曉六月秋。", "露華猶泫草光合，晨氣欲動荷香浮。", "給孤獨園賴君到，伊蒲塞供爲我羞。", "僧窗各自占山色，處處薫爐茶一甌。"]'),
('627c32f7-13bf-4c30-8042-c9d0f860989d','呂居仁力疾作詩送行次其韻','曾幾','宋','宋诗','song-poetry','','[]','雪屋風窗逼歲窮，一杯情話與誰同。',64,'全唐诗/poet.song.94000.json','["雪屋風窗逼歲窮，一杯情話與誰同。", "向人寡偶無如我，抵老相知獨有公。", "文字欲求千古事，簿書還費二年功。", "新詩已佩臨分語，况復哦詩是病中。"]'),
('d62fbd1e-99b0-495e-8eee-6f7706839b97','次韓叔夏送行韻','曾幾','宋','宋诗','song-poetry','','[]','乃祖曾爲文送窮，兒孫氣味略相同。',64,'全唐诗/poet.song.94000.json','["乃祖曾爲文送窮，兒孫氣味略相同。", "立朝有疏慕汲直，去國無書干子公。", "竹椅蒲團深著意，雪窗螢案坐收功。", "自憐無補朝廷事，又向蠻煙瘴雨中。"]'),
('11b016bd-9686-4881-81db-02338029b350','次蘇守朱新仲舍人留會稽之行韻','曾幾','宋','宋诗','song-poetry','','[]','公知此老發船時，不作河梁送别詩。',64,'全唐诗/poet.song.94000.json','["公知此老發船時，不作河梁送别詩。", "但說江湖留我住，爲言巖壑與人期。", "凝香燕寢定自好，懷綬稽山無不宜。", "早晚歡迎剡溪上，去公亦復意遲遲。"]'),
('d3f47b96-ebd0-4618-9005-b670dabdaffe','適越留别朱新仲','曾幾','宋','宋诗','song-poetry','','[]','扁舟綠漲漕渠時，解釋離懷政用詩。',64,'全唐诗/poet.song.94000.json','["扁舟綠漲漕渠時，解釋離懷政用詩。", "管鮑交朋無變態，朱陳嫁娶有佳期。", "長洲茂苑著身久，秦望鏡湖行腳宜。", "二浙中間才一水，短書莫使寄來遲。"]'),
('71c4e98c-e41d-439f-a360-3c3b300ea179','寓居有招客者戲成','曾幾','宋','宋诗','song-poetry','','[]','蓬蒿小院立秋天，禿鬢凄風雨颯然。',64,'全唐诗/poet.song.94000.json','["蓬蒿小院立秋天，禿鬢凄風雨颯然。", "丈室何人問摩詰，後堂無地著彭宣。", "牀頭白酒新浮甕，案上黄詩屢絕編。", "不厭寒家淡生活，書窗期與子周旋。"]'),
('064616b5-8d7d-4f8c-86f0-b5fd3e07f081','次勸農韻','曾幾','宋','宋诗','song-poetry','','[]','典郡治中總得賢，郊原一出萬人傳。',64,'全唐诗/poet.song.94000.json','["典郡治中總得賢，郊原一出萬人傳。", "山行野渡時時雨，婦餉夫耕處處田。", "說與老農無罪歳，但當力作有逢年。", "驅兒播種貧家事，可奈西疇只仰天。"]'),
('05c9d1e6-b6cf-4543-aa51-9a6e52461e7b','處守謝景思寄勸農詩次其韻','曾幾','宋','宋诗','song-poetry','','[]','使君小隊出田間，郤擁旌旗鼔吹還。',64,'全唐诗/poet.song.94000.json','["使君小隊出田間，郤擁旌旗鼔吹還。", "走送勞農詩俊逸，懸知領客事清閑。", "坐曹已白兒時鬢，置酒聊朱病後顔。", "無路從公上烟雨，夢魂長遶處州山。"]'),
('0f6745cf-af91-4190-ae3e-27f87355bf95','乙卯歲江南大旱七月六日臨川得雨奉呈程伯禹待制','曾幾','宋','宋诗','song-poetry','','[]','縹緲爐煙上帝閽，朝來一洗旱如焚。',64,'全唐诗/poet.song.94000.json','["縹緲爐煙上帝閽，朝來一洗旱如焚。", "壟頭無復成龜兆，水面初看起縠紋。", "政使夏畦炊白玉，未妨秋稼割黄雲。", "使君閔雨心猶在，化得邦人不茹葷。"]'),
('1e6b1aa3-47ff-4bac-ad4c-dc49612beb21','空公長老一出即住雪峰書來以建茗爲寄長句奉呈空公時以筆硯作佛事也','曾幾','宋','宋诗','song-poetry','','[]','此公出世使人驚，道眼看來郤未曾。',64,'全唐诗/poet.song.94000.json','["此公出世使人驚，道眼看來郤未曾。", "政爾雪峰千百衆，澹然雲水一孤僧。", "不妨詩筆作佛事，已用茗甌傳祖燈。", "我老尚堪行腳在，因風爲寄古崖藤。"]'),
('620a2559-19f2-42cd-8f15-7feb2bb6388e','送曾宏甫赴光山守','曾幾','宋','宋诗','song-poetry','','[]','千里光山去拊循，長淮練靜屬城闉。',64,'全唐诗/poet.song.94000.json','["千里光山去拊循，長淮練靜屬城闉。", "開門自少公家事，領客寧無我輩人。", "網戶得魚肌切玉，兵厨有酒色鎔銀。", "老翁生死誰相訪，札翰時時到水濱。"]'),
('7d75eda8-082d-4f7c-9cb6-b2e8aa2f58ac','曾宏甫到光山遣送鵝梨淮魚等數種','曾幾','宋','宋诗','song-poetry','','[]','吾宗席未暖淮濱，遣騎持書賸送珍。',64,'全唐诗/poet.song.94000.json','["吾宗席未暖淮濱，遣騎持書賸送珍。", "美實來從壓沙寺，巨魚長比藉糟人。", "欲雕好語略爲報，但愧新詩如有神。", "領客不無桃李樹，知君憶著故園春。"]'),
('132e369c-9f40-4f79-ae8a-4457c98761a7','次秘丞李希聲新省韻','曾幾','宋','宋诗','song-poetry','','[]','吾皇德澤小滄溟，倒載干戈不用刑。',64,'全唐诗/poet.song.94000.json','["吾皇德澤小滄溟，倒載干戈不用刑。", "天以圖書效河洛，人如蘭玉秀堦庭。", "石渠盡日蓬山影，金殿凌虛帝座星。", "從此崇文三萬卷，權輿甲部聖師經。"]'),
('60a1f485-58f7-4d6d-8fbc-f4795b1ab54a','次何德器見贈韻','曾幾','宋','宋诗','song-poetry','','[]','德器交情素所敦，乃翁雖逝典型存。',64,'全唐诗/poet.song.94000.json','["德器交情素所敦，乃翁雖逝典型存。", "不惟歆向皆書府，况復封胡是相門。", "意氣君方凌碧落，年齡我已到黄昏。", "今晨鏡裏如膏沐，歡喜仁人有贈言。"]'),
('86afafae-505f-42ce-b868-2a15adbb45b3','和李宗丞','曾幾','宋','宋诗','song-poetry','','[]','海邦西渡即朝廷，雙闕瓊臺天下名。',64,'全唐诗/poet.song.94000.json','["海邦西渡即朝廷，雙闕瓊臺天下名。", "跋馬望君真屢矣，拏舟過我太遲生。", "門闌不日登元禮，句律今朝得少卿。", "已辦黄花一尊酒，有如江水莫寒盟。"]'),
('e6ef35bb-3a01-41c4-9865-b4f538eab30c','次馮子容主簿信州築居韻','曾幾','宋','宋诗','song-poetry','','[]','聞君卜居水雲鄉，欲往從之各異方。',64,'全唐诗/poet.song.94000.json','["聞君卜居水雲鄉，欲往從之各異方。", "屋角樹陰傾老蓋，溪南山色過浮梁。", "薫風自在翻書葉，梅雨相欺敗堵牆。", "長鋏高歌歸去好，幽棲爲我覓陽岡。"]'),
('af366e81-908e-4d89-9099-2610eb4d9bd2','鄭深道餞曾宏甫台州之行見招風雨不能度溪橋作此贈宏甫','曾幾','宋','宋诗','song-poetry','','[]','一觴相屬費招呼，况復吾宗攬轡初。',64,'全唐诗/poet.song.94000.json','["一觴相屬費招呼，况復吾宗攬轡初。", "春雨春風俱作惡，溪南溪北頓成疏。", "刻殘紅蠟君哦句，挑盡青燈我讀書。", "細故乖違猶似此，功名不必問何如。"]'),
('05a5a4bb-2a05-4645-b4a5-8ab1ec88e820','送曾宏甫守天台','曾幾','宋','宋诗','song-poetry','','[]','莫作陽關墮淚聲，丹丘勝事要君聽。',64,'全唐诗/poet.song.94000.json','["莫作陽關墮淚聲，丹丘勝事要君聽。", "興公賦裏雲霞赤，子美詩中島嶼青。", "天近豈無宣室召，地偏猶有草堂靈。", "鑾坡飛上勤回首，記取來游舊客星。"]'),
('ee269f58-bf60-4f6b-af2e-3ab14fd3f38c','送李似舉尚書帥桂州二首  其一','曾幾','宋','宋诗','song-poetry','','[]','桂林佳事我能言，四座停杯且勿喧。',64,'全唐诗/poet.song.94000.json','["桂林佳事我能言，四座停杯且勿喧。", "人物豪華真樂國，江山清絕勝中原。", "親嘗荔子薫風浦，靜對梅花小雪村。", "邊鎖無虞庭少訟，不妨仙釋問真源。"]'),
('549d2ef6-f4b7-4647-b0d8-6f6dcfe40518','送李似舉尚書帥桂州二首  其二','曾幾','宋','宋诗','song-poetry','','[]','整整三朝玉筍班，幾年流落奉祠官。',64,'全唐诗/poet.song.94000.json','["整整三朝玉筍班，幾年流落奉祠官。", "不令歸曳尚書履，亦合先登大將壇。", "從昔南荒除帥重，只今西顧倚公寛。", "長途不惜身爲御，欲上龍門自作難。"]'),
('7e1822ce-ce55-4751-a764-ad418f006776','送周德修侍郎守武陵郡','曾幾','宋','宋诗','song-poetry','','[]','傾蓋江頭許定交，談經論事聽忘勞。',64,'全唐诗/poet.song.94000.json','["傾蓋江頭許定交，談經論事聽忘勞。", "轍環萬里猶持橐，門掩三秋卻夢刀。", "流水落花公境界，摘山煑海我官曹。", "人生五馬從來貴，行樂何須歎二毛。"]'),
('87e5cf76-ac6e-4f36-b1e8-b35b63c24631','送王亞之','曾幾','宋','宋诗','song-poetry','','[]','執手河梁有贈言，檣烏端爲小留連。',64,'全唐诗/poet.song.94000.json','["執手河梁有贈言，檣烏端爲小留連。", "無風浪起勤看客，不盡江來隱放船。", "煙雨樓臺空夢到，雲天鴻雁只書傳。", "不須更問西歸日，定是彤庭射策年。"]'),
('92eedf53-1420-4909-a5a8-3f8dc1e73b08','送蘇伯益提幹代還侍下','曾幾','宋','宋诗','song-poetry','','[]','幕下官曹寄玉溪，溪邊野老借光輝。',64,'全唐诗/poet.song.94000.json','["幕下官曹寄玉溪，溪邊野老借光輝。", "齧氈校尉衝寒去，扇枕郎君觸熱歸。", "大父正攜靈壽杖，尊公更著老萊衣。", "贈行未說功名事，此事如公世上稀。"]'),
('c77e3cc0-b34f-4d12-8035-48ce3abeffb3','送王宣子赴廬陵守','曾幾','宋','宋诗','song-poetry','','[]','秋風送遠廬陵守，車騎光華鬢未斑。',64,'全唐诗/poet.song.94000.json','["秋風送遠廬陵守，車騎光華鬢未斑。", "早歲名高天下士，同時身到海中山。", "淹回二水分流處，邂逅千巖競秀間。", "行矣衰翁如未死，錦衣白晝候君還。"]'),
('21fad0f4-c363-470f-b2e2-c5703afaa8e1','送賀子忱參議之官閩中','曾幾','宋','宋诗','song-poetry','','[]','越侯賓客有輝光，領袖今年得望郎。',64,'全唐诗/poet.song.94000.json','["越侯賓客有輝光，領袖今年得望郎。", "詩似拾遺留劍外，才如處士去河陽。", "到時晚荔論園買，舊日春茶洗盞嘗。", "璧水同寮幾人在，賸將書疏及滄浪。"]'),
('2755bf09-e61a-43ca-9bb1-d420ca17435b','送路應求赴郢守','曾幾','宋','宋诗','song-poetry','','[]','一雨全清去路塵，石城風物話臨分。',64,'全唐诗/poet.song.94000.json','["一雨全清去路塵，石城風物話臨分。", "了無獄訟勞官長，賸有江山奉使君。", "樓上今誰能和曲，鼻端那復可揮斤。", "吾人莫道知音少，千里歡謡入聽聞。"]'),
('074ba9c3-4fee-43db-9f5d-8ce6a21eb86c','送尹叔之象州','曾幾','宋','宋诗','song-poetry','','[]','歳星一别又回天，貧賤交情老更堅。',64,'全唐诗/poet.song.94000.json','["歳星一别又回天，貧賤交情老更堅。", "傳世典型清徹骨，向人懷抱直如絃。", "經營象郡三椽屋，漂泛龍城一葉船。", "風雨蕭蕭雞自曉，此心常與子周旋。"]'),
('cceb46d4-7a3a-4714-8ab9-97ab35da2df7','送呂倉部治先守齊安','曾幾','宋','宋诗','song-poetry','','[]','齊安剖竹要循良，分付吾家坦腹郎。',64,'全唐诗/poet.song.94000.json','["齊安剖竹要循良，分付吾家坦腹郎。", "賸有江山連赤壁，略無訟獄到黄堂。", "鈴齋晝永宜深念，邊鎖秋高合過防。", "此地元之餘烈在，勉旃幸未鬢毛蒼。"]'),
('bc3ac06c-2fce-4ade-888e-87618b7282f3','送周仲固寺正提舉湖北茶鹽余建炎己酉歲嘗爲此官','曾幾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭湖北飽知聞，嘗以輶軒犯楚氛。',64,'全唐诗/poet.song.94000.json','["洞庭湖北飽知聞，嘗以輶軒犯楚氛。", "遠有光華新令尹，分投閑散故將軍。", "武陵源口自碧水，古德山頭多白雲。", "一路澄清縱幽討，不妨書札細論文。"]'),
('b726c1ab-0d11-4cd8-9458-be12ad3316e5','送方務德將漕廣西時余亦有此除','曾幾','宋','宋诗','song-poetry','','[]','壯時一别鬢成絲，忽漫同盤又語離。',64,'全唐诗/poet.song.94000.json','["壯時一别鬢成絲，忽漫同盤又語離。", "底事不爲三日款，相逢猶是半年遲。", "溪邊贈策正楊柳，境上開尊應荔枝。", "莫歎嶠南荒絕好，光華最有遠人知。"]'),
('63664c85-2f4b-48b6-9fba-20b5a35fae73','送晁恭道侍郎守臨川','曾幾','宋','宋诗','song-poetry','','[]','才猷表表自名卿，何况傳家烜赫聲。',64,'全唐诗/poet.song.94000.json','["才猷表表自名卿，何况傳家烜赫聲。", "道院老人真乃祖，雪堂高弟是諸兄。", "一牛鳴地正接跡，五馬行時尤見情。", "擬峴登臨試回首，小軒應記碧山横。"]'),
('3b50cbe0-d0fc-4fee-91b6-2c9688902b72','送紹興帥湯相得請洞霄歸括蒼二首  其一','曾幾','宋','宋诗','song-poetry','','[]','武公入相不虛傳，奏牘求閑郤更前。',64,'全唐诗/poet.song.94000.json','["武公入相不虛傳，奏牘求閑郤更前。", "聖主閔勞天下士，詔書許作地行仙。", "少微星分臨江左，大滌山門鎖日邊。", "便以公歸良易耳，午橋雖好莫留連。"]'),
('a25de5a9-814e-4e1b-8cd4-8f942065d1af','送紹興帥湯相得請洞霄歸括蒼二首  其二','曾幾','宋','宋诗','song-poetry','','[]','誰言富貴踐危機，永日深春故里歸。',64,'全唐诗/poet.song.94000.json','["誰言富貴踐危機，永日深春故里歸。", "烟雨高樓增意氣，蓬萊傑閣少光輝。", "向來赤舄又遵陸，此去青鞋長掩扉。", "畫戟門東是茅宇，鈴齋想像獨依依。"]'),
('65106b03-ab35-4a37-9b5b-d041eb894b50','送逮子赴秋試江西漕司','曾幾','宋','宋诗','song-poetry','','[]','有詔詞場獵俊英，西風匹馬豫章城。',64,'全唐诗/poet.song.94000.json','["有詔詞場獵俊英，西風匹馬豫章城。", "欲追諸父雁行上，肯逐群兒魚隊行。", "金是莫邪當自必，璞非死鼠會相明。", "筆端妙處還知否，萬里秋天壯氣横。"]'),
('764fc23e-e258-456f-87c6-9486b5503799','示逢子','曾幾','宋','宋诗','song-poetry','','[]','清臞骨相類諸生，黽勉寒窗守一經。',64,'全唐诗/poet.song.94000.json','["清臞骨相類諸生，黽勉寒窗守一經。", "用賦要窺司馬室，學詩頻過伯魚庭。", "可憐親髪鏡中白，莫負子衿身上青。", "五桂蔭門家世事，寂寥天畔幾回星。"]'),
('5eebbe01-991b-4aea-8178-b9783f842c04','同逢子韻寄逮子促其歸','曾幾','宋','宋诗','song-poetry','','[]','九日清尊要及辰，誰令形迹滯甌閩。',64,'全唐诗/poet.song.94000.json','["九日清尊要及辰，誰令形迹滯甌閩。", "饒陽城畔趨庭子，長樂坡前入幕賓。", "竝倚門閭吾二老，相求原隰汝三人。", "借令不共黄花酒，莫與西風作後塵。"]'),
('2262bde7-a4d3-49a7-93f6-7ddddc33d28f','逮子得龍團勝雪茶兩胯以歸予其直萬錢云','曾幾','宋','宋诗','song-poetry','','[]','移人尤物衆談誇，持以趨庭意可嘉。',64,'全唐诗/poet.song.94000.json','["移人尤物衆談誇，持以趨庭意可嘉。", "鮭菜自無三九種，龍團空取十千茶。", "烹嘗便恐成災怪，把玩那能定等差。", "賴有前賢小團例，一囊深貯只傳家。"]'),
('fc217e07-840e-4ff9-9682-f21c4c6d2df3','用逮子韻奉贈鄭禹功參議','曾幾','宋','宋诗','song-poetry','','[]','雨餘依砌上蒼苔，竟日山房閉不開。',64,'全唐诗/poet.song.94000.json','["雨餘依砌上蒼苔，竟日山房閉不開。", "下馬厭聞生客至，敲門喜見故人來。", "長哦綠竹詩三疊，小酌黄花酒一盃。", "此外相看復何事，團蒲隱几湛靈臺。"]'),
('664e9156-12d4-4520-9326-45d119cb2b97','次錢處和贈赴召之行韻','曾幾','宋','宋诗','song-poetry','','[]','蒼顔白髪海邊州，敢與君王側席求。',64,'全唐诗/poet.song.94000.json','["蒼顔白髪海邊州，敢與君王側席求。", "水似篙深催我去，雨如絲下要人留。", "偶然結綬登畿左，不用攀轅擁道周。", "高卧耦耕吾有分，何心賜璧取封侯。"]'),
('5ab83b95-cdf0-4bf4-94ad-c1c2397afc77','留别三侄','曾幾','宋','宋诗','song-poetry','','[]','僧窗又與汝周旋，百感相隨到酒邊。',64,'全唐诗/poet.song.94000.json','["僧窗又與汝周旋，百感相隨到酒邊。", "無復吹箎如異日，空驚枕塊已三年。", "一門叔父吾衰矣，東閣郎君但勉旃。", "不爲懷金紆紫事，澡身玉雪是空傳。"]'),
('3a3364c2-1a58-4acd-ae3c-924af2616c5f','春來聞故舊多云亡者作詩示同志','曾幾','宋','宋诗','song-poetry','','[]','雁足曾無一字收，有時書到郤生愁。',64,'全唐诗/poet.song.94000.json','["雁足曾無一字收，有時書到郤生愁。", "故人疊疊半黄壤，今我蕭蕭全白頭。", "大抵百年皆逝水，可憐萬事只浮漚。", "朝聞夕死真吾道，聖處工夫辦得不。"]'),
('76a2f753-431f-473e-94a6-0ada7719e201','次鄭禹功韻','曾幾','宋','宋诗','song-poetry','','[]','怪底消除執熱煩，鄭公方丈接三韓。',64,'全唐诗/poet.song.94000.json','["怪底消除執熱煩，鄭公方丈接三韓。", "空餘坐榻懸犀柄，豈有行厨洗玉盤。", "作吏忽驚玄鳥變，尋盟未向白鷗寒。", "諸山只在登臨眼，安得陪君杖履看。"]'),
('02b74966-4006-413c-a2e3-caf11d0b6b7b','次招客見贈韻','曾幾','宋','宋诗','song-poetry','','[]','夏夜僧窗淡月籠，新凉絕類九秋中。',64,'全唐诗/poet.song.94000.json','["夏夜僧窗淡月籠，新凉絕類九秋中。", "麴生入座有清濁，荔子堆盤能白紅。", "持此淹留數佳客，慰予牢落一衰翁。", "驪駒散後君知否，獨臥山房竹裏風。"]'),
('fe6e45f2-964c-4430-a667-53e942dd9504','次徐㟯立韻','曾幾','宋','宋诗','song-poetry','','[]','此身那得作飛仙，魂夢相從但欲眠。',64,'全唐诗/poet.song.94000.json','["此身那得作飛仙，魂夢相從但欲眠。", "極目參辰不相見，論心膠膝未爲堅。", "别君甲子三千日，問我春秋七十年。", "久要不忘吾輩事，交情自昔幾人全。"]'),
('e925bc00-d022-40a7-bbab-5c1d13e93f7d','次王元渤問余脱齒韻','曾幾','宋','宋诗','song-poetry','','[]','齒危但以粥充虛，辜負公家夏屋渠。',64,'全唐诗/poet.song.94000.json','["齒危但以粥充虛，辜負公家夏屋渠。", "政恐麴生深作祟，可憐髯簿頓成疏。", "動搖不減韓吏部，蹴踏非同焦校書。", "落勢今年殘未已，秖應從此併無餘。"]'),
('9630cd78-9000-4d92-89a1-9025fc55782f','吳帥見和亦復次韻','曾幾','宋','宋诗','song-poetry','','[]','九日心飛類琯灰，龍山直上好樓臺。',64,'全唐诗/poet.song.94000.json','["九日心飛類琯灰，龍山直上好樓臺。", "老身稚子扶將去，勝地元戎借得來。", "酒似朝霞披霧散，詩如秋菊艷霜開。", "至今研席珠璣滿，莫道登高寂寞回。"]'),
('d159de15-ee96-4f09-af4d-d55eb20cbdb0','次憂字韻','曾幾','宋','宋诗','song-poetry','','[]','公家伯仲世名流，畫省歸來共樂憂。',64,'全唐诗/poet.song.94000.json','["公家伯仲世名流，畫省歸來共樂憂。", "稍喜對牀聽夜雨，永懷扇枕作凉秋。", "誰言小草能蠲忿，未信閑花可療愁。", "惟有塤箎發清吹，渠儂無厭亦無求。"]'),
('817971f3-bce2-43e0-a005-b59cfca09741','挽韓子蒼待制','曾幾','宋','宋诗','song-poetry','','[]','佩聲曾到鳯凰池，不盡胸中五色絲。',64,'全唐诗/poet.song.94000.json','["佩聲曾到鳯凰池，不盡胸中五色絲。", "三黜本因元祐學，一飛合在中興時。", "忽驚地下修文去，太息門邊問字誰。", "猶想泉臺有新作，郊原小雨欲催詩。"]'),
('e5017ae1-8a3b-44f0-9d67-03142997c113','挽鄭禹功','曾幾','宋','宋诗','song-poetry','','[]','鄭公高義絕陳雷，别我姑胥首重回。',64,'全唐诗/poet.song.94000.json','["鄭公高義絕陳雷，别我姑胥首重回。", "書跡横斜良足喜，訃音曲折可勝哀。", "定知泡影垂垂盡，故傍江湖得得來。", "俗眼看公終未是，無生滅處詠歸哉。"]'),
('199f0da4-c2d7-4c9a-9eaa-30fedf6b83f5','挽梁元功','曾幾','宋','宋诗','song-poetry','','[]','朋儔大半白頭新，臭味同流少似君。',64,'全唐诗/poet.song.94000.json','["朋儔大半白頭新，臭味同流少似君。", "交契雖深淡如水，宦情何翅薄于雲。", "安知暮景鶯聲谷，遽作高原馬鬛墳。", "忍向西風歌薤露，略無好語頌清芬。"]'),
('130bf2ab-a708-49cf-a902-070faf596722','挽陳丞相','曾幾','宋','宋诗','song-poetry','','[]','中興論相得耆英，進退能爲國重輕。',64,'全唐诗/poet.song.94000.json','["中興論相得耆英，進退能爲國重輕。", "有望臨人山泰華，無私待物器權衡。", "兩朝禮貌緣同德，多士憑依爲至誠。", "自古元臣薨位少，一時生死極哀榮。"]'),
('d0bd7bc0-ef8e-4674-b80a-9e0cc2f7eac3','悼雲泉勤庵主','曾幾','宋','宋诗','song-poetry','','[]','正坐長齋早得衰，中年一病莫醫治。',64,'全唐诗/poet.song.94000.json','["正坐長齋早得衰，中年一病莫醫治。", "懸知水複山重地，難度風饕雪虐時。", "乘興前村曾有約，寄聲絕頂可無詩。", "禪房手自栽花木，付主林神好護持。"]'),
('43a34a5e-c586-4dbb-9f93-0faaf8309dfc','上元日大雪','曾幾','宋','宋诗','song-poetry','','[]','句芒整轡浹辰間，雪片相隨大可觀。',64,'全唐诗/poet.song.94000.json','["句芒整轡浹辰間，雪片相隨大可觀。", "挑菜園林有餘潤，燒燈庭院不勝寒。", "柳條弄色政爾好，梅蘂飄香殊未闌。", "便似落花飛絮去，直疑春事併衰殘。"]'),
('2fe25c46-37f0-44ed-9b80-1b9726b12ca9','寒食只旬日間風雨不已','曾幾','宋','宋诗','song-poetry','','[]','年光胡不少留連，熟食清明又眼前。',64,'全唐诗/poet.song.94000.json','["年光胡不少留連，熟食清明又眼前。", "敢望深宫傳蠟燭，可堪小市禁炊煙。", "滿城風雨無杯酒，故國松楸欠紙錢。", "老病心情冷時節，只將書策替幽禪。"]'),
('8969a506-f517-4ee0-9399-ebe3c4890f46','寒食與客遊東湖','曾幾','宋','宋诗','song-poetry','','[]','官曹顔狀滿塵埃，負郭陂湖眼爲開。',64,'全唐诗/poet.song.94000.json','["官曹顔狀滿塵埃，負郭陂湖眼爲開。", "春色少留如過客，賞心多病只寒灰。", "黄童白叟喜相告，皁蓋朱幡能一來。", "日暮遊人歸去盡，沙頭鷗鷺與徘徊。"]'),
('b9f409d1-80fd-4aea-93a6-c642cd2222c6','久雨','曾幾','宋','宋诗','song-poetry','','[]','誰言春雨散如絲，一月垂空似綆縻。',64,'全唐诗/poet.song.94000.json','["誰言春雨散如絲，一月垂空似綆縻。", "雲去雲來何日了，花開花落不曾知。", "直愁排蕩根荄盡，安用栽培桃李爲。", "政恐東君不無意，十分姸暖乞酴釄。"]'),
('c285e501-eef2-477a-a116-5f4eaeabfebd','上方','曾幾','宋','宋诗','song-poetry','','[]','前朝蘭若舊聞名，絕頂禪房日月鄰。',64,'全唐诗/poet.song.94000.json','["前朝蘭若舊聞名，絕頂禪房日月鄰。", "木潤山輝應有物，錫飛杯渡不無神。", "郊坰行去僅百里，郡郭往來今十春。", "未踏青雲梯一級，會當齊侶箇中人。"]'),
('b204503d-5061-467e-8b5a-9632d0894643','遊姑蘇張氏園二首  其一','曾幾','宋','宋诗','song-poetry','','[]','郭內名園舊所聞，扶攜老稺及良辰。',64,'全唐诗/poet.song.94000.json','["郭內名園舊所聞，扶攜老稺及良辰。", "重重碧樹深留客，一一華堂極可人。", "綠暗池塘初破夏，清和時節尙關春。", "憑誰說與滄浪水，早晚芒鞋去問津。"]'),
('0b9655cf-cada-4c31-876d-940ddcf2a339','遊姑蘇張氏園二首  其二','曾幾','宋','宋诗','song-poetry','','[]','雨近黄梅細不聞，破窗夜夜看星辰。',64,'全唐诗/poet.song.94000.json','["雨近黄梅細不聞，破窗夜夜看星辰。", "園林如許不行樂，魚鳥有知應笑人。", "盛喜晴天容卜晝，絕憐小塢解藏春。", "何妨著我閑田地，坐看垂楊夾廣津。"]'),
('bcbb9ac1-c86b-442a-8abb-ca62142a2541','遊橋南竹園','曾幾','宋','宋诗','song-poetry','','[]','杖屨橋南訪此君，别君安否斷知聞。',64,'全唐诗/poet.song.94000.json','["杖屨橋南訪此君，别君安否斷知聞。", "苦遭積雨來爲祟，政得新晴爲解紛。", "直幹萬餘森碧玉，高標一半入青雲。", "人言歳暮於吾子，踏雪相看未當勤。"]'),
('202ea7ef-8b77-40ae-a9e9-17c5e0bce9e2','遊滄浪亭詩','曾幾','宋','宋诗','song-poetry','','[]','丘壑園林得我驚，茲遊便足了餘生。',64,'全唐诗/poet.song.94000.json','["丘壑園林得我驚，茲遊便足了餘生。", "飛來嶓冢横空翠，流出滄浪徹底清。", "探討不遺幽士力，招邀難得主人情。", "波間漁父還知否，已挂朝冠不濯纓。"]'),
('d99a68a2-4470-464f-9947-221deb8550e1','遊虎丘','曾幾','宋','宋诗','song-poetry','','[]','誰能竟日把書看，蕩槳扶笻十里間。',64,'全唐诗/poet.song.94000.json','["誰能竟日把書看，蕩槳扶笻十里間。", "未辦深藏豹林谷，不妨時到虎丘山。", "秋來千頃境絕麗，老矣北窗人極閑。", "忽見題名在塵壁，餘生那得許堅頑。"]'),
('18e9d227-f8d8-4fd7-8860-82b1f1f61b7d','過松江','曾幾','宋','宋诗','song-poetry','','[]','家在朱簾畫舫中，今朝誤入水精宫。',64,'全唐诗/poet.song.94000.json','["家在朱簾畫舫中，今朝誤入水精宫。", "江澄不起無風浪，天遠長垂未霽虹。", "酒熟杯盤供雪鱠，詩成島嶼落霜楓。", "帆來帆去何曾歇，萬頃煙波屬釣翁。"]'),
('53a52f48-767c-427b-a015-98d1bb02b93b','信衢道中溪流不通全家遵陸','曾幾','宋','宋诗','song-poetry','','[]','客情厭楚卻思吳，白鷺汀洲政起予。',64,'全唐诗/poet.song.94000.json','["客情厭楚卻思吳，白鷺汀洲政起予。", "渴雨溪流妨進艇，得晴山路稱騎驢。", "滿林霜著春相似，半嶺雲横雪不如。", "匹馬四方男子事，饒陽況不是吾廬。"]'),
('62d176ad-fd8d-4f97-86ec-af642f04a0fa','風月堂二首  其一','曾幾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖地僻少人知，隱吏官曹占作池。',64,'全唐诗/poet.song.94000.json','["西湖地僻少人知，隱吏官曹占作池。", "浩蕩芙蕖風過夜，扶疏楊柳月明時。", "雖多不用一錢買，縱少足供千首詩。", "但使尊中深貯此，巵刀細薄可無饑。"]'),
('612e3f13-13ca-40c7-bf5c-554a8aca1560','風月堂二首  其二','曾幾','宋','宋诗','song-poetry','','[]','青羅熨鏡正揩磨，上有虛堂發興多。',64,'全唐诗/poet.song.94000.json','["青羅熨鏡正揩磨，上有虛堂發興多。", "大熱端能排酷吏，廣寒只合在嫦娥。", "又成畫舫珠簾去，可奈紅妝翠蓋何。", "縱使曲肱無别夢，一尊風月弄婆娑。"]'),
('0d038791-4282-40ed-9681-ad80369ed0e2','即事','曾幾','宋','宋诗','song-poetry','','[]','野寺山家兩寂然，小窗下有白頭禪。',64,'全唐诗/poet.song.94000.json','["野寺山家兩寂然，小窗下有白頭禪。", "微風不動爐煙直，永日方中樹影圓。", "隱几讀書長竟夕，閉門覓句可忘年。", "幸無駟馬高車客，觸忤幽人到眼邊。"]'),
('12a1850e-3e44-4cf6-bbaf-e94edafe9cdd','出嶺','曾幾','宋','宋诗','song-poetry','','[]','乞得身閑又禦魑，干戈瘴癘兩危機。',64,'全唐诗/poet.song.94000.json','["乞得身閑又禦魑，干戈瘴癘兩危機。", "三年似涉新冰過，十口今持舊璧歸。", "天靜不憂鴻北向，月明休詠鵲南飛。", "只應黄帽青鞋底，城郭人民有是非。"]'),
('e4a0d0fc-cffa-44ee-92ec-bb602fd673ba','詠城居','曾幾','宋','宋诗','song-poetry','','[]','盤碧棲寒結露居，虛封水戶食芙蕖。',64,'全唐诗/poet.song.94000.json','["盤碧棲寒結露居，虛封水戶食芙蕖。", "錦雲長日來無定，蘿月通宵色有餘。", "靜拂琴書尋密契，時因齋戒具甘蔬。", "門穿藜徑裁塵跡，車馬無煩問廣閭。"]'),
('6e49270e-61f8-4b96-bd2f-7f0abdbf72a7','秋日郊居','曾幾','宋','宋诗','song-poetry','','[]','眼前百種併愁予，風日凄凄野外居。',64,'全唐诗/poet.song.94000.json','["眼前百種併愁予，風日凄凄野外居。", "落雁沙邊水清淺，蛻蟬枝上葉蕭疏。", "一身病著殘光景，盡室貧依古屋廬。", "物色情懷兩岑寂，更無人問客何如。"]'),
('04690fc0-336e-4845-b25b-c0f490f11014','避寇遷居郭內風雨凄然鄭顧道餉酒','曾幾','宋','宋诗','song-poetry','','[]','煙雨昏昏一月梅，全家避賊寄城隈。',64,'全唐诗/poet.song.95000.json','["煙雨昏昏一月梅，全家避賊寄城隈。", "欲尋碧落侍郎去，遽沐青州從事來。", "令我妻孥爭洗盞，想公伯仲政傳杯。", "安能鬰鬰久居此，且傍茶山松徑回。"]'),
('80db9202-fbb5-4fa5-ac59-b82358feb4bf','寓居吳興','曾幾','宋','宋诗','song-poetry','','["\u7231\u56fd"]','相對真成泣楚囚，遂無末策到神州。',64,'全唐诗/poet.song.95000.json','["相對真成泣楚囚，遂無末策到神州。", "但知遶樹如飛鵲，不解營巢似拙鳩。", "江北江南猶斷絕，秋風秋雨敢淹留。", "低回又作荆州夢，落日孤雲始欲愁。"]'),
('f4dcd1b4-3a1d-4a7a-99a7-f0ea22412114','寓廣教寺東軒','曾幾','宋','宋诗','song-poetry','','[]','誰將老境覓菟裘，聊與瞿曇共一丘。',64,'全唐诗/poet.song.95000.json','["誰將老境覓菟裘，聊與瞿曇共一丘。", "青士無多自蕭散，紫君雖小亦風流。", "要須憩寂有茅宇，何以落成惟茗甌。", "穩看林間上番筍，惜無餘地可通幽。"]'),
('107a4a28-19a3-4f36-bb71-d4bb97765457','宜興邵智卿天遠堂','曾幾','宋','宋诗','song-poetry','','[]','目極雲沙靜渺然，邵卿風月過年年。',64,'全唐诗/poet.song.95000.json','["目極雲沙靜渺然，邵卿風月過年年。", "雁行滅沒山横晚，漁艇空濛水接天。", "南國棠陰春寂寂，東風瓜蔓日緜緜。", "問君許作鄰翁否，陽羨溪邊即買田。"]'),
('418155fa-1586-4e3f-821a-4540848eb5ac','發宜興','曾幾','宋','宋诗','song-poetry','','[]','老境垂垂六十年，又將家上鐡頭船。',64,'全唐诗/poet.song.95000.json','["老境垂垂六十年，又將家上鐡頭船。", "客留陽羨秖三月，歸去玉溪無一錢。", "觀水觀山都廢食，聽風聽雨不妨眠。", "從今布襪青鞵夢，不到張公即善權。"]'),
('d335096e-1002-443f-8371-04ee1ce3c7fa','壬戌歳除作明朝六十歳矣','曾幾','宋','宋诗','song-poetry','','[]','禪榻蕭然丈室空，薰銷火冷閉門中。',64,'全唐诗/poet.song.95000.json','["禪榻蕭然丈室空，薰銷火冷閉門中。", "光陰又似燭見跋，學問只如船逆風。", "一歳臨分驚老大，五更相守笑兒童。", "休言四十明朝過，看取霜髯六十翁。"]'),
('3973415a-95d7-49b7-b460-d2dfb7e0cac7','謁靈康廟','曾幾','宋','宋诗','song-poetry','','[]','玉霄峰外海西頭，即是衰翁所領州。',64,'全唐诗/poet.song.95000.json','["玉霄峰外海西頭，即是衰翁所領州。", "雲水茫茫長發興，春山疊疊未生愁。", "舊時英物餘千載，勝地叢祠尙一丘。", "苦雨凄風莫爲崇，與君同樂亦同憂。"]'),
('5e219ac8-a45d-492a-823b-b0202fdc9056','登玉霄亭','曾幾','宋','宋诗','song-poetry','','[]','老荷君恩付赤城，瘦笻扶上玉霄亭。',64,'全唐诗/poet.song.95000.json','["老荷君恩付赤城，瘦笻扶上玉霄亭。", "懸知地接溟溟海，坐見天横兩兩星。", "作賦興公虛想像，謫官司戶實飄零。", "衰翁何幸分符竹，一覽東吳未了青。"]'),
('96477087-0769-48ca-90bb-c66c44ca7592','竹軒小睡','曾幾','宋','宋诗','song-poetry','','[]','好竹迷時手自栽，一軒寒碧謝塵埃。',64,'全唐诗/poet.song.95000.json','["好竹迷時手自栽，一軒寒碧謝塵埃。", "清風政爲我輩設，小睡忽從何許來。", "已用官茶麾得去，莫因家釀挽令回。", "呼兒靜掃黄葉徑，吾與此君俱快哉。"]'),
('671a0242-fdea-467e-b74b-d1c93c4e3871','竹軒睡起詩和者既多輒復次韻','曾幾','宋','宋诗','song-poetry','','[]','雨中好竹不難栽，雨後清無一點埃。',64,'全唐诗/poet.song.95000.json','["雨中好竹不難栽，雨後清無一點埃。", "政有賢人林下集，何嘗俗客洞中來。", "稽山老幹應相憶，茂苑新梢未遣回。", "歸去南軒曲肱夢，蔥蔥鬰鬰氣佳哉。"]'),
('8a314214-e519-4472-bf75-287d6768f986','曾表勳畫屏','曾幾','宋','宋诗','song-poetry','','[]','筆端水遠又山長，瀟灑吾宗白面郎。',64,'全唐诗/poet.song.95000.json','["筆端水遠又山長，瀟灑吾宗白面郎。", "薺樹煙中分瑣細，葉舟沙外見微茫。", "不宜朝士聽雞枕，政愜幽人夢蝶牀。", "卻恐非關毫素事，此身元住玉溪旁。"]'),
('46c78686-0f19-4c21-97b9-9b2a256a8c92','程吉老撫幹以英石見遺層疊可愛報之以此','曾幾','宋','宋诗','song-poetry','','[]','几凈窗明丈室間，炷香危坐不開關。',64,'全唐诗/poet.song.95000.json','["几凈窗明丈室間，炷香危坐不開關。", "如何密密深深地，忽有層層疊疊山。", "珍重故人初入手，攜持使我得怡顔。", "從今石友常相對，世上交遊費往還。"]'),
('72faf3fc-289c-4d4c-8e29-012dd5bb11b2','雪後梅花盛開折置燈下','曾幾','宋','宋诗','song-poetry','','[]','滿城桃李望東君，破臘江梅未上春。',64,'全唐诗/poet.song.95000.json','["滿城桃李望東君，破臘江梅未上春。", "窗几數枝逾靜好，園林一雪倍清新。", "已無妙語形容汝，不用幽香觸撥人。", "迨此暇時當舉酒，明朝風雨恐傷神。"]'),
('5a4a884b-66e0-45f5-906a-237f9b8a547c','瓶中梅','曾幾','宋','宋诗','song-poetry','','[]','小窗水冰青琉璃，梅花横斜三四枝。',64,'全唐诗/poet.song.95000.json','["小窗水冰青琉璃，梅花横斜三四枝。", "若非風日不到處，何得色香如許時。", "神情蕭散林下氣，玉雪清瑩閨中姿。", "陶泓毛穎果安用，疏影寫出無聲詩。"]'),
('3c573799-b5bf-4a5b-a75e-cebc4266dacc','返魂梅','曾幾','宋','宋诗','song-poetry','','[]','徑菊庭蘭日夜摧，禪房未合有江梅。',64,'全唐诗/poet.song.95000.json','["徑菊庭蘭日夜摧，禪房未合有江梅。", "香今政作依稀似，花乃能令頃刻開。", "笑說巫陽真浪下，寄聲驛使未須來。", "爲君浮動黄昏月，挽取林逋句法回。"]'),
('74706836-5969-4d77-9037-b041276c47fc','諸人見和返魂梅再次韻','曾幾','宋','宋诗','song-poetry','','[]','蠟炬高花半欲摧，斑斑小雨學黄梅。',64,'全唐诗/poet.song.95000.json','["蠟炬高花半欲摧，斑斑小雨學黄梅。", "有時燕寢香中坐，如夢前村雪裏開。", "披拂故令攜袖滿，横斜便欲映窗來。", "重簾幽戶深深閉，亦恐風飄不得回。"]'),
('9157fa8c-5afb-48a3-b988-d0e0b964fdb9','鄭侍郎折贈白芍藥','曾幾','宋','宋诗','song-poetry','','[]','奇葩天遣殿芳叢，一朵瑤臺月下逢。',64,'全唐诗/poet.song.95000.json','["奇葩天遣殿芳叢，一朵瑤臺月下逢。", "黄遶腰間空自貴，紅潮頰上莫爭穠。", "如何風日許姸暖，更著衣裳能疊重。", "定是揚州玉樓子，略無佳句與形客。"]'),
('09148271-0994-4716-b255-50de161aaf42','曾宏甫分餉洞庭柑','曾幾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','黄柑送似得嘗新，坐我松江震澤濵。',64,'全唐诗/poet.song.95000.json','["黄柑送似得嘗新，坐我松江震澤濵。", "想見霜林三百顆，夢成羅帕一雙珍。", "流泉噴霧真宜酒，带葉連枝絕可人。", "莫向君家樊素口，瓠犀微齼遠山顰。"]'),
('d0cfc196-f667-4c79-8eb8-0ac21634b008','福帥張淵道送荔子','曾幾','宋','宋诗','song-poetry','','[]','豈無重碧實瓶罍，難得輕紅薦一杯。',64,'全唐诗/poet.song.95000.json','["豈無重碧實瓶罍，難得輕紅薦一杯。", "千里人從閩嶺出，三年公送荔枝來。", "玉爲肌骨凉無汗，雲作衣裳皺不開。", "莫訝關情向尤物，厭看綠李與楊梅。"]'),
('1c253ef0-1a3c-4bcc-8d9d-40b55961849a','荔子','曾幾','宋','宋诗','song-poetry','','[]','異方風物鬢成斑，荔子嘗新得破顔。',64,'全唐诗/poet.song.95000.json','["異方風物鬢成斑，荔子嘗新得破顔。", "蘭蕙香浮襟解後，雪冰膚在酒酣間。", "絕知高味傾瑤柱，未覺豐肌病玉環。", "似是看來終不近，寄聲龍目儘追攀。"]'),
('2b1f9961-92b3-4cb0-b7ac-76028275c499','又詠荔子','曾幾','宋','宋诗','song-poetry','','[]','百年中半飽聞渠，名下親承果不虛。',64,'全唐诗/poet.song.95000.json','["百年中半飽聞渠，名下親承果不虛。", "可愛風流元有種，自然富貴乃其餘。", "肯隨妃子紅塵驛，甘伴先生白鶴居。", "可惜不經山谷賞，照紅鴨綠定何如。"]'),
('afa05bd1-9ad3-451f-b322-fe63c2785b28','吳傅朋送惠山泉兩瓶竝所書石刻','曾幾','宋','宋诗','song-poetry','','[]','錫谷寒泉雙玉瓶，故人捐惠意非輕。',64,'全唐诗/poet.song.95000.json','["錫谷寒泉雙玉瓶，故人捐惠意非輕。", "疾風驟雨湯聲作，淡月疏星茗事成。", "新歳頭綱須擊拂，舊時水遞費經營。", "銀鉤蠆尾增奇麗，併得晴窗兩眼明。"]'),
('19211a68-63f8-40d3-bfc1-0745d39e34b4','李相公餉建溪新茗奉寄','曾幾','宋','宋诗','song-poetry','','[]','一書說盡故人情，閩嶺春風入戶庭。',64,'全唐诗/poet.song.95000.json','["一書說盡故人情，閩嶺春風入戶庭。", "碾處曾看眉上白，分時爲見眼中青。", "飯羹正晝成空洞，枕簟通宵失杳冥。", "無奈筆端塵俗在，更呼活火發銅瓶。"]'),
('ce0ad0bc-26fb-48ff-872f-f6766770ac91','鄭顧道招賞瑞香','曾幾','宋','宋诗','song-poetry','','[]','山城底處不春風，未似畱賓鄭驛中。',64,'全唐诗/poet.song.95000.json','["山城底處不春風，未似畱賓鄭驛中。", "家釀篘成玉池水，檻花移得錦薰籠。", "已將故事來招我，不著新詩去惱公。", "從此溪南溪北路，桃蹊一任雨繁紅。"]'),
('7edd696b-d5ba-4470-9284-0e7b916b7c19','得瑞香于四明','曾幾','宋','宋诗','song-poetry','','[]','錦樹團欒海角州，移春檻裏見風流。',64,'全唐诗/poet.song.95000.json','["錦樹團欒海角州，移春檻裏見風流。", "兩三翠蓋張前面，千百香囊綴上頭。", "絕代紅梅相對好，妒人山麝莫來休。", "衰翁若被兒童問，入眼還曾有此不。"]'),
('2b1bb2be-da7e-4e50-af9b-cceade42f40f','張耆年教授置酒官舍環碧散步上園煎桃花茶','曾幾','宋','宋诗','song-poetry','','[]','何許清尊對物華，廣文官舍似僧家。',64,'全唐诗/poet.song.95000.json','["何許清尊對物華，廣文官舍似僧家。", "向人只合供談笑，領客猶能辦咄嗟。", "光動杯盤環碧水，香隨珠履上園花。", "公如不厭過從數，但煮東坡所種茶。"]'),
('8b9e7e68-3202-4ed7-a8a1-0dd146435b6a','郡中禁私釀嚴甚戲作','曾幾','宋','宋诗','song-poetry','','[]','結交歡伯無他腸，小槽竊比顧建康。',64,'全唐诗/poet.song.95000.json','["結交歡伯無他腸，小槽竊比顧建康。", "此身忽墮禁酒國，何路得到無功鄉。", "官酤快甚夏酌水，齋釀愜于冬飲湯。", "客來且復置是事，北焙薦椀春風香。"]'),
('a83bdf5c-4cf4-4332-9d8b-768d4a8d7987','榮茂實侍郎餉家釀','曾幾','宋','宋诗','song-poetry','','[]','風窗雪屋坐昏晨，一老江湖寂寞濱。',64,'全唐诗/poet.song.95000.json','["風窗雪屋坐昏晨，一老江湖寂寞濱。", "解戰充虛惟有酒，絕甘分少不無人。", "交情好在篔簹谷，臘味持來麴米春。", "便覺寒家生暖熱，故知客裏未全貧。"]'),
('42ffa0f2-33c4-4e60-9ecd-7d0b19a681bc','家釀紅酒美甚戲作','曾幾','宋','宋诗','song-poetry','','[]','麴生奇麗乃如許，酒母穠華當若何。',64,'全唐诗/poet.song.95000.json','["麴生奇麗乃如許，酒母穠華當若何。", "向人自作醉時面，遣我寧不蒼顔酡。", "得非琥珀所成就，更有丹砂相盪磨。", "可憐老杜不對汝，但愛引頸舟前鵝。"]'),
('c18b2b1b-bcdb-4f0b-ab67-7767ecdd18b0','食筍','曾幾','宋','宋诗','song-poetry','','[]','花事闌珊竹事初，一番風味殿春蔬。',64,'全唐诗/poet.song.95000.json','["花事闌珊竹事初，一番風味殿春蔬。", "龍蛇戢戢風雷後，虎豹斑斑霧雨餘。", "但使此君常有子，不憂每食歎無魚。", "丁寧下番須留取，障日遮風卻要渠。"]'),
('3b366a27-1081-4d1e-97e1-10c3c21d9872','戲作盆池四于和青堂','曾幾','宋','宋诗','song-poetry','','[]','陂湖春盡水茫茫，收拾波濤入小塘。',64,'全唐诗/poet.song.95000.json','["陂湖春盡水茫茫，收拾波濤入小塘。", "睡起微凉馥荷氣，雨餘斜日麗萍光。", "聊爲堂下龜魚主，少退階前雁鶩行。", "只欠盆行數峰在，併持小樹作青蒼。"]'),
('a23251e9-837b-412c-a506-99826e5e3ceb','秘省避暑抵暮乃出','曾幾','宋','宋诗','song-poetry','','[]','蝸廬何以度袢延，竟日蓬山一洗湔。',64,'全唐诗/poet.song.95000.json','["蝸廬何以度袢延，竟日蓬山一洗湔。", "陰翳樹林無六月，風涼殿閣是諸天。", "政須深隱似玄豹，不用懷歸如杜鵑。", "咄咄逼人牛馬走，夜窗妨我枕書眠。"]'),
('789ac769-a4f8-4452-b77d-1074a6fcbd77','復熱','曾幾','宋','宋诗','song-poetry','','[]','墨雲行雨併成空，突兀彤雲在眼中。',64,'全唐诗/poet.song.95000.json','["墨雲行雨併成空，突兀彤雲在眼中。", "瓜李不禁如許熱，蒲葵能得幾多風。", "通宵看月坐還臥，竟日追凉西復東。", "回首本無寒暑地，聽渠亭午汗珠融。"]'),
('d23120b5-0a1f-4128-99bd-f75250136991','兒輩次復熱詩韻再次韻示之','曾幾','宋','宋诗','song-poetry','','[]','蓐收何在渺層空，三伏炎蒸尙未中。',64,'全唐诗/poet.song.95000.json','["蓐收何在渺層空，三伏炎蒸尙未中。", "況復今宵無好月，不知底處有清風。", "看雲暮暮不爲雨，畏日朝朝還自東。", "憶昔給孤園裏夢，褰裳覓路踏泥融。"]'),
('32b54abf-73d2-4c12-b5d3-67dea52ad4fa','八月十五夜月二首  其一','曾幾','宋','宋诗','song-poetry','','[]','玉露金波不可孤，相瞻今夕定何如。',64,'全唐诗/poet.song.95000.json','["玉露金波不可孤，相瞻今夕定何如。", "氛埃未凈雨湔洗，陰翳小留風掃除。", "丹桂看來元了了，白榆種得許疏疏。", "一杯濁酒非難事，未有新詩報答渠。"]'),
('885b944f-4418-4a2b-9aeb-fc5c2151bc63','八月十五夜月二首  其二','曾幾','宋','宋诗','song-poetry','','[]','雲日晶熒固自佳，幽人有待至昏鴉。',64,'全唐诗/poet.song.95000.json','["雲日晶熒固自佳，幽人有待至昏鴉。", "遠分嵒際松楓樹，復亂洲前蘆荻花。", "曳履商聲憐此老，倚樓長笛問誰家。", "霜螯玉柱姚江上，作意三年醉月華。"]'),
('d7d904d8-67a2-4d3a-9d77-7b60ebd68c16','重陽','曾幾','宋','宋诗','song-poetry','','[]','老去長爭一寸陰，良辰物色負幽襟。',64,'全唐诗/poet.song.95000.json','["老去長爭一寸陰，良辰物色負幽襟。", "中秋素月偏離畢，九日黄花未散金。", "蓓蕾不妨供小摘，茱萸聊復伴孤斟。", "重陽何必今朝是，從此籬邊日訪尋。"]'),
('e2fd39a7-1c7a-48b3-b058-525420969f9c','十月一日','曾幾','宋','宋诗','song-poetry','','[]','屋角羲娥轉兩輪，今朝水帝又司辰。',64,'全唐诗/poet.song.95000.json','["屋角羲娥轉兩輪，今朝水帝又司辰。", "山家嘗稻知良月，野徑尋梅見小春。", "一歳坐看除得盡，百年正與死爲鄰。", "誰能思許無窮事，閉閤開爐但飲醇。"]'),
('f0acb31f-3667-4ec3-b2a8-7504173afd1f','長至日述懷兼寄十七兄','曾幾','宋','宋诗','song-poetry','','[]','老來愈覺白駒忙，眼看重陽又一陽。',64,'全唐诗/poet.song.95000.json','["老來愈覺白駒忙，眼看重陽又一陽。", "心似死灰飛不起，技如寒日短中長。", "厭看賓客空投謁，強對妻孥略舉觴。", "回首山陰酬勸地，應憐鴻雁不成行。"]'),
('7157acc0-d69b-4c0d-8fca-649033e7b782','雪作','曾幾','宋','宋诗','song-poetry','','[]','臥聞微霰卻無聲，起看階前又不能。',64,'全唐诗/poet.song.95000.json','["臥聞微霰卻無聲，起看階前又不能。", "一夜紙窗明似月，多年布被冷于冰。", "履穿過我柴門客，笠重歸來竹院僧。", "三白自佳晴亦好，諸山粉黛見層層。"]'),
('98bfa46d-8f8b-4626-a808-9e5863dd8ab8','雪晴','曾幾','宋','宋诗','song-poetry','','[]','衾裯一夜冷于冰，雪事心知作得成。',64,'全唐诗/poet.song.95000.json','["衾裯一夜冷于冰，雪事心知作得成。", "自起穴窗看不見，卻來攲枕聽無聲。", "下牀走報童心喜，開戶驚呼老眼明。", "晴日垂簷白銀塔，怪奇亦復可憐生。"]'),
('6e2162f4-7762-4a6b-ae2f-7c014db00488','十二月六日大雪','曾幾','宋','宋诗','song-poetry','','[]','薄晚蓬山下直餘，笑看六出點衣裾。',64,'全唐诗/poet.song.95000.json','["薄晚蓬山下直餘，笑看六出點衣裾。", "絮飛簾外無縈絆，花落階前不掃除。", "松鬛垂身全類我，竹頭搶地最憐渠。", "短檠便可捐牆角，剩有窗光映讀書。"]'),
('f580393b-20f1-4d10-8cc0-0349c909e459','歳盡','曾幾','宋','宋诗','song-poetry','','[]','漏箭更籌日夜催，萬牛不挽白駒回。',64,'全唐诗/poet.song.95000.json','["漏箭更籌日夜催，萬牛不挽白駒回。", "梅花雪片歳華盡，萱草柳條春鼎來。", "病裏詩書元不讀，貧中尊俎未嘗開。", "年光似此真虛擲，請以丹心學死灰。"]'),
('c20a73ec-abdb-4d33-93fc-8919b7c7010f','致仕','曾幾','宋','宋诗','song-poetry','','[]','妻孥挽我奉真祠，老子婆娑正坐誰。',64,'全唐诗/poet.song.95000.json','["妻孥挽我奉真祠，老子婆娑正坐誰。", "受祿功無一毫末，休官事有十年遲。", "尚容款曲懸車地，絕勝倉皇易簀時。", "請祝聖人千萬壽，小臣何敢望期頤。"]'),
('df60898f-96b9-46b2-a780-c72b7409e09d','癸未八月十四日至十六夜月色皆佳','曾幾','宋','宋诗','song-poetry','','["\u601d\u4e61", "\u4e2d\u79cb\u8282", "\u8d4f\u6708"]','年年歳歳望中秋，歳歳年年霧雨愁。',64,'全唐诗/poet.song.95000.json','["年年歳歳望中秋，歳歳年年霧雨愁。", "涼月風光三夜好，老夫懷抱一生休。", "明時諒費銀河洗，缺處應須玉斧修。", "京洛胡塵滿人眼，不知能似浙江不。"]'),
('bf471a80-4ef8-46f2-ab3c-1176854a2650','自號在家衲子','曾幾','宋','宋诗','song-poetry','','[]','絕勝人間萬戶侯，不稱俗士不緇流。',64,'全唐诗/poet.song.95000.json','["絕勝人間萬戶侯，不稱俗士不緇流。", "又隨拄杖去行腳，未辦把茅來蓋頭。", "但使宗風嗣龐藴，誰能佛事覺裴休。", "秖應除卻閑名字，一聽人呼作馬牛。"]'),
('5e3f0452-76c4-440c-8b24-e1f2833063d5','題東臯','曾幾','宋','宋诗','song-poetry','','[]','市聲俱不聞，野色良可喜。',24,'全唐诗/poet.song.95000.json','["市聲俱不聞，野色良可喜。", "聽公北宅住，還我東臯子。"]'),
('56b0756b-45f9-489e-a515-548fdbc023ca','西崦','曾幾','宋','宋诗','song-poetry','','[]','一重仍一掩，少有外人知。',24,'全唐诗/poet.song.95000.json','["一重仍一掩，少有外人知。", "杖屨歸來處，斜陽隱半規。"]'),
('d748747b-4c77-481d-8876-49822d6c8733','南埭','曾幾','宋','宋诗','song-poetry','','[]','薫風追晚凉，愛日引朝步。',24,'全唐诗/poet.song.95000.json','["薫風追晚凉，愛日引朝步。", "瘦策與青鞋，應知來往路。"]'),
('bf9b3fae-0547-4754-b0e4-782e8aa99ecb','北垞','曾幾','宋','宋诗','song-poetry','','[]','不謂蕞爾邦，有此巋然宅。',24,'全唐诗/poet.song.95000.json','["不謂蕞爾邦，有此巋然宅。", "江山自比鄰，風月相主客。"]'),
('751f4518-6fd7-4103-a04e-38e83d0cb2c9','松谿','曾幾','宋','宋诗','song-poetry','','[]','不似居城市，澄湖上有松。',24,'全唐诗/poet.song.95000.json','["不似居城市，澄湖上有松。", "日斜人影散，百尺臥蒼龍。"]'),
('147606d3-fdfe-4fcc-81ef-ec7d98c9da9d','竹塢','曾幾','宋','宋诗','song-poetry','','[]','煙雨百餘年，茅茨數間屋。',24,'全唐诗/poet.song.95000.json','["煙雨百餘年，茅茨數間屋。", "中有在家僧，蕭然如此竹。"]'),
('36ab94ed-0625-4120-9bcd-42982bc13c77','梅坡','曾幾','宋','宋诗','song-poetry','','[]','被雪一枝好，令人雙眼明。',24,'全唐诗/poet.song.95000.json','["被雪一枝好，令人雙眼明。", "未須貪結子，對汝不勝清。"]'),
('8fb944eb-4661-493d-927e-8c28679b846a','蘭畹','曾幾','宋','宋诗','song-poetry','','[]','深林以薌名，花木不知數。',24,'全唐诗/poet.song.95000.json','["深林以薌名，花木不知數。", "一點無俗氛，蘭芽在幽處。"]'),
('6d25be26-aee9-438a-805c-d46e9216541c','叢桂','曾幾','宋','宋诗','song-poetry','','[]','行攀叢桂枝，坐息叢桂影。',24,'全唐诗/poet.song.95000.json','["行攀叢桂枝，坐息叢桂影。", "王孫胡不歸，歳晏雪霜冷。"]'),
('7d1fc0fb-c855-41b1-9827-5448423b3e3d','海棠洞','曾幾','宋','宋诗','song-poetry','','[]','玉頰酒潮紅，醉頭扶不舉。',24,'全唐诗/poet.song.95000.json','["玉頰酒潮紅，醉頭扶不舉。", "杜老豈無詩，應爲六丁取。"]'),
('d412a658-801b-4644-a912-4975620aeaed','柔桑陌','曾幾','宋','宋诗','song-poetry','','[]','南陌綠成陰，園林正春老。',24,'全唐诗/poet.song.95000.json','["南陌綠成陰，園林正春老。", "能令蠶事辦，更遣鴞音好。"]'),
('4f1106e2-b6f1-4c32-bfe9-f6d3e9b1122d','梨花原','曾幾','宋','宋诗','song-poetry','','[]','酒渴上安市，甘寒爲解圍。',24,'全唐诗/poet.song.95000.json','["酒渴上安市，甘寒爲解圍。", "鵝兒黄不見，空見鷺鷥飛。"]'),
('9d1757e6-90e5-453a-9717-3a705a7a2fb2','柑子園','曾幾','宋','宋诗','song-poetry','','[]','小摘亂青黄，開嘗馥香氣。',24,'全唐诗/poet.song.95000.json','["小摘亂青黄，開嘗馥香氣。", "持比千戶封，真成敗人意。"]'),
('3be1a2cf-449a-4e3f-b8de-98e3aa66a596','山齋','曾幾','宋','宋诗','song-poetry','','[]','頗知藏曲折，故作小崢嶸。',24,'全唐诗/poet.song.95000.json','["頗知藏曲折，故作小崢嶸。", "一穟香已過，半山雲正横。"]'),
('18c7d892-1b8b-4901-abea-2a41d3bda340','泛宅','曾幾','宋','宋诗','song-poetry','','[]','薌林新賜宅，春水向鷗前。',24,'全唐诗/poet.song.95000.json','["薌林新賜宅，春水向鷗前。", "不是蕭何第，元非范蠡船。"]'),
('c81ab7a6-5165-45e5-b9c0-c8a83294e649','上饒方君小倅官而不婚宦居偏戶間靜無官宦之事舍後梯城而上即棚爲亭盡得溪山之勝名之曰快哉爲作四小詩以快哉此風爲韻  其一','曾幾','宋','宋诗','song-poetry','','[]','簿書苦沈迷，世俗嗟迫隘。',24,'全唐诗/poet.song.95000.json','["簿書苦沈迷，世俗嗟迫隘。", "不如溪山上，風至取一快。"]'),
('c8893b66-6521-4670-beb5-eb92617525ec','上饒方君小倅官而不婚宦居偏戶間靜無官宦之事舍後梯城而上即棚爲亭盡得溪山之勝名之曰快哉爲作四小詩以快哉此風爲韻  其二','曾幾','宋','宋诗','song-poetry','','[]','掾曹官事了，載取麴生來。',24,'全唐诗/poet.song.95000.json','["掾曹官事了，載取麴生來。", "得酒且歡喜，俗氛安在哉。"]'),
('fce3a302-4a43-4c40-a62d-68db62f336dd','上饒方君小倅官而不婚宦居偏戶間靜無官宦之事舍後梯城而上即棚爲亭盡得溪山之勝名之曰快哉爲作四小詩以快哉此風爲韻  其三','曾幾','宋','宋诗','song-poetry','','[]','從容吏隱間，游戲僧俗裏。',24,'全唐诗/poet.song.95000.json','["從容吏隱間，游戲僧俗裏。", "孤月浪中翻，吾心正如此。"]'),
('91e513c2-6d9d-4a1c-844e-208eb66717d0','上饒方君小倅官而不婚宦居偏戶間靜無官宦之事舍後梯城而上即棚爲亭盡得溪山之勝名之曰快哉爲作四小詩以快哉此風爲韻  其四','曾幾','宋','宋诗','song-poetry','','[]','偪仄何偪仄，官居塵土中。',24,'全唐诗/poet.song.95000.json','["偪仄何偪仄，官居塵土中。", "高城與隔盡，惟有一溪風。"]'),
('d4ddb50d-8da8-428b-952a-b77b587134c3','遺直堂  其一','曾幾','宋','宋诗','song-poetry','','[]','三孔吾渭陽，猶及見仲叔。',24,'全唐诗/poet.song.95000.json','["三孔吾渭陽，猶及見仲叔。", "堂堂舍人公，再拜但喬木。"]'),
('7150b71f-d016-4d87-abef-1550fdf73bfb','遺直堂  其二','曾幾','宋','宋诗','song-poetry','','[]','長身一庭中，勁氣九霄上。',24,'全唐诗/poet.song.95000.json','["長身一庭中，勁氣九霄上。", "思公立朝時，澟澟不可向。"]'),
('beec4a4e-e17a-4846-a5d2-f6576bb16ceb','遺直堂  其三','曾幾','宋','宋诗','song-poetry','','[]','策登董相科，賦作長卿語。',24,'全唐诗/poet.song.95000.json','["策登董相科，賦作長卿語。", "劉牢出外甥，愧我不如古。"]'),
('529a9991-2f85-45df-b2c5-870e288304aa','遺直堂  其四','曾幾','宋','宋诗','song-poetry','','[]','老柏蜀人愛，甘棠召南思。',24,'全唐诗/poet.song.95000.json','["老柏蜀人愛，甘棠召南思。", "領客清樾下，作詩詠歌之。"]'),
('f95cfafb-f797-471d-a6ff-6c656dbde913','遺直堂  其五','曾幾','宋','宋诗','song-poetry','','[]','元祐幾閱歳，諸公一無遺。',24,'全唐诗/poet.song.95000.json','["元祐幾閱歳，諸公一無遺。", "吾舅典型在，神明力扶持。"]'),
('62756fa9-208c-4f52-aea3-d07a6ee7c10f','遺直堂  其六','曾幾','宋','宋诗','song-poetry','','[]','柏葉松其身，在時公手植。',24,'全唐诗/poet.song.95000.json','["柏葉松其身，在時公手植。", "雜樹誰所栽，一錢初不直。"]'),
('3a741fd9-1699-4c98-9f4b-51bf45f34f94','同官皆和復次韻  其一','曾幾','宋','宋诗','song-poetry','','[]','蒼官可長雄，餘子皆季叔。',24,'全唐诗/poet.song.95000.json','["蒼官可長雄，餘子皆季叔。", "所以吾外家，深栽後彫木。"]'),
('953f305b-7ad7-41bd-a4bd-bdf1f2f7774c','同官皆和復次韻  其二','曾幾','宋','宋诗','song-poetry','','[]','高標何許看，小閣有時上。',24,'全唐诗/poet.song.95000.json','["高標何許看，小閣有時上。", "烈風知人懷，柯葉盡西向。"]'),
('a522e4b3-ec0f-4510-a3a7-ad6644694b09','同官皆和復次韻  其三','曾幾','宋','宋诗','song-poetry','','[]','孔父昔所遊，父老不能語。',24,'全唐诗/poet.song.95000.json','["孔父昔所遊，父老不能語。", "文章翠珉上，如此樹高古。"]'),
('3223abdb-2b84-4586-be51-72a78d6fa143','同官皆和復次韻  其四','曾幾','宋','宋诗','song-poetry','','[]','寂寞西州路，淒凉渭陽思。',24,'全唐诗/poet.song.95000.json','["寂寞西州路，淒凉渭陽思。", "敢不酷似舅，蒼官實臨之。"]'),
('94ab4a00-6e88-420e-9b0c-680322a117b7','同官皆和復次韻  其五','曾幾','宋','宋诗','song-poetry','','[]','大廈要直木，郢斤棄如遺。',24,'全唐诗/poet.song.95000.json','["大廈要直木，郢斤棄如遺。", "一朝諫省上，王魏不支持。"]'),
('3059aa94-cc3b-4a07-a9c6-1a595914557b','同官皆和復次韻  其六','曾幾','宋','宋诗','song-poetry','','[]','華屋落山丘，悲歌詠曹植。',24,'全唐诗/poet.song.95000.json','["華屋落山丘，悲歌詠曹植。", "故有主林神，百年依正直。"]'),
('d3d8e8e8-c83b-496e-ae3d-1be9dc1f6fca','玉井','曾幾','宋','宋诗','song-poetry','','[]','茗飲貴石泉，江流亦其亞。',24,'全唐诗/poet.song.95000.json','["茗飲貴石泉，江流亦其亞。", "甘寒如此井，未肯出汝下。"]'),
('2bb82e18-8ae5-409f-8b63-1e6e3a32ab42','碧蘆潨','曾幾','宋','宋诗','song-poetry','','[]','春風桃李蹊，學語鳥相喚。',24,'全唐诗/poet.song.95000.json','["春風桃李蹊，學語鳥相喚。", "不可無寒蘆，汀洲下鳧雁。"]'),
('8af53306-ddc5-4c20-bd9d-bd2dd72553af','通幽花徑','曾幾','宋','宋诗','song-poetry','','[]','一徑夾青葱，無人到幽處。',24,'全唐诗/poet.song.95000.json','["一徑夾青葱，無人到幽處。", "花發曉鶯啼，欣然得佳趣。"]'),
('9a29d0e4-5d3c-4f1f-8dc3-08d99b0aa5f7','虎川','曾幾','宋','宋诗','song-poetry','','[]','嘯壑有於菟，吹波作奇字。',24,'全唐诗/poet.song.95000.json','["嘯壑有於菟，吹波作奇字。", "川上雪髯翁，文章政相似。"]'),
('88f06463-add2-4454-86b3-413e2dfa4333','放魚磯','曾幾','宋','宋诗','song-poetry','','[]','一絲公不掛，釣餌也憐渠。',24,'全唐诗/poet.song.95000.json','["一絲公不掛，釣餌也憐渠。", "舊日垂竿地，臨流只放魚。"]'),
('60bf8e8a-8dcd-4527-96d7-f2e428aa3128','三老亭','曾幾','宋','宋诗','song-poetry','','[]','華髪累朝人，蒼髯幾時樹。',24,'全唐诗/poet.song.95000.json','["華髪累朝人，蒼髯幾時樹。", "政恐郢斤尋，明堂要材具。"]'),
('0a435ed8-6e68-43e7-a7b0-d11ad976bd91','題摘蔬亭','曾幾','宋','宋诗','song-poetry','','[]','幽畦小雨餘，一一錦繡段。',24,'全唐诗/poet.song.95000.json','["幽畦小雨餘，一一錦繡段。", "春日細春盤，懸知咄嗟辦。"]'),
