('55bf8bbe-cc53-4a55-8ca1-14773bb14f5b','荔子六言','曾幾','宋','宋诗','song-poetry','','[]','蕉葉定成噲伍，梅花應愧盧前。',28,'全唐诗/poet.song.95000.json','["蕉葉定成噲伍，梅花應愧盧前。", "金谷危樓魂斷，白州舊井名傳。"]'),
('995e51de-4437-4985-8811-7a83299edae6','絕句','曾幾','宋','宋诗','song-poetry','','[]','自公退食入僧定，心與香字俱寒灰。',32,'全唐诗/poet.song.95000.json','["自公退食入僧定，心與香字俱寒灰。", "小兒了不解人意，正用此時持事來。"]'),
('5921b008-0482-49c0-9210-9199aa4a989c','讀呂居仁舊詩有懷其人作詩寄之','曾幾','宋','宋诗','song-poetry','','[]','學詩如參禪，慎勿參死句。',192,'全唐诗/poet.song.95000.json','["學詩如參禪，慎勿參死句。", "縱橫無不可，乃在歡喜處。", "又如學仙子，辛苦終不遇。", "忽然毛骨換，正用口訣故。", "居仁說活法，大意欲人悟。", "常言古作者，一一從此路。", "豈惟如是說，實亦造佳處。", "其圓如金彈，所向若脫兔。", "風吹春空雲，頃刻多態度。", "鏘然奏琴筑，間以八珍具。", "人誰無口耳，寧不起欣慕。", "一編落吾手，貪讀不能去。", "嘗疑君胸中，食飲但風露。", "經年闕親近，方寸滿塵霧。", "足音何時來，招喚亦云屢。", "賤子當爲君，移家七閩住。"]'),
('67cfffbe-fe54-4737-9239-4b12f49e42a9','剡溪竹紙三首  其一','曾幾','宋','宋诗','song-poetry','','[]','會稽竹箭東南美，來伴陶泓住管城。',32,'全唐诗/poet.song.95000.json','["會稽竹箭東南美，來伴陶泓住管城。", "可惜不逢韓吏部，相從但說楮先生。"]'),
('21c2c9cc-f1ac-47c5-a02a-de9056b61710','剡溪竹紙三首  其二','曾幾','宋','宋诗','song-poetry','','[]','會稽竹箭東南美，化作經黄紙疊層。',32,'全唐诗/poet.song.95000.json','["會稽竹箭東南美，化作經黄紙疊層。", "舊日土毛無用處，剡中老卻一溪藤。"]'),
('151db490-9630-4434-8cbc-2c05cc7ce0ac','剡溪竹紙三首  其三','曾幾','宋','宋诗','song-poetry','','[]','會稽竹箭東南美，研席之間見此君。',32,'全唐诗/poet.song.95000.json','["會稽竹箭東南美，研席之間見此君。", "爲間溪工底方法，殺青書字有前聞。"]'),
('c4638ede-752a-4a93-84e2-c10daff6f3c2','放猿','曾幾','宋','宋诗','song-poetry','','[]','孤猿鎖檻歲年深，放出城南百丈林。',32,'全唐诗/poet.song.95000.json','["孤猿鎖檻歲年深，放出城南百丈林。", "綠水任從聯臂飲，青山不用斷腸吟。"]'),
('ec956631-3245-487a-b12d-4d20f08f0d78','過水東','曾幾','宋','宋诗','song-poetry','','[]','出郭市聲遠，過溪山色多。',48,'全唐诗/poet.song.95000.json','["出郭市聲遠，過溪山色多。", "稻畦春雨足，野水晚迎波。", "客自無軒冕，今誰在澗阿。", "相逢不相識，歸去夢松蘿。"]'),
('4b030cfd-4fbf-4022-aeaa-4f51d4259349','三霄亭和韻','曾幾','宋','宋诗','song-poetry','','[]','新亭崛起最高峰，無數遙岑翠掃空。',64,'全唐诗/poet.song.95000.json','["新亭崛起最高峰，無數遙岑翠掃空。", "恐有謝公留屐齒，爲聞摩詰畫屏風。", "倚江楊柳自高下，照水杏花能白紅。", "正欠渭川千畝竹，清陰分借賴鄰翁。"]'),
('1887a205-29a5-4da3-8346-3f000c786b2b','寄空同山中道士','曾幾','宋','宋诗','song-poetry','','[]','昨夜清霜重，念此山中客。',96,'全唐诗/poet.song.95000.json','["昨夜清霜重，念此山中客。", "落葉聚堆牀，暗蟲吟敗壁。", "泬漻天宇肅，疏林風瑟瑟。", "曳杖掛詩瓢，悠然適所適。", "息心歸冥漠，山深萬籟寂。", "散髪排天闥，叱咤鞭龍脊。", "何時共采藥，相與對晨夕。", "月夜供洪崖，嘯吟鏗金石。"]'),
('6fb729ca-8764-4eb4-a7f2-a62da7dbf331','蟹','曾幾','宋','宋诗','song-poetry','','[]','舊交髯簿久相忘，公子相從獨味長。',32,'全唐诗/poet.song.95000.json','["舊交髯簿久相忘，公子相從獨味長。", "醉死糟丘終不悔，看來端的是無腸。"]'),
('36be3de9-7ef6-4a37-9df7-778b1bb596b3','糟蟹','曾幾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','風味端宜配麯生，無腸公子藉糟成。',64,'全唐诗/poet.song.95000.json','["風味端宜配麯生，無腸公子藉糟成。", "可憐不作空虛腹，尚想能爲郭索行。", "張翰蓴鱸休發興，洞庭蝦蟹可忘情。", "君看醉死真奇事，不受人間五鼎烹。"]'),
('d42751d8-4b6e-4ed9-8b55-4c8d53b15609','錢仲修餉新蟹','曾幾','宋','宋诗','song-poetry','','[]','開奩破殻喜新黄，此物移來所未嘗。',64,'全唐诗/poet.song.95000.json','["開奩破殻喜新黄，此物移來所未嘗。", "一手正宜深把酒，二螯已是飽經霜。", "橫行足使班寅懼，乾死能令瘧鬼亡。", "畢竟爬沙能底事，祇應大嚼慰枯腸。"]'),
('b0080a91-87cf-4136-92ca-34d660dd134b','贈王明清','曾幾','宋','宋诗','song-poetry','','[]','吾宗擇婿得羲之，令子傳家又絕奇。',32,'全唐诗/poet.song.95000.json','["吾宗擇婿得羲之，令子傳家又絕奇。", "甥舅從來多酷似，弟兄如此信難爲。"]'),
('455040db-c382-48a1-9880-03eb470dd624','題意大師房','曾幾','宋','宋诗','song-poetry','','[]','頭白高僧心已灰，石菖蒲長水蕉開。',32,'全唐诗/poet.song.95000.json','["頭白高僧心已灰，石菖蒲長水蕉開。", "莊嚴茗事爐煙起，不用關防俗子來。"]'),
('1546beaf-68ce-4aa4-80a3-0c080a873ad0','長淮有感','曾幾','宋','宋诗','song-poetry','','[]','目送長淮去不回，登臨萬感集層臺。',32,'全唐诗/poet.song.95000.json','["目送長淮去不回，登臨萬感集層臺。", "波間定有隋渠水，曾向大梁城下來。"]'),
('86d2cd9e-0b39-4345-93de-ad307c507433','寄許子禮','曾幾','宋','宋诗','song-poetry','','[]','草堂竹塢閉門中，吏部持身有古風。',64,'全唐诗/poet.song.95000.json','["草堂竹塢閉門中，吏部持身有古風。", "老去一麾還作病，歸來四壁又成空。", "今朝札翰如無恙，舊日詩書卻未窮。", "拭目看君進明德，乃兄事業付天公。"]'),
('c7a9e4b4-9ede-4598-9ae5-d05a8a252e63','贈外甥呂祖謙','曾幾','宋','宋诗','song-poetry','','[]','昔別溪南寺，奇龐總角兒。',48,'全唐诗/poet.song.95000.json','["昔別溪南寺，奇龐總角兒。", "傳聞不好弄，賸喜更能詩。", "絃術真吾道，躬行是汝師。", "掖垣家學在，何以徧參爲。"]'),
('7fc99461-ce88-478d-8f0c-f0e5bc57eee8','將適台州','曾幾','宋','宋诗','song-poetry','','[]','風林何許著驚禽，惟有台州舊所臨。',64,'全唐诗/poet.song.95000.json','["風林何許著驚禽，惟有台州舊所臨。", "避地妻孥雖在眼，藏山文字卻關心。", "維揚大將金城固，建業名臣天槧深。", "說與單于歸去好，長淮邊是殺胡林。"]'),
('50fd2ca7-4100-4083-8c2a-ae74a2886618','冬','曾幾','宋','宋诗','song-poetry','','[]','歲事空餘數行曆，年勞繞得幾篇詩。',48,'全唐诗/poet.song.95000.json','["歲事空餘數行曆，年勞繞得幾篇詩。", "猶慳雪片下彌隴，已放梅花開滿枝。", "便是東風來解凍，春盤生菜屬群兒。"]'),
('f4f19b10-576e-4cf8-8fb9-3ad4c74d2c14','寄空禪師','曾幾','宋','宋诗','song-poetry','','[]','江西句法空公得，一向逃禪挽不回。',32,'全唐诗/poet.song.95000.json','["江西句法空公得，一向逃禪挽不回。", "深密伽陀妙天下，無人知道派中來。"]'),
('40fead16-3539-4577-9ee2-52a92026c7b3','海棠','曾幾','宋','宋诗','song-poetry','','[]','空谷嫣然笑靨開，春風元自蜀山來。',32,'全唐诗/poet.song.95000.json','["空谷嫣然笑靨開，春風元自蜀山來。", "少陵忘卻渾閑事，更有離騷忘卻梅。"]'),
('ed457eb7-d12a-4671-bb87-a536038045e2','水仙花','曾幾','宋','宋诗','song-poetry','','[]','坐令簪一枝，蛾眉淡初掃。',24,'全唐诗/poet.song.95000.json','["坐令簪一枝，蛾眉淡初掃。", "笑弄黄金盃，連臺盤拗倒。"]'),
('e37b6bad-8313-4b82-8d9c-c6455376e277','山礬','曾幾','宋','宋诗','song-poetry','','[]','青雲葉底雪花繁，只與田家插髻鬟。',32,'全唐诗/poet.song.95000.json','["青雲葉底雪花繁，只與田家插髻鬟。", "不枉涪翁初着句，能令大士久開顔。"]'),
('ca3c1bab-1563-4e49-b7c5-a44eb3b1a060','石菖蒲','曾幾','宋','宋诗','song-poetry','','[]','窗明几凈室空虛，盡道幽人一事無。',32,'全唐诗/poet.song.95000.json','["窗明几凈室空虛，盡道幽人一事無。", "莫道幽人無一事，汲泉承露養菖蒲。"]'),
('fee017a7-1905-48ec-9c11-2b708945bb66','芭蕉','曾幾','宋','宋诗','song-poetry','','[]','以此葉陰涼，代彼青瑯玕。',24,'全唐诗/poet.song.95000.json','["以此葉陰涼，代彼青瑯玕。", "但恐本質脆，不堪期歲寒。"]'),
('70ac7b56-bff0-4646-9f72-81da1a65fccb','薺','曾幾','宋','宋诗','song-poetry','','[]','盤餐到野薺，曳杖閑挑根。',36,'全唐诗/poet.song.95000.json','["盤餐到野薺，曳杖閑挑根。", "幽人此味熟，俗子誰知津。", "微物經品題，便作席上珍。"]'),
('59f2c927-a0d3-4400-b800-dee4c5be258e','把酒思閑事二首  其一','曾幾','宋','宋诗','song-poetry','','[]','把酒思閑事，春愁誰最深。',48,'全唐诗/poet.song.95000.json','["把酒思閑事，春愁誰最深。", "乞錢羈客面，落第舉人心。", "月下低眉立，燈前抱膝吟。", "憑君勸一醉，勝與萬黄金。"]'),
('d9204d2e-5c19-41c1-9171-1c2092736c3a','把酒思閑事二首  其二','曾幾','宋','宋诗','song-poetry','','[]','把酒思閑事，春嬌何處多。',48,'全唐诗/poet.song.95000.json','["把酒思閑事，春嬌何處多。", "試鞍新白馬，弄鏡小青娥。", "掌上初教舞，花頭欲按歌。", "憑君勸一醉，勸了又如何。"]'),
('86897647-79c0-4556-8efc-64b1f5582ab3','晚春酒醒尋夢得','曾幾','宋','宋诗','song-poetry','','[]','料合同惆悵，花殘酒亦殘。',48,'全唐诗/poet.song.95000.json','["料合同惆悵，花殘酒亦殘。", "醉心忘老易，醒眼別春難。", "獨出雖慵懶，相逢定喜歡。", "還攜小蠻去，試覓老劉看。"]'),
('09bf1ae7-6551-4913-82bf-69c5f7b19eeb','投壺','曾幾','宋','宋诗','song-poetry','','[]','連朝賜沐吏功休，請以陶壺竹矢投。',64,'全唐诗/poet.song.95000.json','["連朝賜沐吏功休，請以陶壺竹矢投。", "整整斜斜森劍戟，紛紛藉藉委戈矛。", "坐人各自慶多馬，老子不惟輸一籌。", "中否何關興廢事，天公應解笑齊侯。"]'),
('fbec6508-2590-4c7e-a13a-1cb4c850b2f0','投壺全中戲成','曾幾','宋','宋诗','song-poetry','','[]','寸心只在所投中，出手何曾一箭空。',64,'全唐诗/poet.song.95000.json','["寸心只在所投中，出手何曾一箭空。", "不作秋風鋪落葉，端如春草種成叢。", "旁觀詎敢當勍敵，俯拾無勞命短童。", "說與妻孥須辦取，如山酒肉賀全功。"]'),
('6a64edf9-acb4-437e-99a3-7a761e25ec76','次韻陳魯山正字社日同西湖  其一','曾幾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昔在兒童歲，湖山入眼新。',48,'全唐诗/poet.song.95000.json','["昔在兒童歲，湖山入眼新。", "只今餘白髪，何以報青春。", "日暖繁遊子，年豐樂社神。", "諸公勤載酒，四事每參辰。"]'),
('e818ff82-65c3-4a5d-9619-b827c01026cc','次韻陳魯山正字社日同西湖  其二','曾幾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鬢髪垂領白，塵埃迎面紅。',48,'全唐诗/poet.song.95000.json','["鬢髪垂領白，塵埃迎面紅。", "相從林下寸，一洗水邊風。", "寫物詩無敵，蠲愁酒有功。", "夕陽應更好，可惜在城中。"]'),
('135a3ac4-fbc4-4a2f-9388-75564172d881','郡齋偶成','曾幾','宋','宋诗','song-poetry','','[]','臥病江東久，饑驅強作官。',48,'全唐诗/poet.song.95000.json','["臥病江東久，饑驅強作官。", "年豐雙雪鬢，心事一蒲團。", "簾影垂晝寂，竹陰生夏寒。", "無人知老子，於此有餘歡。"]'),
('2ab97215-ade0-4cf2-add7-a9b0f1f4ee12','觀四種梅  其一','曾幾','宋','宋诗','song-poetry','','[]','花信風從底處來，水邊探得一枝開。',32,'全唐诗/poet.song.95000.json','["花信風從底處來，水邊探得一枝開。", "箯輿日日溪南北，看盡江梅看臘梅。"]'),
('6fce3df8-d861-43d5-abd8-72a16ea3dd66','觀四種梅  其二','曾幾','宋','宋诗','song-poetry','','[]','斬新梅蕊破東風，一樹鵝黄一樹紅。',32,'全唐诗/poet.song.95000.json','["斬新梅蕊破東風，一樹鵝黄一樹紅。", "不着鉛華元自好，未妨時世略相同。"]'),
('801fb0ca-c3d2-4f5e-bda8-3c8ce441c3e2','舟中','曾幾','宋','宋诗','song-poetry','','[]','灘聲送我入嚴州，過得州來水漫流。',32,'全唐诗/poet.song.95000.json','["灘聲送我入嚴州，過得州來水漫流。", "一夜好風潮信早，滿船明月荻花秋。"]'),
('b3b091a2-3fec-4920-ac43-ba7a3502de64','江漲','曾幾','宋','宋诗','song-poetry','','[]','霧裏江流欲到天，旅人合眼夢歸船。',32,'全唐诗/poet.song.95000.json','["霧裏江流欲到天，旅人合眼夢歸船。", "雨聲竹屋曉來急，誤喜全家蓬底眠。"]'),
('c48c5169-babc-484d-b5da-7eb777e4fe5d','聞禽聲有感','曾幾','宋','宋诗','song-poetry','','[]','寂寂禪房閉，陰陰夏木繁。',48,'全唐诗/poet.song.95000.json','["寂寂禪房閉，陰陰夏木繁。", "坐聞幽鳥語，勝與俗人言。", "脫袴高低樹，提壺遠近村。", "汝曹知底事，獨與子規論。"]'),
('9cd6a913-88cd-4cd7-a0f6-a8626509088a','雪臺','曾幾','宋','宋诗','song-poetry','','[]','白晝俯層臺，千山萬山月。',24,'全唐诗/poet.song.95000.json','["白晝俯層臺，千山萬山月。", "若不犯高寒，安知此奇絕。"]'),
('c4181307-3a5b-46f9-b266-3c2f572d08fb','有山堂','曾幾','宋','宋诗','song-poetry','','[]','江南家家窗，何處無遠岫。',24,'全唐诗/poet.song.95000.json','["江南家家窗，何處無遠岫。", "唯有謝玄暉，眼中揖其秀。"]'),
('5eab33f2-771c-4357-aac4-a0a029ee9733','歲寒亭','曾幾','宋','宋诗','song-poetry','','[]','飽霜猶鬰葱，立雪故清潤。',24,'全唐诗/poet.song.95000.json','["飽霜猶鬰葱，立雪故清潤。", "下有老成人，持心以相印。"]'),
