('c4135c19-c482-4efc-9e26-24e4474a0713','句  其一四','曾幾','宋','宋诗','song-poetry','','[]','紅皺解羅襦處，清香開玉肌時。',14,'全唐诗/poet.song.95000.json','["紅皺解羅襦處，清香開玉肌時。"]'),
('de901f8a-1fba-4e75-8011-5e591531a43c','句  其一五','曾幾','宋','宋诗','song-poetry','','[]','猩血染羅欣入手，冰肌飲露欲濡唇。',16,'全唐诗/poet.song.95000.json','["猩血染羅欣入手，冰肌飲露欲濡唇。"]'),
('3b2975f1-4890-43f7-b8ff-52e486220bd4','存目','曾幾','宋','宋诗','song-poetry','','[]','詩題：蘆溝橋全詩：輿馬連年東復西，巨鰲雙脇夾青猊。',41,'全唐诗/poet.song.95000.json','["詩題：蘆溝橋全詩：輿馬連年東復西，巨鰲雙脇夾青猊。", "荷旃食肉無非命，憔悴相如不敢題。"]'),
('f390c256-2eac-4d14-b860-01f801a678ee','題淡山巖','盛某','宋','宋诗','song-poetry','','[]','黄公丘壑人，閱遍山水奇。',288,'全唐诗/poet.song.95000.json','["黄公丘壑人，閱遍山水奇。", "晚觀淡巖作，獨許天下稀。", "我初頗未信，及到乃愧之。", "偉茲過奇特，驟睹心驚疑。", "神靈藴幽秘，無乃弗許窺。", "捫苔漸深入，歡愕不自持。", "穹窿但一石，轇轕周四維。", "廣容千人騶，高建五丈旂。", "巨勢裂地軸，虛窗豁天扉。", "森然萬幕張，鬰若曾雲垂。", "危磴過別洞，絕壁浮煙霖。", "幽房瞰窈窕，屏榻如礱治。", "雲霞起坐隅，翠嵐著人衣。", "頓覺從來山，榛莽翳土埠。", "化石事茫昧，驅蛇知是非。", "井臼儼遺處，芝田留舊畦。", "云昔隱仙宅，此理固亦宜。", "元柳跡不到，隱顯當有時。", "憶我半紀前，已與茲山期。", "了然蘭臺夢，宛渡瀟江湄。", "今來恍如昨，始悟非人爲。", "寧嗟擯幽邈，持爾足自怡。", "無窮軒冕客，有幾能遊斯。", "天應出此境，以慰遐荒悲。"]'),
('743b6f42-4680-47b7-86c7-6a881a4dd01f','句','黄琚','宋','宋诗','song-poetry','','[]','長虹吸盡兩潮水，赤鑑粧成萬頃田。',16,'全唐诗/poet.song.95000.json','["長虹吸盡兩潮水，赤鑑粧成萬頃田。"]'),
('80adcc91-036e-41ad-bd89-55e3326d41b5','定光南安巖','方開之','宋','宋诗','song-poetry','','[]','天下名山饒洞穴，不似南安最奇絕。',48,'全唐诗/poet.song.95000.json','["天下名山饒洞穴，不似南安最奇絕。", "一峰突兀上干天，十二子孫旁就列。", "上有虛窗透碧霄，夜分明月歸巖腹。"]'),
('2bd26418-b8db-4562-bb23-decdaa6697d0','觀高郵寺壁曹仁熙畫水','張表臣','宋','宋诗','song-poetry','','[]','曹生畫手信有神，毫端風雨生奫沄。',224,'全唐诗/poet.song.95000.json','["曹生畫手信有神，毫端風雨生奫沄。", "波濤不合來翻屋，鮫鰐何須欲噬人。", "湯湯此水勢方割，陽侯鬰怒馮夷搏。", "鼉擲鯨呿海岳驚，霧塞雲昏光景薄。", "開元將軍愛驊騮，拳奇滅沒隘九州。", "時危此物豈易得，寫此尚可銷人憂。", "末有乃孫畫乃水，逋客見之心欲死。", "雷奔電擊走中原，魚怖龍愁寧忍視。", "先生道眼高崑崙，聊將妙語破迷津。", "中流險絕待舟楫，四海浩蕩須經綸。", "我生甘作淮海客，身脫垂涎頭雪白。", "驚心未定畏漰湍，欲覓平波泛家宅。", "此身端的老江湖，雨笠煙蓑是所圖。", "他年但飽揚州米，今日寧論甓社珠。"]'),
('f105349b-79e5-4a40-87d0-e8a4945b35d3','金陵鳳凰臺','張表臣','宋','宋诗','song-poetry','','[]','騎鯨仙伯已凌凌，奈爾三山二水何。',32,'全唐诗/poet.song.95000.json','["騎鯨仙伯已凌凌，奈爾三山二水何。", "地老天荒成脈脈，鳳凰臺上獨來過。"]'),
('c91abca8-2c39-4fa3-876c-82ad80831374','題睢陽雙廟二首  其一','張表臣','宋','宋诗','song-poetry','','[]','張許昭鴻烈，南雷賈共靈。',48,'全唐诗/poet.song.95000.json','["張許昭鴻烈，南雷賈共靈。", "無瑕雙白璧，有曜五華星。", "懷哲音容在，傷時涕淚零。", "向來丹鳳闕，猶带犬羊腥。"]'),
('fa353594-0c86-405e-a155-d43304fa06b1','題睢陽雙廟二首  其二','張表臣','宋','宋诗','song-poetry','','[]','漁陽哭騎滿關東，百戰孤城挫賊鋒。',32,'全唐诗/poet.song.95000.json','["漁陽哭騎滿關東，百戰孤城挫賊鋒。", "唐室興亡繫公等，九原可作更誰從。"]'),
('b7336009-be69-48e9-941a-34cd2c82c474','和陳叔易就晁以道求長松','張表臣','宋','宋诗','song-poetry','','[]','暫隱嵩高六六峰，未乘雲氣御飛龍。',32,'全唐诗/poet.song.95000.json','["暫隱嵩高六六峰，未乘雲氣御飛龍。", "自餐白石求黄石，更採長松寄赤松。"]'),
('b4e087cc-0664-43b9-b27e-c4c88be6a543','和楊大年館直詩','張表臣','宋','宋诗','song-poetry','','[]','翰林歷歷侵華蓋，禁掖明明侍紫微。',32,'全唐诗/poet.song.95000.json','["翰林歷歷侵華蓋，禁掖明明侍紫微。", "自昔詞臣最清切，帝宸高拱借光輝。"]'),
('e6d16869-659f-4529-9d04-49f90711e414','傷胡少汲兵敗','張表臣','宋','宋诗','song-poetry','','[]','還將他年重，作師此日難。',24,'全唐诗/poet.song.95000.json','["還將他年重，作師此日難。", "傷心閔東道，白首戴南冠。"]'),
('cef6b2f0-44df-4191-841b-c9fc11ba0350','詩一首','張表臣','宋','宋诗','song-poetry','','[]','射飛何必捐金彈，抵鵲虛煩用夜光。',32,'全唐诗/poet.song.95000.json','["射飛何必捐金彈，抵鵲虛煩用夜光。", "切玉昆吾寧刺豕，斷蛟干越豈刲羊。"]'),
('05e7aeeb-6a23-4bd4-a13b-9350ddb975b1','八陳圖','張表臣','宋','宋诗','song-poetry','','[]','八陳功成妙用藏，木牛流馬法俱亡。',32,'全唐诗/poet.song.95000.json','["八陳功成妙用藏，木牛流馬法俱亡。", "後來識得常山勢，縱有桓溫恐未詳。"]'),
('8dde7598-2d34-4deb-b608-1596f8566474','琵琶','張表臣','宋','宋诗','song-poetry','','[]','白鴿潛來入紫槽，朱鸞飛去唳青霄。',64,'全唐诗/poet.song.95000.json','["白鴿潛來入紫槽，朱鸞飛去唳青霄。", "江邊塞上情何限，瀛府霓裳曲再調。", "漫道靈妃鼓瑤瑟，虛傳仙子弄雲璈。", "小憐破得春風恨，何似今宵月正高。"]'),
('f6a7eed2-9fcb-4427-9db4-83929de67a33','青田壺碧筩酒','張表臣','宋','宋诗','song-poetry','','[]','醸憶青田核，觴宜碧藕筩。',24,'全唐诗/poet.song.95000.json','["醸憶青田核，觴宜碧藕筩。", "直須千日醉，莫放一杯空。"]'),
('093c23fa-72e3-4d32-927b-fbef47373573','婺州山中','張表臣','宋','宋诗','song-poetry','','[]','作畎捉簷卸，呼田欸乃儂。',24,'全唐诗/poet.song.95000.json','["作畎捉簷卸，呼田欸乃儂。", "山塘莫車水，梅雨正分龍。"]'),
('bc272823-a9ee-41f5-af95-1d00cde979e2','句  其一','張表臣','宋','宋诗','song-poetry','','[]','已乘雲氣翳鳳麟，六百餘歲無斯民。',48,'全唐诗/poet.song.95000.json','["已乘雲氣翳鳳麟，六百餘歲無斯民。", "想像璧月何當親，虎頭摩詰俱泯淪。", "誰其畫者陸仲仁，遠紹乃祖高無倫。"]'),
('76153854-64c9-4d9f-81bd-403713d931a1','句  其二','張表臣','宋','宋诗','song-poetry','','[]','雲移鳥滅沒，風霽蝶飛翻。',12,'全唐诗/poet.song.95000.json','["雲移鳥滅沒，風霽蝶飛翻。"]'),
('ba69a39a-c345-46a1-8cd1-8a9e4a688c70','句  其三','張表臣','宋','宋诗','song-poetry','','[]','采玉應求破山劍，探珠仍遣水精奴。',16,'全唐诗/poet.song.95000.json','["采玉應求破山劍，探珠仍遣水精奴。"]'),
('7e553ffc-a205-491b-ae52-ae2f7e4e956f','句  其四','張表臣','宋','宋诗','song-poetry','','[]','蛇蛟已盡定飛去，雷電欻驚重下來。',16,'全唐诗/poet.song.95000.json','["蛇蛟已盡定飛去，雷電欻驚重下來。"]'),
('e9e280cd-d23a-4e4f-ad52-97b062a5ee8e','句  其五','張表臣','宋','宋诗','song-poetry','','[]','牀弩天誅韓闥覽，劍鋒神助宋將軍。',16,'全唐诗/poet.song.95000.json','["牀弩天誅韓闥覽，劍鋒神助宋將軍。"]'),
('e42abc95-f9ba-4a93-9ca5-08155d761538','句  其六','張表臣','宋','宋诗','song-poetry','','[]','碧藕連根絲不斷，紅蕖著子薏何多。',16,'全唐诗/poet.song.95000.json','["碧藕連根絲不斷，紅蕖著子薏何多。"]'),
('31dac5d9-3494-438a-a957-2976bc6e58a0','宿青綏鋪','童蒙','宋','宋诗','song-poetry','','[]','跋涉千千里，我行亦良勤。',144,'全唐诗/poet.song.95000.json','["跋涉千千里，我行亦良勤。", "戒途桂林臘，解轡盱水春。", "赤石照病眼，紅泉濯征塵。", "麻姑顧我笑，問別何所因。", "憶昨罷清江，中興初甲寅。", "去家十五年，一掃先君墳。", "未及親舊語，遽隨犬羊奔。", "幕燕遂如客，月鵲無安村。", "得官嶠南州，欲訪出世人。", "禦虎信有命，生還聊一欣。", "此事姑置之，既往安足論。", "山神似相憐，靜掃群峰雲。"]'),
('090e1dd3-b94b-4e22-b143-ad63143b7e6b','句','虞祺','宋','宋诗','song-poetry','','[]','留得甘泉作霖雨，白雲來往自無心。',16,'全唐诗/poet.song.95000.json','["留得甘泉作霖雨，白雲來往自無心。"]'),
('5eb96602-dd5c-48ff-89c1-d7a8ae17c856','初夏','侯延慶','宋','宋诗','song-poetry','','[]','猥山狹路蔚桑麻，籬落春歸尚有花。',32,'全唐诗/poet.song.95000.json','["猥山狹路蔚桑麻，籬落春歸尚有花。", "雨漲小溪蒲劍短，風回橫隴麥旗斜。"]'),
('1c2796d8-9e8d-4530-9ec7-e9ba15cbbbd7','次韻時從事桃花菊','侯延慶','宋','宋诗','song-poetry','','[]','霜郊百草半青黄，寒菊偷春作艷粧。',64,'全唐诗/poet.song.95000.json','["霜郊百草半青黄，寒菊偷春作艷粧。", "灼灼似誇籬下客，夭夭欲伴禁中郎。", "玄都道士聞須種，彭澤先生見定狂。", "莫信化工欺世俗，且將一笑薦彫觴。"]'),
('1d04dac2-775b-4129-9a37-5f9b2aef0356','詩一首','侯延慶','宋','宋诗','song-poetry','','[]','雲來萬山動，雲去天一色。',24,'全唐诗/poet.song.95000.json','["雲來萬山動，雲去天一色。", "長嘯兩三聲，天高秋月白。"]'),
