('5e1bdef0-4820-4d8e-96c5-78d3aa7a5dba','句  其三','葉廷珪','宋','宋诗','song-poetry','','[]','幾多雁鶩行間吏，衙退頻來禮釋迦。',16,'全唐诗/poet.song.95000.json','["幾多雁鶩行間吏，衙退頻來禮釋迦。"]'),
('c33e50a0-d0fa-42a9-8262-0f2ec8e3745a','句  其四','葉廷珪','宋','宋诗','song-poetry','','[]','戍兵數有流星遞，元白詩筒幸寄將。',16,'全唐诗/poet.song.95000.json','["戍兵數有流星遞，元白詩筒幸寄將。"]'),
('dfb5a5ef-3b74-485f-8de1-ca2228bb8baf','句  其五','葉廷珪','宋','宋诗','song-poetry','','[]','道旁曾種萬株松。',8,'全唐诗/poet.song.95000.json','["道旁曾種萬株松。"]'),
('3a072ae9-ee5c-43c1-8a29-e810a9afa62c','句  其六','葉廷珪','宋','宋诗','song-poetry','','[]','名字惟因佛書見，根苗應逐賈胡來。',16,'全唐诗/poet.song.95000.json','["名字惟因佛書見，根苗應逐賈胡來。"]'),
('eb5c34e9-501b-4bf1-b2f5-90d5a114c81a','自題畫像','蔡樞','宋','宋诗','song-poetry','','[]','平生陋質寫難真，畫史揮毫妙入神。',64,'全唐诗/poet.song.95000.json','["平生陋質寫難真，畫史揮毫妙入神。", "瘦似休文寧復健，寒如東野故應貧。", "塵埃自笑雙蓬鬢，泡影俄驚兩幻身。", "從此山林皆獨往，定無勳業上麒麟。"]'),
('621e0ea3-a616-4ccc-8256-3e3b12f747a2','漾花池','劉無極','宋','宋诗','song-poetry','','[]','一池春水綠如苔，水上新紅取次開。',32,'全唐诗/poet.song.95000.json','["一池春水綠如苔，水上新紅取次開。", "閑倚東風看魚樂，動搖花片卻驚猜。"]'),
('ec72e398-762c-4ca7-9b4f-771ae2438499','句','陳紆','宋','宋诗','song-poetry','','[]','舍法得才傳黼扆，古人馳譽重賢關。',16,'全唐诗/poet.song.95000.json','["舍法得才傳黼扆，古人馳譽重賢關。"]'),
('a990dfa9-1222-49f3-8778-3ecc5cdc091a','賦新繁周表權如詔亭','陳昂','宋','宋诗','song-poetry','','[]','封典寵巖穴，褒言華日星。',72,'全唐诗/poet.song.95000.json','["封典寵巖穴，褒言華日星。", "其誰盡如詔，何暇更名亭。", "公昔善教子，家傳惟治經。", "當年雲榜揭，今日璽書形。", "籍已貴同省，坐應嘗隔屏。", "公餘褫簪綍，綵服戲家庭。"]'),
('54ff0fdd-2ee3-4e04-a64c-ca995899db5a','句','陳博古','宋','宋诗','song-poetry','','[]','門外海濤奔鐵騎，檻前山背擁金鰲。',16,'全唐诗/poet.song.95000.json','["門外海濤奔鐵騎，檻前山背擁金鰲。"]'),
('6f70373b-5286-4134-b676-c6ae1ab1fe8b','剛顯廟','鄭昂','宋','宋诗','song-poetry','','[]','公昔隱居烏石岡，老觀禪師同道場。',208,'全唐诗/poet.song.95000.json','["公昔隱居烏石岡，老觀禪師同道場。", "法主懶安共徜徉，李薛咨參互擊揚。", "擺脫利欲心清涼，是以能全此至剛。", "黄巢兵亂來福唐，公力抗之不肯降。", "欣然引頸齒劍芒，白乳上湧如雪霜。", "老賊自謂暴無傷，纔殺人半於南方。", "公無爵位在周行，史臣不書名不彰。", "後三百年丞相張，夜夢三賢與迎將。", "翌日遊山登公堂，宛如夢中貌昂藏。", "再來爲州剡奏章，賜名剛顯烈有光。", "葺祠爲廟飾棟梁，普與州人奉肴觴。", "於薦荔丹與蕉黄，歲時來享以爲常。", "我作銘詩刻其旁，千萬億載死不亡。"]'),
('17a74a5f-eb89-4dfa-ab1f-acf5984c9237','柬呂太學禎','邵知柔','宋','宋诗','song-poetry','','[]','當時欲殺尚憐才，奏稿流傳讀轉哀。',64,'全唐诗/poet.song.95000.json','["當時欲殺尚憐才，奏稿流傳讀轉哀。", "一寸丹心朝士愕，十分頭白道州回。", "汴京今日猶豺虎，陵寢多年沒草萊。", "聖主不勝嘗膽恨，先生無用鶴書催。"]'),
('0d27b764-363c-4f38-b130-5307b7585360','柘川漁火','蔣旦','宋','宋诗','song-poetry','','[]','桃浪流香春雨餘，漁燈深夜出溪湄。',64,'全唐诗/poet.song.95000.json','["桃浪流香春雨餘，漁燈深夜出溪湄。", "半篷明滅風生處，數點微茫月上時。", "影落沙汀鷗夢斷，光搖蘆葦雁棲遲。", "明朝解纜滄浪外，濯足船頭唱竹枝。"]'),
('a4c26f58-b928-4ce8-b9e9-b7ac21ac5ee2','捕虎行','汪襄','宋','宋诗','song-poetry','','[]','西山春暮繁草木，紅白花開映巖谷。',322,'全唐诗/poet.song.95000.json','["西山春暮繁草木，紅白花開映巖谷。", "朝來猛虎忽留蹤，獵人挾刃爭驅逐。", "坡平草軟筋力健，目光兩鏡照林麓。", "吻牙狐兔何足噬，要向川原飽人肉。", "獵夫鼓勇欲生擒，失利寧虞傷手足。", "我令壯士八九輩，袒裼而往敢退縮。", "持戈踴躍皆直前，不顧爪牙加觝觸。", "於菟怒鬬力已困，白刃紛然刺其腹。", "不施陷穽設羅網，須臾俄聞就縛束。", "未踰半晝捷書來，撫掌驚嗟大神速。", "百夫肩舁向城市，塞巷填街爭縱目。", "皆云古昔未曾有，不比春山得麋鹿。", "斑皮愛護輸府，肝膽珍奇競收蓄。", "吾聞獸之猛者莫如虎，搖尾磨牙肆其毒。", "一旦力盡勢已窮，血膋反以餉僮僕。", "乃知剛狠不足恃，仁若騶虞才可錄。", "虎兮虎兮，曷爲出哉，深山窮谷可以隱而不隱，豈以夫皮爲之災。", "官有壯土長戟可以捕取爾，爾其亟去無復來。", "大江雖深亦可渡，縱橫勿礙行人路。"]'),
('8bcdd441-0f79-4537-b641-52411a737d6d','句','吳達老','宋','宋诗','song-poetry','','[]','水流丁字通地脈，人從甲第破天荒。',16,'全唐诗/poet.song.95000.json','["水流丁字通地脈，人從甲第破天荒。"]'),
('b1dee232-1abe-448d-9465-a80ed3951a2c','還靖師草屨','王珉','宋','宋诗','song-poetry','','[]','跣足山行踐綠蕪，道人應念我崎嶇。',64,'全唐诗/poet.song.95000.json','["跣足山行踐綠蕪，道人應念我崎嶇。", "還將達磨西歸履，暫作王喬羽化鳬。", "爲愛輕鬆宜踏石，更憐蕭灑勝聯珠。", "還君舊物君收取，認得拖泥带水無。"]'),
('0ed638e1-5357-41c0-b62d-5950873b1167','舟行吳應求惜春次韻','王珉','宋','宋诗','song-poetry','','[]','弄日嬌雲未肯收，暫憑堤柳繫行舟。',64,'全唐诗/poet.song.95000.json','["弄日嬌雲未肯收，暫憑堤柳繫行舟。", "數聲杜宇碧山遠，幾片落花春水流。", "強借酒兵銷別恨，卻因詩債起新愁。", "嗟予已豎降旗久，寄語將軍好罷休。"]'),
('1e5456f0-f5a2-480f-8202-1f55d78b5976','和仲長統詩二首  其一','郭印','宋','宋诗','song-poetry','','[]','造化一機，乾坤一殻。',90,'全唐诗/poet.song.95000.json','["造化一機，乾坤一殻。", "死生蟲臂，勝負蝸角。", "達人於道，混混殊俗。", "瞽非喪明，刖非卞足。", "賊生戶牖，禍徵帷幄。", "聚蟻貪羶，飛蛾赴燭。", "彈雀以珠，抵鵲以玉。", "喪精失靈，皆由多欲。", "命也天齊，愚夫自促。"]'),
('e3958dbc-f07d-46ee-a2f3-892dd38d317d','和仲長統詩二首  其二','郭印','宋','宋诗','song-poetry','','[]','致虛守靜，其術至寡。',100,'全唐诗/poet.song.95000.json','["致虛守靜，其術至寡。", "有相皆虛，無物不可。", "包藏寥廓，該攝細瑣。", "出入隱顯，妙用由我。", "九天匪高，九地匪下。", "駕鶴周遊，魚魚雅雅。", "焚蕩三彭，性空真火。", "大道甚夷，學孝僻左。", "發車推轅，捨舟搖柂。", "五金八石，殘生爐冶。"]'),
('d0b06116-b597-4ce9-ba3e-3106ac54c59b','蜀州試闈豋樓西山巍然可愛因用試舉子股肱蕭曹詩肱字韻賦詩一篇呈同舍','郭印','宋','宋诗','song-poetry','','[]','棘闈倦覊束，何異韝上鷹。',120,'全唐诗/poet.song.95000.json','["棘闈倦覊束，何異韝上鷹。", "突兀有高樓，寸目堪遠凝。", "雨殘空正霽，暑盡秋初澄。", "西山横一天，奇峰矗層層。", "素約念樵子，煙霞同曲肱。", "口腹在塵土，擺脱良未能。", "嵩岱久隔絕，氛霾尚薫烝。", "唯有岷峨秀，宇宙誇崚嶒。", "或悵碧雲合，或瞻紅日昇。", "危欄朝暮意，拉君時一登。"]'),
('5beb5754-93e4-4ffe-a3e7-36bc83e9ecbe','類試院考校九月十日塔之八級中現寶光楊齊伯有詩記其事亦賦一首','郭印','宋','宋诗','song-poetry','','[]','崢嶸大千界，等是菩提鄉。',192,'全唐诗/poet.song.95000.json','["崢嶸大千界，等是菩提鄉。", "昆蟲暨草木，各放無邊光。", "而况佛之覺，靈明亘十方。", "化身三昧火，骨節金彌剛。", "纍纍燦五色，珠璣斗斛量。", "寶傳百世後，伽藍深秘藏。", "錦官岌浮圖，直上干穹蒼。", "中有堅固子，示現尤非常。", "朝來八級內，明燈忽煌煌。", "胥隸走驚詫，觀者即堵墻。", "初疑伏螢過，顯沒何微茫。", "繼如兩星出，左右爭飛揚。", "是時霽霧歛，若木昇太陽。", "儻非照耀成，不知果何祥。", "西南一都會，廣開選士場。", "定應得奇才，歸美報君王。"]'),
('fd627bb4-947d-4713-8bfe-7c8ffcd5aced','臨都試院考校已畢諸公尚恨遺才勉作數語釋其意','郭印','宋','宋诗','song-poetry','','[]','平時參與商，會遇何由緣。',168,'全唐诗/poet.song.95000.json','["平時參與商，會遇何由緣。", "相從棘闈中，再見月之弦。", "歡然臭味合，言笑浩無邊。", "論事快今古，談玄貫天淵。", "白袍閲多士，燈窗極精研。", "所得乃溢數，無路能周旋。", "躊躇不忍舍，在野恐遺賢。", "我時職監視，日食亦千錢。", "一言爲訂正，少逭饕餮愆。", "譬如滿盤珠，差擇先光圓。", "又如采美玉，疵瑕終棄捐。", "兹事既不免，吾心白日懸。", "群公人中傑，行簉蓬瀛仙。", "願開取士額，條畫奏上前。"]'),
('4514418f-812a-4ee0-871e-120105b5d19d','迓帥夜渡廣漢','郭印','宋','宋诗','song-poetry','','[]','負弩迎使車，暮塗頗忽迫。',96,'全唐诗/poet.song.95000.json','["負弩迎使車，暮塗頗忽迫。", "篝火滅還明，羸駑費鞭策。", "行行漢江漘，月照沙水白。", "登舟越驚濤，未濟忽欹側。", "可憐爲升斗，性命鴻毛擲。", "人生誰貴賤，同是蘧廬客。", "敢輕千戶侯，願丐五畝宅。", "歸共老農遊，飲酣歌帝澤。"]'),
('55f2b5e6-e046-4711-92c8-766586c64906','早行界上迓何使者','郭印','宋','宋诗','song-poetry','','[]','天星半牢落，月窗光冏冏。',96,'全唐诗/poet.song.95000.json','["天星半牢落，月窗光冏冏。", "僮婢寐正酣，四鄰雞犬靜。", "而我獨何之，倒衣不及整。", "呵鞭驅蹇驢，霜風破裘領。", "既無王事敦，又匪奉朝請。", "窮年憊將迎，功業羞明鏡。", "相如徒四壁，季子無二頃。", "何時滌塵纓，農畝迹甘屏。"]'),
('6000b4d0-8866-4daa-843c-7a5fb54bb0bf','上李西美制置','郭印','宋','宋诗','song-poetry','','[]','諦觀天地間，物物無非易。',228,'全唐诗/poet.song.95000.json','["諦觀天地間，物物無非易。", "有情洎無情，與我固真一。", "伏羲未仰俯，卦象已先畫。", "乾坤易之門，神機盡開闢。", "周文魯仲尼，傳授何太密。", "古今元共處，心心印空寂。", "展編韋三絕，門人豈語詰。", "曾高本愚魯，超然入于室。", "子思中庸篇，孟軻仁義術。", "于易初不言，此道皎如日。", "寥落餘千載，學者空陳迹。", "條葉競尋採，幾人擷其實。", "盤根有仙李，靈芽一枝出。", "衣鉢自家傳，獨智探聖域。", "契兹三聖書，羹墻面相覿。", "雅懷親炙願，進退終跼蹐。", "達人具大觀，胸次吞溟渤。", "斐章露肝膽，猶愧多言失。", "儻許接玄談，平生事已畢。"]'),
('b93828cb-05b4-49fe-a986-301eb67497cb','送韓美成都大赴夔帥','郭印','宋','宋诗','song-poetry','','[]','公來雪山重，公去雪山輕。',192,'全唐诗/poet.song.95000.json','["公來雪山重，公去雪山輕。", "少陵有是語，申言餞公行。", "公初來蜀時，豺狼浩縱横。", "剪除二三輩，百獸弭耳驚。", "坐令坤維地，衆醉稍稍醒。", "仁風被動植，德澤覃幽明。", "咸云真使者，有眼未曾經。", "今將夔子去，方面倚長城。", "雖分閫外憂，三川難爲情。", "岷山黯無色，錦水咽無聲。", "政恐狐貍出，依然擾吾民。", "鄙夫爲之言，汝曹且靜聽。", "我公非常人，夷夏知威名。", "平生活國心，須臾不少寧。", "天欲靖乾坤，平步公與卿。", "大攄康濟學，引手援生靈。"]'),
('999f21b1-6eb8-434e-a45c-94afb091c2ef','送韓美成帥荆南','郭印','宋','宋诗','song-poetry','','[]','何國不生士，汝潁獨多奇。',168,'全唐诗/poet.song.95000.json','["何國不生士，汝潁獨多奇。", "公於輩行中，玉潔了無玼。", "少年遊宦場，英譽蔚四馳。", "郎宿爭璀璨，使星勝光輝。", "去惡如去草，根本須芟夷。", "就義若就渴，事難必勇爲。", "姦吏戢猛虎，良民撫嬰兒。", "髦節已歷試，人訝鋒車遲。", "遺愛猶在益，去思今滿夔。", "行行遠荆州，迤邐近丹墀。", "深嗟鷁首東，孤猿失攀依。", "愁看巫峽內，江山氣慘悽。", "但同此邦民，日日誦清徽。", "它年黄閣下，簪屨或收遺。"]'),
('ef3e8892-2ab6-47e9-8907-f7efd948d50a','送种守','郭印','宋','宋诗','song-poetry','','[]','群峰逶迤來，落處如鼎峙。',144,'全唐诗/poet.song.95000.json','["群峰逶迤來，落處如鼎峙。", "真仙鑿鹽穴，下引滄溟水。", "英氣鍾人物，衣冠何濟濟。", "古來陵陽守，賢哲多卧理。", "公分一歳符，治譽歘然起。", "鈴齋清畫閑，山色入簾几。", "璽書換金淵，要踵前兄美。", "跨鼇煙雲愁，十日雨不止。", "聞昔乃祖風，勳業照國史。", "尺箠鞭羌夷，奇謀付孫子。", "青雲且遇合，未信朱輪柅。", "行觀舊物歸，一洗中原耻。"]'),
('d0aa8af7-c8b3-4c29-b42f-72839bd4c3f3','送路守','郭印','宋','宋诗','song-poetry','','[]','道衰世彌隘，俗薄人易驕。',168,'全唐诗/poet.song.95000.json','["道衰世彌隘，俗薄人易驕。", "一爲居所移，盛氣干雲霄。", "官曹出已下，俯視如僬僥。", "崇卑兩懸絕，相望天壤遼。", "猗歟路漢州，冠纓早彯彯。", "亨衢快著鞭，壯歳亟乘軺。", "耘耡矜色盡，茂德日以昭。", "朅來西南守，揀拔自公朝。", "侯館賓客富，平湖水竹饒。", "退食未爲樂，鸞輿萬里遙。", "赤子拊吾民，良朋遇吾僚。", "薫然四時春，草木無枯焦。", "明朝馬首西，秋風更蕭條。", "當宁方急賢，三旌副旁招。"]'),
('fdd60b2c-4328-4027-8b1e-51577f94280b','詩别杜安行赴合州守','郭印','宋','宋诗','song-poetry','','[]','雁水分攜後，懸懸二十秋。',132,'全唐诗/poet.song.95000.json','["雁水分攜後，懸懸二十秋。", "世路少青眼，人生易白頭。", "况復遭亂離，長懷家國憂。", "是中欲傾倒，一面終無由。", "君從萬里歸，訪我三日留。", "寒燈話平生，尊酒相勸酬。", "喜極感今昔，潸然涕將流。", "君行駕朱轓，我亦稻粱謀。", "努力盡此道，全身早歸休。", "林泉遵素約，杖屨發清游。", "庶幾踐前言，母俾猿鶴羞。"]'),
('e6200d2e-0d66-4a0e-913f-07ca4cce6e20','送董守','郭印','宋','宋诗','song-poetry','','["\u897f\u6e56"]','房相風流遠，寥寥四百年。',96,'全唐诗/poet.song.95000.json','["房相風流遠，寥寥四百年。", "西湖有陳迹，水竹尚蒼然。", "公來刺是邦，魚鳥亦安全。", "官閑得放曠，樂事踵前賢。", "亭臺一增飾，草木發夭妍。", "瓜期秋風來，歳月驚翩翩。", "長橋淡孤月，老樹含愁煙。", "賴有龐眉叟，送行賫百錢。"]'),
('5a56cb84-035a-4d13-b483-2816fb760fb2','送陳守','郭印','宋','宋诗','song-poetry','','[]','惟昔號能吏，在公勤嚴明。',252,'全唐诗/poet.song.95000.json','["惟昔號能吏，在公勤嚴明。", "挾兹來共理，敎化日流行。", "堂堂陳漢州，所至樹風聲。", "四美出天性，早擅循良名。", "平心衡稱物，敏手刀發硎。", "姦黠膽欲破，隱伏無遁形。", "千里歸鎮靜，人神各安寧。", "愛物及魚鳥，游泳全其生。", "輿言誦嘉政，不待三年成。", "房湖天下絕，好景無陰晴。", "退食來徜徉，風月攪詩情。", "脩竹如君直，流水如君清。", "豈無宴賞心，對此樂事并。", "國步正艱險，天驕尚縱横。", "惜哉廊廟器，乃爾屈專城。", "瓜期忽忽來，歳月令人驚。", "車轍不容卧，去意一何輕。", "金陵一水通，當宁思豪英。", "况最郡守課，由來入公卿。", "君才森武庫，可當十萬兵。", "行矣佐中興，力扶天柱傾。"]'),
('30fdc874-87fe-496d-86d6-62c62bed3d52','送雷公達觀赴召','郭印','宋','宋诗','song-poetry','','[]','我觀靖康初，塵氛蒙帝闕。',168,'全唐诗/poet.song.95000.json','["我觀靖康初，塵氛蒙帝闕。", "君臣失上著，社稷幾危絕。", "君時沉布衣，抗疏何悲切。", "言聽豺狼誅，狐狸肝膽裂。", "鐵騎稍稍去，佞諛歸一轍。", "小臣更不容，排擯爭媒蘖。", "後來禍何如，欲語氣先噎。", "七年坐閉廢，口舌宜鉗結。", "技癢不復禁，囊封仍論列。", "朝廷果召還，愛士如饑渇。", "魏闕心久馳，行色安可遏。", "江山阻且長，忠信自平達。", "露肘見天子，首薦經綸說。", "邦榮身亦榮，無愧古明哲。"]'),
('4dd03f6c-f6f5-495a-b9f5-52bb0a0e3fb7','送喻迪孺赴召','郭印','宋','宋诗','song-poetry','','[]','志士居環堵，常懷天下憂。',216,'全唐诗/poet.song.95000.json','["志士居環堵，常懷天下憂。", "而况立王朝，爲國當遠謀。", "中原亂戎馬，騷擾十三秋。", "宫闕翳草莽，井邑成墟丘。", "先生身補外，興言淚長流。", "滿腹貯經綸，寸絲殊未抽。", "篇章洩幽憤，山雲爲之愁。", "遂令寰海間，望治空悠悠。", "詔旨忽旁招，喜氣扶仙舟。", "風濤照孤忠，軒陛需嘉猷。", "屈指在廷彦，如公實罕儔。", "片言儻遇合，男兒志願酬。", "方今艱難際，皇祚若綴斿。", "百蠧盡掃除，群黎自歌謳。", "古來柔遠人，莫先政事修。", "要當效甫申，豈但爲枚鄒。", "高堂有甲兵，千里歸坐籌。", "賛成中興功，踵跡商與周。"]'),
('97815343-4128-4485-8a5d-384d5258868a','送吳蜀州還朝','郭印','宋','宋诗','song-poetry','','[]','達官視貧賤，遼絕間天壤。',144,'全唐诗/poet.song.95000.json','["達官視貧賤，遼絕間天壤。", "門墻奥莫窺，鼎茵恣居享。", "令行雷風前，氣吐虹霓上。", "陋彼衡門流，揮斥同草莽。", "堂堂吳蜀州，浩氣深涵養。", "毫端掃千軍，胸次包萬象。", "驕色盡耘耡，儒林植標榜。", "自憐爨下焦，亦值知音賞。", "方當出肺肝，晨夕趨函丈。", "金闕佇公歸，無由挽輪鞅。", "拭目上巖廊，獻納攄忠讜。", "網羅寒畯姿，直道光吾黨。"]'),
('bbe758ee-c96a-495f-afde-4c9aea2b7ab0','送計敏夫赴闕','郭印','宋','宋诗','song-poetry','','[]','衣冠半知識，喜君天下士。',216,'全唐诗/poet.song.95000.json','["衣冠半知識，喜君天下士。", "奥學滄溟深，高談風雨駛。", "胸中富經綸，憂國心屢痞。", "誓言排閶闔，開口獻天子。", "時絀道不伸，倦懷歸故里。", "盤礴曾幾時，九天飛詔旨。", "春風飽征帆，一葦吳江水。", "見晚上應嗟，使華聊復爾。", "丞相君之甥，風流酷相似。", "彤陛看摩肩，笑談銷敵壘。", "君家有世臣，名實耀國史。", "奇謀付子孫，鞭笞餘馬箠。", "行增前德光，更雪中朝耻。", "事成豈因人，碌碌焉能比。", "我昔綴僚末，高山日仰止。", "窮達兩懸殊，星辰視泥滓。", "平生白眼多，君獨掛牙齒。", "更須假扶摇，南溟將一徙。"]'),
('a9c4c7f8-e603-4d78-9297-c058d3bb97fc','送朱仲遠樊唐老趨闕奉大對','郭印','宋','宋诗','song-poetry','','[]','充城環髠山，南嶺獨秀鬰。',120,'全唐诗/poet.song.95000.json','["充城環髠山，南嶺獨秀鬰。", "何以獲佳稱，上有朱鳯集。", "三載爭一嗚，朝陽整雲翮。", "今年二妙飛，好語鬨邦邑。", "爲言皆老蒼，文采勝疇昔。", "其一出上黨，其一出沛國。", "同聲相呼和，深可調六律。", "長風送天衢，萬里纔一擊。", "邕邕中簫韶，虞廷誰可匹。", "四顧啁啾群，俛首不能息。"]'),
('dae0824c-4ff4-4ad0-8a8e-cbd18a4b7ede','送張安國赴天彭司錄','郭印','宋','宋诗','song-poetry','','[]','騏驥服鹽車，垂頭困長道。',288,'全唐诗/poet.song.95000.json','["騏驥服鹽車，垂頭困長道。", "蒼鷹在韝縶，側耳思秋草。", "憶昔初見公，衮衮一傾倒。", "平生仰止意，相逢恨不早。", "清輝粲景星，巨浸屹孤島。", "徐榻未易解，膺門但頻掃。", "公才天河傾，顧我乃潢潦。", "篠簜何足云，所貴會稽笴。", "魚泳鳥雲飛，氣合無不可。", "歳月忽荏苒，何言賦離抱。", "彭城不百里，摻袂空懊惱。", "糾郡因多暇，時政亦叢脞。", "猾吏虎插翼，疲民葉振槁。", "邦侯待禆益，幕客要摽表。", "咄嗟贊畫諾，談笑辦紛擾。", "江山頗足娛，杯酒興不小。", "搘笻恣清游，蠟屐縱幽討。", "雲煙入高躅，詩句出餘巧。", "升沉置勿問，道義端可飽。", "眼前多少年，難致淄川老。", "儻令班中朝，功業信不少。", "賤生宿所期，志願慚未果。", "因公激壯懷，綠髪豈能葆。", "還應最課績，歸步直青瑣。"]'),
('8b30a441-db53-40d2-ab60-e06538e3f59f','送友人赴省','郭印','宋','宋诗','song-poetry','','[]','仲冬陰氣積，嚴霜凍郊坰。',120,'全唐诗/poet.song.95000.json','["仲冬陰氣積，嚴霜凍郊坰。", "居人猶念寒，子有萬里行。", "此行勿云遠，去路青雲平。", "驊騮無蹇步，鴻鵠有脩翎。", "聖明圖治切，仄席用儒生。", "曈曨九門闢，紛袍集王庭。", "吾子富春秋，詞學浩縱横。", "一吐經濟策，唾手拾科名。", "秋風歸故里，錦衣爲親榮。", "眤眤重離去，莫學兒女情。"]'),
('30a47f30-d1e7-4043-84e2-a8195c0dcc62','和宋文淵送仲明舉西歸三首  其一','郭印','宋','宋诗','song-poetry','','[]','丈夫志萬里，耿耿抱長慮。',48,'全唐诗/poet.song.95000.json','["丈夫志萬里，耿耿抱長慮。", "青雲卻倦飛，功業何由樹。", "廟堂有先達，體國心焦勞。", "歸來掩關卧，茅簷日色高。"]'),
('f8d58ea0-8c0c-4f25-b671-abc1e741ff9c','和宋文淵送仲明舉西歸三首  其二','郭印','宋','宋诗','song-poetry','','[]','馬蹄厭長道，詎忍别帝京。',48,'全唐诗/poet.song.95000.json','["馬蹄厭長道，詎忍别帝京。", "夢想子規啼，花落故園春。", "山驛暗孤燈，江城歇滯雨。", "悠悠秦蜀間，慨然念今古。"]'),
('b9076dc6-89a4-4f76-ba2d-de7f4396f9ec','和宋文淵送仲明舉西歸三首  其三','郭印','宋','宋诗','song-poetry','','[]','朔風吹别袂，草色冷萋萋。',48,'全唐诗/poet.song.95000.json','["朔風吹别袂，草色冷萋萋。", "憑高望佳人，天遠浮雲低。", "恍然從之游，神魂坐飛越。", "何當清夜語，分此半床月。"]'),
('27294277-856f-4ea8-82de-c3e7a5946dfe','何耕道還卭南贈詩爲别','郭印','宋','宋诗','song-poetry','','[]','古人不復見，俗學尚穿鑿。',144,'全唐诗/poet.song.95000.json','["古人不復見，俗學尚穿鑿。", "時花亦可觀，潢潦終易涸。", "暮年識吾子，志與流輩各。", "入道窮根源，高情轉寥廓。", "詩章富波瀾，議論生鋒鍔。", "胡爲困窮途，計拙客古雒。", "出門春草芳，西風漸摇落。", "我時喜過從，妙語資發藥。", "人情變炎凉，白首忽難託。", "悵望鶴鳴雲，羈懷每作惡。", "告别何依依，交游義不薄。", "行矣覲親闈，菽水端可樂。"]'),
('0b824b17-f2a3-476c-bd25-d18afdda81a8','送齊侍者南遊','郭印','宋','宋诗','song-poetry','','[]','癡癡行腳師，要覓南方禪。',96,'全唐诗/poet.song.95000.json','["癡癡行腳師，要覓南方禪。", "不知未舉足，罪過已彌天。", "三千大千界，當處本湛然。", "若作如是解，猶嫌墮一邊。", "子今腰包去，慎勿求真詮。", "真詮不可得，往往成風顛。", "芒鞋縱所之，江山發清妍。", "得住且即住，飯了曲肱眠。"]');
